-- Poems batch 12
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('80e0d5d2-f668-45c0-8f80-11eca42467e0','仲秋夜郡內西亭對月','張登','唐','唐诗','tang','','["\u957f\u6c5f"]','天高月滿影悠悠，一夜炎荒併覺秋。',64,'全唐诗/poet.tang.16000.json','["天高月滿影悠悠，一夜炎荒併覺秋。", "氣與露清凝衆草，色如霜白怯輕裘。", "高臨華宇還知隙，靜映長江不共流。", "囗直西傾河漢曙，遺風猶想武昌樓。"]'),
('2d83c470-1dbe-4930-9b54-e50a1f128bfe','冬至夜郡齋宴別前華陰盧主簿','張登','唐','唐诗','tang','','[]','虎宿方冬至，雞人積夜籌。',48,'全唐诗/poet.tang.16000.json','["虎宿方冬至，雞人積夜籌。", "相逢一尊酒，共結兩鄉愁。", "王儉花爲府，盧諶幄內璆。", "明朝更臨水，悵望嶺南流。"]'),
('2040723e-bc4c-4083-bf86-35b25bc37c7f','小雪日戲題絕句','張登','唐','唐诗','tang','','[]','甲子徒推小雪天，刺梧猶綠槿花然。',32,'全唐诗/poet.tang.16000.json','["甲子徒推小雪天，刺梧猶綠槿花然。", "融和長養無時歇，却是炎洲雨露偏。"]'),
('9a253b91-286c-4148-8f41-cd675c5df318','招客遊寺','張登','唐','唐诗','tang','','[]','江城吏散捲春陰，山寺鳴鐘隔雨深。',32,'全唐诗/poet.tang.16000.json','["江城吏散捲春陰，山寺鳴鐘隔雨深。", "招取遺民赴僧社，竹堂分坐靜看心。"]'),
('a5f1043b-4313-461f-bda7-260191751398','句','張登','唐','唐诗','tang','','[]','孤高齊帝石，蕭灑晉亭峰。',24,'全唐诗/poet.tang.16000.json','["孤高齊帝石，蕭灑晉亭峰。", "境曠窮山外，城標漲海頭。"]'),
('e2310c7a-b1e5-4ade-8b9c-61dd403a8c05','陪韓退之竇貽周同尋劉尊師不遇得師字','韋執中','唐','唐诗','tang','','[]','早尚逍遙境，常懷汗漫期。',48,'全唐诗/poet.tang.16000.json','["早尚逍遙境，常懷汗漫期。", "星郎同訪道，羽客杳何之。", "物外求仙侶，人間失我師。", "不知柯爛者，何處看圍棊。"]'),
('4d78bede-6620-4b78-b820-cc1ef372f550','尋人偶題','邵真','唐','唐诗','tang','','[]','日昃不復午，落花難歸樹。',24,'全唐诗/poet.tang.16000.json','["日昃不復午，落花難歸樹。", "人生能幾何，莫厭相逢遇。"]'),
('f5b5f360-038f-448a-9998-7cf5b41329de','牆陰殘雪','何頻瑜','唐','唐诗','tang','','[]','積雪還因地，牆陰久尚殘。',72,'全唐诗/poet.tang.16000.json','["積雪還因地，牆陰久尚殘。", "影添斜月白，光借夕陽寒。", "皎潔開簾近，清熒步履看。", "狀花飛著樹，如玉不成盤。", "冰薄方寧及，霜濃比亦難。", "誰憐高臥處，歲暮歎袁安。"]'),
('b5fc66ba-be3d-468c-9e22-e600355dabeb','題度支雜事典庭中柏樹','駱浚','唐','唐诗','tang','','[]','幹聳一條青玉直，葉鋪千疊綠雲低。',32,'全唐诗/poet.tang.16000.json','["幹聳一條青玉直，葉鋪千疊綠雲低。", "爭如燕雀偏巢此，却是鴛鴦不得棲。"]'),
('a66133c3-2ede-417c-94cd-d52c4bd4b4cc','梢雲','羅讓','唐','唐诗','tang','','[]','殊質資靈貺，凌空發瑞雲。',72,'全唐诗/poet.tang.16000.json','["殊質資靈貺，凌空發瑞雲。", "梢梢含樹彩，郁郁動霞文。", "不比因風起，全非觸石分。", "葉光閑泛灩，枝杪靜氛氳。", "隱見心無宰，裴回慶自君。", "翻飛如可託，長願在橫汾。"]'),
('4ce1c554-784f-4654-8d0c-ea19813e232d','閏月定四時','羅讓','唐','唐诗','tang','','[]','月閏隨寒暑，疇人定職司。',72,'全唐诗/poet.tang.16000.json','["月閏隨寒暑，疇人定職司。", "餘分將考日，積算自成時。", "律候行宜表，陰陽運不欺。", "氣薰灰琯驗，數扐卦辭推。", "六律文明序，三年理暗移。", "當知歲功立，唯是奉無私。"]'),
('0ea39dc8-7451-4ecc-a894-ffbd61914936','享文恭太子廟樂章','陳京','唐','唐诗','tang','','[]','歌以德發，聲以樂貴。',40,'全唐诗/poet.tang.16000.json','["歌以德發，聲以樂貴。", "樂善名存，追仙禮異。", "鸞旌拱修，鳳鳴合次。", "神聽皇慈，仲月皆至。"]'),
('78bf0059-45ef-46fb-8cf4-21ff9af4c86b','步虛詞十九首 一','韋渠牟','唐','唐诗','tang','','[]','玉簡真人降，金書道籙通。',48,'全唐诗/poet.tang.16000.json','["玉簡真人降，金書道籙通。", "煙霞方蔽日，雲雨已生風。", "四極威儀異，三天使命同。", "那將人世戀，不去上清宮。"]'),
('8448e2fc-9cfa-48ba-ac37-b6f527dd4086','步虛詞十九首 二','韋渠牟','唐','唐诗','tang','','[]','羽駕正翩翩，雲鴻最自然。',48,'全唐诗/poet.tang.16000.json','["羽駕正翩翩，雲鴻最自然。", "霞冠將月曉，珠珮與星連。", "鏤玉留新訣，雕金得舊編。", "不知飛鸞鶴，更有幾人仙。"]'),
('2b950e2f-f09c-4ccc-9fdc-b387f9a713f7','步虛詞十九首 三','韋渠牟','唐','唐诗','tang','','[]','上帝求仙使，真符取玉郎。',48,'全唐诗/poet.tang.16000.json','["上帝求仙使，真符取玉郎。", "三才閑布象，二景鬱生光。", "騎吏排龍虎，笙歌走鳳皇。", "天高人不見，暗入白雲鄉。"]'),
('7d4350b3-d20f-44b9-ae00-12ca275df160','步虛詞十九首 四','韋渠牟','唐','唐诗','tang','','[]','鸞鶴共裴回，仙官使者催。',48,'全唐诗/poet.tang.16000.json','["鸞鶴共裴回，仙官使者催。", "香花三洞啓，風雨百神來。", "鳳篆文初定，龍泥印已開。", "何須生羽翼，始得上瑤臺。"]'),
('7047b72d-516e-4fbb-8a87-782664d488d9','步虛詞十九首 五','韋渠牟','唐','唐诗','tang','','[]','羽節忽排煙，蘇君已得仙。',48,'全唐诗/poet.tang.16000.json','["羽節忽排煙，蘇君已得仙。", "命風驅日月，縮地走山川。", "幾處留丹竈，何時種玉田。", "一朝騎白虎，直上紫微天。"]'),
('9407c33b-66b9-485c-bd9e-0217167089d6','步虛詞十九首 六','韋渠牟','唐','唐诗','tang','','[]','靜發降靈香，思神意智長。',48,'全唐诗/poet.tang.16000.json','["靜發降靈香，思神意智長。", "虎存時促步，龍想更成章。", "扣齒風雷響，挑燈日月光。", "仙雲在何處，髣髴滿空堂。"]'),
('bb2ff622-762d-4021-8231-969adb3b3575','步虛詞十九首 七','韋渠牟','唐','唐诗','tang','','[]','幾度遊三洞，何方召百神。',48,'全唐诗/poet.tang.16000.json','["幾度遊三洞，何方召百神。", "風雲皆守一，龍虎亦全真。", "執節仙童小，燒香玉女春。", "應須絕巖內，委曲問皇人。"]'),
('64a58b4d-e749-4e65-93fa-9ac7a8431803','步虛詞十九首 八','韋渠牟','唐','唐诗','tang','','[]','上法杳無營，玄修似有情。',48,'全唐诗/poet.tang.16000.json','["上法杳無營，玄修似有情。", "道宮瓊作想，真帝玉爲名。", "召岳馳旌節，驅雷發吏兵。", "雲車降何處，齋室有仙卿。"]'),
('351ba95c-9ebb-45b7-928f-b57ce42fc4fc','步虛詞十九首 九','韋渠牟','唐','唐诗','tang','','[]','羽衛一何鮮，香雲起暮煙。',48,'全唐诗/poet.tang.16000.json','["羽衛一何鮮，香雲起暮煙。", "方朝太素帝，更向玉清天。", "鳳曲凝猶吹，龍驂儼欲前。", "真文幾時降，知在永和年。"]'),
('f6284471-7726-4de2-ae2f-cca09eb5bf40','步虛詞十九首 十','韋渠牟','唐','唐诗','tang','','[]','大道何年學，真符此日催。',48,'全唐诗/poet.tang.16000.json','["大道何年學，真符此日催。", "還持金作印，未要玉爲臺。", "羽節分明授，霞衣整頓裁。", "應緣五雲使，敎上列仙來。"]'),
('164e0e37-ece0-4172-acc8-7b785134dff0','步虛詞十九首 十一','韋渠牟','唐','唐诗','tang','','[]','獨自授金書，蕭條詠紫虛。',48,'全唐诗/poet.tang.16000.json','["獨自授金書，蕭條詠紫虛。", "龍行還當馬，雲起自成車。", "九轉風煙合，千年井竈餘。", "參差從太一，壽等混元初。"]'),
('bce8d67e-ee84-425e-aea3-8cae1cd48321','步虛詞十九首 十二','韋渠牟','唐','唐诗','tang','','[]','道學已通神，香花會女真。',48,'全唐诗/poet.tang.16000.json','["道學已通神，香花會女真。", "霞牀珠斗帳，金薦玉輿輪。", "一室心偏靜，三天夜正春。", "靈官竟誰降，仙相有夫人。"]'),
('ca9a3b79-4b08-4905-93e4-1fae7fe4766b','步虛詞十九首 十三','韋渠牟','唐','唐诗','tang','','[]','上界有黃房，仙家道路長。',48,'全唐诗/poet.tang.16000.json','["上界有黃房，仙家道路長。", "神來知位次，樂變叶宮商。", "競把瑠璃盞，都傾白玉漿。", "霞衣最芬馥，蘇合是靈香。"]'),
('2de81208-7492-4c3e-ba56-4dd795b03156','步虛詞十九首 十四','韋渠牟','唐','唐诗','tang','','[]','珠佩紫霞纓，夫人會八靈。',48,'全唐诗/poet.tang.16000.json','["珠佩紫霞纓，夫人會八靈。", "太霄猶有觀，絕宅豈無形。", "暮雨裴回降，仙歌宛轉聽。", "誰逢玉妃輦，應檢九真經。"]'),
('6a322d06-85db-48ee-a1d1-5b5d3964e2d0','步虛詞十九首 十五','韋渠牟','唐','唐诗','tang','','[]','西海辭金母，東方拜木公。',48,'全唐诗/poet.tang.16000.json','["西海辭金母，東方拜木公。", "雲行疑帶雨，星步欲凌風。", "羽袖揮丹鳳，霞巾曳彩虹。", "飄颻九霄外，下視望仙宮。"]'),
('cc07c8a8-4df7-4b47-9f55-65ed8ed6f1b5','步虛詞十九首 十六','韋渠牟','唐','唐诗','tang','','[]','玉樹襍金花，天河織女家。',48,'全唐诗/poet.tang.16000.json','["玉樹襍金花，天河織女家。", "月邀丹鳳舃，風送紫鸞車。", "霧縠籠綃帶，雲屏列錦霞。", "瑤臺千萬里，不覺往來賒。"]'),
('b6e12a9c-978b-4b14-8e5c-21703e06df3b','步虛詞十九首 十七','韋渠牟','唐','唐诗','tang','','[]','舞鳳凌天出，歌麟入夜聽。',48,'全唐诗/poet.tang.16000.json','["舞鳳凌天出，歌麟入夜聽。", "雲容衣眇眇，風韻曲泠泠。", "扣齒端金簡，焚香檢玉經。", "仙宮知不遠，祗近太微星。"]'),
('8d9a1d2c-074b-499d-9c81-71ce34ccfd10','步虛詞十九首 十八','韋渠牟','唐','唐诗','tang','','[]','紫府與玄洲，誰來物外遊。',48,'全唐诗/poet.tang.16000.json','["紫府與玄洲，誰來物外遊。", "無煩騎白鹿，不用駕青牛。", "金化顏應駐，雲飛鬢不秋。", "仍聞碧海上，更用玉爲樓。"]'),
('6aad34ed-7bf5-425f-ab60-c7e2dcc2cf21','步虛詞十九首 十九','韋渠牟','唐','唐诗','tang','','[]','轡鶴復驂鸞，全家去不難。',48,'全唐诗/poet.tang.16000.json','["轡鶴復驂鸞，全家去不難。", "雞聲隨羽化，犬影入雲看。", "釀玉當成酒，燒金且轉丹。", "何妨五色綬，次第給仙官。"]'),
('44401911-0654-445a-ba06-909468174a8d','覽外生盧綸詩因以示此','韋渠牟','唐','唐诗','tang','','[]','衛玠清談性最強，明時獨拜正員郎。',64,'全唐诗/poet.tang.16000.json','["衛玠清談性最強，明時獨拜正員郎。", "關心珠玉曾無價，滿手瓊瑤更有光。", "謀略久參花府盛，才名常帶粉闈香。", "終期內殿聊詩句，共汝朝天會柏梁。"]'),
('501ee5f7-cbd9-4a26-bb5b-32ee7e645fe5','贈竇五判官','韋渠牟','唐','唐诗','tang','','[]','故舊相逢三兩家，愛君兄弟有聲華。',64,'全唐诗/poet.tang.16000.json','["故舊相逢三兩家，愛君兄弟有聲華。", "文輝錦綵珠垂露，逸興江天綺散霞。", "美玉自矜頻獻璞，真金難與細披沙。", "終須撰取新詩品，更比芙蓉出水花。"]'),
('c65455a7-a886-4473-b0b6-c8e654964998','湖上閑居','竇參','唐','唐诗','tang','','[]','避影將息陰，自然知音稀。',60,'全唐诗/poet.tang.16000.json','["避影將息陰，自然知音稀。", "向來深林中，偶亦有所窺。", "飛鳥口銜食，引雛上高枝。", "高枝但各有，安知宜不宜。", "止止復何云，物情何自私。"]'),
('e1052b8e-ca43-4092-b9fd-66568fd10143','遷謫江表久未歸','竇參','唐','唐诗','tang','','[]','一自經放逐，裴回無所從。',84,'全唐诗/poet.tang.16000.json','["一自經放逐，裴回無所從。", "便爲寒山雲，不得隨飛龍。", "名豈不欲保，歸豈不欲早。", "苟無三月資，難適千里道。", "離心與羈思，終日常草草。", "人生年幾齊，憂苦即先老。", "誰能假羽翼，使我暢懷抱。"]'),
('c1369520-bef5-4613-8b43-711f35300c56','登潛山觀','竇參','唐','唐诗','tang','','[]','山勢欲相抱，一條微徑盤。',120,'全唐诗/poet.tang.16000.json','["山勢欲相抱，一條微徑盤。", "攀蘿歇復行，始得凌仙壇。", "聞道葛夫子，此中鍊還丹。", "丹成五色光，服之生羽翰。", "靈草空自綠，餘霞誰共餐。", "至今步虛處，猶有孤飛鸞。", "幽幽古殿門，下壓浮雲端。", "萬丈水聲落，四時松色寒。", "既入無何鄉，轉嫌人事難。", "終當遠塵俗，高臥從所安。"]'),
('4520b4ef-e24a-4338-b25c-e6d85afa33bd','淮西席上醉歌','盧羣','唐','唐诗','tang','','[]','祥瑞不在鳳凰麒麟，太平須得邊將忠臣。',64,'全唐诗/poet.tang.16000.json','["祥瑞不在鳳凰麒麟，太平須得邊將忠臣。", "衛霍真誠奉主，貔虎十萬一身。", "江河潛注息浪，蠻貊款塞無塵。", "但得百寮師長肝膽，不用三軍羅綺金銀。"]'),
('cdaef630-3ae1-4899-8358-1a674ccfab02','天池晚櫂','韋臯','唐','唐诗','tang','','[]','雨霽天池生意足，花間誰詠採蓮曲。',64,'全唐诗/poet.tang.16000.json','["雨霽天池生意足，花間誰詠採蓮曲。", "舟浮十里芰荷香，歌發一聲山水綠。", "春暖魚拋水面綸，晚晴鷺立波心玉。", "扣舷歸載月黃昏，直至更深不假燭。"]'),
('8206ea85-575a-43e7-b3e8-0b7ead649adb','贈何遐','韋臯','唐','唐诗','tang','','[]','腰間寶劒七星文，掌上彎弓挂六鈞。',32,'全唐诗/poet.tang.16000.json','["腰間寶劒七星文，掌上彎弓挂六鈞。", "箭發囗雲雙鴈落，始知秦地有將軍。"]'),
('eb1ef8d5-7c1b-43e6-bb30-dc16fcd24478','憶玉簫','韋臯','唐','唐诗','tang','','["\u957f\u6c5f"]','黃雀銜來已數春，別時留解贈佳人。',32,'全唐诗/poet.tang.16000.json','["黃雀銜來已數春，別時留解贈佳人。", "長江不見魚書至，爲遣相思夢入秦。"]'),
('80755f56-38a4-4d80-a366-cce77d9578ba','觀翟玉妓','李愿','唐','唐诗','tang','','[]','女郎閨閣春，抱瑟坐花茵。',48,'全唐诗/poet.tang.16000.json','["女郎閨閣春，抱瑟坐花茵。", "豔粉宜斜燭，羞蛾慘向人。", "寄情搖玉柱，流眄整羅巾。", "幸以芳香袖，承君宛轉塵。"]'),
('5f066cb1-dd30-4622-8b07-492afd2e9a85','思婦','李愿','唐','唐诗','tang','','[]','良人久不至，惟恨錦屏孤。',24,'全唐诗/poet.tang.16000.json','["良人久不至，惟恨錦屏孤。", "顦顇衣寬日，空房問女巫。"]'),
('6218387b-d123-409f-ab48-754dba36b772','徐州使院賦','王智興','唐','唐诗','tang','','[]','三十年前老健兒，剛被郎中遣作詩。',32,'全唐诗/poet.tang.16000.json','["三十年前老健兒，剛被郎中遣作詩。", "江南花柳從君詠，塞北煙塵我獨知。"]'),
('71a62f85-a346-4872-927c-b12ef74f36d6','茶山詩','袁高','唐','唐诗','tang','','[]','禹貢通遠俗，所圖在安人。',240,'全唐诗/poet.tang.16000.json','["禹貢通遠俗，所圖在安人。", "後王失其本，職吏不敢陳。", "亦有姦佞者，因茲欲求伸。", "動生千金費，日使萬姓貧。", "我來顧渚源，得與茶事親。", "甿輟耕農耒，采采實苦辛。", "一夫旦當役，盡室皆同臻。", "捫葛上欹壁，蓬頭入荒榛。", "終朝不盈掬，手足皆鱗皴。", "悲嗟遍空山，草木爲不春。", "陰嶺芽未吐，使者牒已頻。", "心爭造化功，走挺麋鹿均。", "選納無晝夜，搗聲昏繼晨。", "衆工何枯櫨，俯視彌傷神。", "皇帝尚巡狩，東郊路多堙。", "周迴遶天涯，所獻愈艱勤。", "況減兵革困，重茲固疲民。", "未知供御餘，誰合分此珍。", "顧省忝邦守，又慙復因循。", "茫茫滄海間，丹憤何由申。"]'),
('e583001a-c3a7-4b5f-9e66-d2f9371d2c13','送惟詳律師自越之義興','崔子向','唐','唐诗','tang','','[]','陽羨諸峰頂，何曾異剡山。',48,'全唐诗/poet.tang.16000.json','["陽羨諸峰頂，何曾異剡山。", "雨晴人到寺，木落夜開關。", "縫衲紗燈亮，看心錫杖閑。", "西方知有社，未得與師還。"]'),
('f01db97a-eb46-44bd-9ea8-f567ac9ca447','上鮑大夫','崔子向','唐','唐诗','tang','','[]','行盡江南塞北時，無人不誦鮑家詩。',32,'全唐诗/poet.tang.16000.json','["行盡江南塞北時，無人不誦鮑家詩。", "東堂桂樹何年折，直至如今少一枝。"]'),
('7ece95cb-79bc-437a-973b-7c5e388185db','題越王臺','崔子向','唐','唐诗','tang','','[]','越井崗頭松柏老，越王臺上生秋草。',32,'全唐诗/poet.tang.16000.json','["越井崗頭松柏老，越王臺上生秋草。", "古木多年無子孫，牛羊踐踏成官道。"]'),
('35114ff1-afd4-49fd-bc9f-e35acd942986','贈韓退之','張署','唐','唐诗','tang','','[]','九疑峰畔二江前，戀闕思鄉日抵年。',64,'全唐诗/poet.tang.16000.json','["九疑峰畔二江前，戀闕思鄉日抵年。", "白簡趨朝曾竝命，蒼梧左宦一聊翩。", "鮫人遠泛漁舟水，鵩鳥閑飛露裏天。", "渙汗幾時流率土，扁舟西下共歸田。"]'),
('12784fcd-06f6-4864-bd4b-b8a871c441a5','享惠昭太子廟樂章','歸登','唐','唐诗','tang','','[]','嘉薦既陳，祀事孔明。',40,'全唐诗/poet.tang.16000.json','["嘉薦既陳，祀事孔明。", "間歌在堂，萬舞在庭。", "外則盡物，內則盡誠。", "鳳笙如聞，歆其潔精。"]'),
('954bf9b1-ed59-4bca-8f60-5cc747cbd58c','剡溪行却寄新別者','朱放','唐','唐诗','tang','','[]','潺湲寒溪上，自此成離別。',48,'全唐诗/poet.tang.16000.json','["潺湲寒溪上，自此成離別。", "廻首望歸人，移舟逢暮雪。", "頻行識草樹，漸老傷年髮。", "唯有白雲心，爲向東山月。"]'),
('1e68bd0e-37f6-4d40-a6d3-b03589b51cb0','九日陪劉中丞宴昌樂寺送梁廷評','朱放','唐','唐诗','tang','','[]','獨坐三臺妙，重陽百越間。',48,'全唐诗/poet.tang.16000.json','["獨坐三臺妙，重陽百越間。", "水心觀遠俗，霜氣入秋山。", "不棄遺簪舊，寧辭落帽還。", "仍聞西上客，咫尺謁天顏。"]'),
('9dfa43bd-32fe-459d-bec3-7e391bc247cd','經故賀賓客鏡湖道士觀','朱放','唐','唐诗','tang','','[]','已得歸鄉里，逍遙一外臣。',48,'全唐诗/poet.tang.16000.json','["已得歸鄉里，逍遙一外臣。", "那隨流水去，不待鏡湖春。", "雪裏登山屐，林間漉酒巾。", "空餘道士觀，誰是學仙人。"]'),
('cee4158e-e753-43bf-9a2a-99d4148d3d1a','送著公歸越','朱放','唐','唐诗','tang','','[]','誰能愁此別，到越會相逢。',48,'全唐诗/poet.tang.16000.json','["誰能愁此別，到越會相逢。", "長憶雲門寺，門前千萬峰。", "石牀埋積雪，山路倒枯松。", "莫學白道士，無人知去蹤。"]'),
('76327dab-5c19-42e7-a276-1294a1709caf','秣陵送客入京','朱放','唐','唐诗','tang','','[]','秣陵春已至，君去學歸鴻。',48,'全唐诗/poet.tang.16000.json','["秣陵春已至，君去學歸鴻。", "綠水琴聲切，青袍草色同。", "鳥喧金谷樹，花滿洛陽宮。", "日日相思處，江邊楊柳風。"]'),
('27db32d1-c747-4c6d-a937-4091287b6622','靈門寺贈靈一上人','朱放','唐','唐诗','tang','','[]','所思勞旦夕，惆悵去湘東。',48,'全唐诗/poet.tang.16000.json','["所思勞旦夕，惆悵去湘東。", "禪客知何在，春山幾處同。", "獨行殘雪裏，相見暮雲中。", "請住東林寺，彌年事遠公。"]'),
('c4620a2b-9b8d-4eb4-8ca7-ef99fa9b479b','江上送別','朱放','唐','唐诗','tang','','[]','浦邊新見柳搖時，北客相逢只自悲。',64,'全唐诗/poet.tang.16000.json','["浦邊新見柳搖時，北客相逢只自悲。", "惆悵空知思後會，艱難不敢料前期。", "行看漢月愁征戰，共折江花怨別離。", "向夕孤城分首處，寂寥橫笛爲君吹。"]'),
('e01dc039-7097-4060-8741-df0ef66ec930','歸桐廬舊居寄嚴長史','朱放','唐','唐诗','tang','','[]','昨辭天子棹歸舟，家在桐廬憶舊丘。',64,'全唐诗/poet.tang.16000.json','["昨辭天子棹歸舟，家在桐廬憶舊丘。", "三月暖時花競發，兩溪分處水爭流。", "近聞江老傳鄉語，遙見家山減旅愁。", "或在醉中逢夜雪，懷賢應向剡川遊。"]'),
('56f4eb52-4489-494d-a140-817d264544c8','竹','朱放','唐','唐诗','tang','','[]','青林何森然，沈沈獨曙前。',120,'全唐诗/poet.tang.16000.json','["青林何森然，沈沈獨曙前。", "出牆同淅瀝，開戶滿嬋娟。", "籜卷初呈粉，苔侵亂上錢。", "疎中思水過，深處若山連。", "疊夜常栖露，清朝乍有蟬。", "砌陰迎緩策，簷翠對欹眠。", "迸笋雙分箭，繁梢一向偏。", "月過驚散雪，風動極聞泉。", "幽谷添詩譜，高人欲製篇。", "蕭蕭意何恨，不獨往湘川。"]'),
('ea3e49a3-7e47-47c3-ad1a-e73f28d3f1b8','銅雀妓','朱放','唐','唐诗','tang','','[]','恨唱歌聲咽，愁翻舞袖遲。',24,'全唐诗/poet.tang.16000.json','["恨唱歌聲咽，愁翻舞袖遲。", "西陵日欲暮，是妾斷腸時。"]'),
('3c229ea7-c9a5-4d13-8c76-376361f3c28e','毘陵留別','朱放','唐','唐诗','tang','','[]','別離非一處，此處最傷情。',24,'全唐诗/poet.tang.16000.json','["別離非一處，此處最傷情。", "白髮將春草，相隨日日生。"]'),
('e2651472-5d43-436f-92d9-d75cb2628c2f','題竹林寺','朱放','唐','唐诗','tang','','[]','歲月人間促，煙霞此地多。',24,'全唐诗/poet.tang.16000.json','["歲月人間促，煙霞此地多。", "殷勤竹林寺，能得幾廻過。"]'),
('e9a7ddac-9ea3-48a2-a928-0762e9b2c5c5','答陸[澧]','朱放','唐','唐诗','tang','','["\u7530\u56ed"]','松葉堪爲酒，春來釀幾多。',24,'全唐诗/poet.tang.16000.json','["松葉堪爲酒，春來釀幾多。", "不辭山路遠，踏雪也相過。"]'),
('d2a8f65a-d509-4498-b266-5bcb6edf8522','楊子津送人','朱放','唐','唐诗','tang','','[]','今朝楊子津，忽見五溪人。',24,'全唐诗/poet.tang.16000.json','["今朝楊子津，忽見五溪人。", "老病無餘事，丹砂乞五斤。"]'),
('35c33a52-1c3a-48bc-86b3-eb3d0820ea22','山中謁皇甫曾','朱放','唐','唐诗','tang','','[]','尋源路已盡，笑入白雲間。',24,'全唐诗/poet.tang.16000.json','["尋源路已盡，笑入白雲間。", "不解乘軺客，那知有此山。"]'),
('61d6b6c0-f564-4af0-9f10-761e37a92b64','剡山夜月','朱放','唐','唐诗','tang','','[]','月在沃洲山上，人歸剡縣溪邊。',28,'全唐诗/poet.tang.16000.json','["月在沃洲山上，人歸剡縣溪邊。", "漠漠黃花覆水，時時白鷺驚船。"]'),
('5134669f-2f36-4c7e-bf82-6534e429bf0e','九日與楊凝崔淑期登江上山會有故不得往因贈之','朱放','唐','唐诗','tang','','[]','欲從攜手登高去，一到門前意已無。',32,'全唐诗/poet.tang.16000.json','["欲從攜手登高去，一到門前意已無。", "那得更將頭上髮，學他年少插茱萸。"]'),
('f4236519-05da-479b-978d-20afd9807dbc','山中聽子規','朱放','唐','唐诗','tang','','[]','幽人自愛山中宿，又近葛洪丹井西。',32,'全唐诗/poet.tang.16000.json','["幽人自愛山中宿，又近葛洪丹井西。", "窗中有箇長松樹，半夜子規來上啼。"]'),
('81c5f483-c429-41d1-b348-1f9edb94f1d9','亂後經淮陰岸','朱放','唐','唐诗','tang','','[]','荒村古岸誰家在，野水浮雲處處愁。',32,'全唐诗/poet.tang.16000.json','["荒村古岸誰家在，野水浮雲處處愁。", "唯有河邊衰柳樹，蟬聲相送到揚州。"]'),
('96142aad-bfcb-4c04-b2af-19a9d834d365','送張山人','朱放','唐','唐诗','tang','','[]','知君住處足風煙，古寺荒村在眼前。',32,'全唐诗/poet.tang.16000.json','["知君住處足風煙，古寺荒村在眼前。", "便欲移家逐君去，唯愁未有買山錢。"]'),
('619f435c-0bff-4d9b-9961-6030b735d13c','別李季蘭','朱放','唐','唐诗','tang','','[]','古岸新花開一枝，岸傍花下有分離。',32,'全唐诗/poet.tang.16000.json','["古岸新花開一枝，岸傍花下有分離。", "莫將羅袖拂花落，便是行人腸斷時。"]'),
('9e19d83c-cf9f-4a92-bf32-2dcddb1d280d','遊石澗寺','朱放','唐','唐诗','tang','','[]','聞道幽深石澗寺，不逢流水亦難知。',32,'全唐诗/poet.tang.16000.json','["聞道幽深石澗寺，不逢流水亦難知。", "莫道山僧無伴侶，獼猴長在古松枝。"]'),
('1409de04-8027-4732-b7a8-780bcbdcc33c','新安所居答相訪人所居蕭使君爲制','朱放','唐','唐诗','tang','','[]','謝公見我多愁疾，爲我開門對碧山。',32,'全唐诗/poet.tang.16000.json','["謝公見我多愁疾，爲我開門對碧山。", "君若欲來看猿鳥，不須爭把桂枝攀。"]'),
('8f0393eb-6462-45a4-8fe1-c75794310dc2','送魏校書','朱放','唐','唐诗','tang','','[]','長恨江南足別離，幾廻相送復相隨。',32,'全唐诗/poet.tang.16000.json','["長恨江南足別離，幾廻相送復相隨。", "楊花撩亂撲流水，愁殺人行知不知。"]'),
('e5ef3391-9223-4cdc-90c1-4479421166bb','送溫台','朱放','唐','唐诗','tang','','[]','眇眇天涯君去時，浮雲流水自相隨。',32,'全唐诗/poet.tang.16000.json','["眇眇天涯君去時，浮雲流水自相隨。", "人生一世長如客，何必今朝是別離。"]'),
('39dfdc61-5137-4cf1-9e16-810c09854ef4','句','朱放','唐','唐诗','tang','','[]','愛彼雲外人，求取磵底泉。',24,'全唐诗/poet.tang.16000.json','["愛彼雲外人，求取磵底泉。", "風吹芭蕉拆，鳥啄梧桐落。"]'),
('96c2637f-6955-4d16-84da-d365ac65e6f6','古意','武元衡','唐','唐诗','tang','','[]','蜀國春與秋，岷江朝夕流。',60,'全唐诗/poet.tang.16000.json','["蜀國春與秋，岷江朝夕流。", "長波東接海，萬里至揚州。", "開門面淮甸，楚俗饒歡宴。", "舞榭黃金梯，歌樓白雲面。", "蕩子未言歸，池塘月如練。"]'),
('ebdfb300-4a19-402b-8699-36651d5e1e5f','塞下曲','武元衡','唐','唐诗','tang','','[]','草枯馬蹄輕，角弓勁如石。',72,'全唐诗/poet.tang.16000.json','["草枯馬蹄輕，角弓勁如石。", "驕虜初欲來，風塵暗南國。", "走檄召都尉，星火勦羌狄。", "吾身許報主，何暇避鋒鏑。", "白露濕鐵衣，半夜待攻擊。", "龍沙早立功，名向燕然勒。"]'),
('58e6bae1-ebe7-4d5c-95e9-15a1e3b2196d','獨不見','武元衡','唐','唐诗','tang','','[]','荆門一柱觀，楚國三休殿。',84,'全唐诗/poet.tang.16000.json','["荆門一柱觀，楚國三休殿。", "環珮儼神仙，輝光生顧盼。", "春風細腰舞，明月高堂宴。", "夢澤水連雲，渚宮花似霰。", "俄驚白日晚，始悟炎涼變。", "別島異波潮，離鴻分海縣。", "南北斷相聞，歎嗟獨不見。"]'),
('4214d7ff-667b-4385-ac26-81484cf19ed2','旬假南亭寄熊郎中','武元衡','唐','唐诗','tang','','[]','旬休屏戎事，涼雨北窗眠。',120,'全唐诗/poet.tang.16000.json','["旬休屏戎事，涼雨北窗眠。", "江城一夜雨，萬里繞山川。", "草木散幽氣，池塘鳴早蟬。", "妍芳落春後，旅思生秋前。", "紅槿粲庭豔，綠蒲繁渚煙。", "行歌獨謠酌，坐發朱絲弦。", "哀玉不可扣，華燭徒湛然。", "聞君樂林臥，郡閣曠周旋。", "酬對龍象侶，灌注清泠泉。", "如何無礙智，猶苦病纏牽。"]'),
('77e2e49f-c95f-4deb-84ba-4af7aab28da2','晨興寄贈竇使君','武元衡','唐','唐诗','tang','','[]','江陵歲方晏，晨起眄庭柯。',96,'全唐诗/poet.tang.16000.json','["江陵歲方晏，晨起眄庭柯。", "白露傷紅葉，清風斷綠蘿。", "徇時真氣索，念遠懷憂多。", "夙昔樂山意，縱橫南浦波。", "有美嬋娟子，百慮攢雙蛾。", "緘情鬱不舒，幽行駢復羅。", "爲予歌苦寒，酌酒朱顏酡。", "世事浮雲變，功名將奈何。"]'),
('d3d65f19-7b17-430e-b3c0-cbf69f2c27ff','秋日對酒','武元衡','唐','唐诗','tang','','[]','行年過始衰，秋至獨先悲。',168,'全唐诗/poet.tang.16000.json','["行年過始衰，秋至獨先悲。", "事往憐神魄，感深滋涕洟。", "百憂紛在慮，一醉兀無思。", "寶瑟拂麈匣，徽音凝朱絲。", "幽圃蕙蘭氣，煙窗松桂姿。", "我乏濟時略，杖節撫藩維。", "山川大兵後，牢落空城池。", "驚沙猶振野，綠草生荒陂。", "物變風雨順，人懷天地慈。", "春耕事秋戰，戎馬去封陲。", "波瀾暗超忽，堅白亦磷緇。", "客有自嵩潁，重徵棲隱期。", "丹訣學仙晚，白雲歸谷遲。", "君恩不可報，霜露繞南枝。"]'),
('d76f7632-9926-40d4-8ac2-497f7ca08223','安邑里中秋懷寄高員外','武元衡','唐','唐诗','tang','','[]','原憲素非貧，嵇康自寡欲。',120,'全唐诗/poet.tang.16000.json','["原憲素非貧，嵇康自寡欲。", "守道識通窮，達命齊榮辱。", "庭梧變葱蒨，籬菊揚芳馥。", "墜葉翻夕霜，高堂瞬華燭。", "況茲寒夜永，復歎流年促。", "感物思殷勤，懷賢心躑躅。", "雄詞封禪草，麗句陽春曲。", "高德十年兄，異才千里足。", "咫尺邈雪霜，相望如瓊玉。", "欲識歲寒心，松筠更秋綠。"]'),
('8184fda1-03e8-47cf-8d73-569079ec2c93','送唐次','武元衡','唐','唐诗','tang','','[]','都門去馬嘶，灞水春流淺。',36,'全唐诗/poet.tang.16000.json','["都門去馬嘶，灞水春流淺。", "青槐驛路長，白日離尊晚。", "望望煙景微，草色行人遠。"]'),
('26246a65-c679-431b-8f2a-670769edb7b6','秋夜雨中懷友','武元衡','唐','唐诗','tang','','[]','庭空雨鳴驕，天寒鴈啼苦。',40,'全唐诗/poet.tang.16000.json','["庭空雨鳴驕，天寒鴈啼苦。", "青燈淡吐光，白髮悄無語。", "幾年不與聯牀吟，君方客吳我猶楚。"]'),
('401eb402-25a0-471d-a0d2-6c68d273d7ea','望夫石','武元衡','唐','唐诗','tang','','[]','佳名望夫處，苔蘚封孤石。',40,'全唐诗/poet.tang.16000.json','["佳名望夫處，苔蘚封孤石。", "萬里水連天，巴江暮雲碧。", "湘妃泣下竹成斑，子規夜啼江樹白。"]'),
('23fdcbe4-3063-481e-9807-89e47b6daf92','行路難','武元衡','唐','唐诗','tang','','[]','君不見道旁廢井傍開花，原是昔年驕貴家。',111,'全唐诗/poet.tang.16000.json','["君不見道旁廢井傍開花，原是昔年驕貴家。", "幾度美人來照影，濯纖笑引銀瓶綆。", "風飄雨散今奈何，繡闥雕甍綠苔多。", "笙歌鼎沸君莫矜，豪奢未必長多金。", "休說編氓朴無耻，至竟終須合天理。", "非故敗他却成此，蘇張終作多言鬼。", "行路難，路難不在九折灣。"]'),
('fb602c4f-bdaa-4fea-9d77-147baac66358','長相思','武元衡','唐','唐诗','tang','','[]','長相思，隴雲愁，單于臺上望伊州。',48,'全唐诗/poet.tang.16000.json','["長相思，隴雲愁，單于臺上望伊州。", "鴈書絕，蟬鬢秋。", "行人天一畔，暮雨海西頭。", "殷勤大河水，東注不還流。"]'),
('0b56e203-9c57-4ea7-b337-b174f9a00c95','出塞作','武元衡','唐','唐诗','tang','','[]','夙駕逾人境，長驅出塞垣。',84,'全唐诗/poet.tang.16000.json','["夙駕逾人境，長驅出塞垣。", "邊風引去騎，胡沙拂征轅。", "奏笳山月白，結陣瘴雲昏。", "雖云風景異華夏，亦喜地理通樓煩。", "白羽矢飛先火礮，黃金甲耀奪朝暾。", "要須灑掃龍沙淨，歸謁明光一報恩。"]'),
('ecfeec5e-3205-401e-bc5d-e9b58efb9031','桃源行送友','武元衡','唐','唐诗','tang','','[]','武陵川徑入幽遐，中有雞犬秦人家，家傍流水多桃花。',152,'全唐诗/poet.tang.16000.json','["武陵川徑入幽遐，中有雞犬秦人家，家傍流水多桃花。", "桃花兩邊種來久，流水一通何時有。", "垂條落蘂暗春風，夾岸芳菲至山口。", "歲歲年年能寂寥，林下青苔日爲厚。", "時有仙鳥來銜花，曾無世人此攜手。", "可憐不知若爲名，君往從之多所更。", "古驛荒橋平路盡，崩湍怪石小溪行。", "相見維舟登覽處，紅堤綠岸宛然成。", "多君此去從仙隱，令人晚節悔營營。"]'),
('afb30a0c-422f-4656-b0bb-90174c0d3d1f','長安敘懷寄崔十五','武元衡','唐','唐诗','tang','','[]','延首直城西，花飛綠草齊。',208,'全唐诗/poet.tang.16000.json','["延首直城西，花飛綠草齊。", "迢遙隔山水，悵望思遊子。", "百囀黃鸝細雨中，千條翠柳衡門裏。", "門對長安九衢路，愁心不惜芳菲度。", "風塵冉冉秋復春，鐘鼓喧喧朝復暮。", "漢家宮闕在中天，紫陌朝臣車馬連。", "蕭蕭霓旌合仙杖，悠悠劍佩入爐煙。", "李廣少時思報國，終軍未遇敢論邊。", "無媒守儒行，榮悴紛相映。", "家甚長卿貧，身多公幹病。", "不知身病竟如何，嬾向青山眠薜蘿。", "雞黍空多元伯惠，琴書不見子猷過。", "超名累歲與君同，自歎還隨鷁退風。", "聞說唐生子孫在，何當一爲問窮通。"]'),
('d0cc0807-e34e-40a0-87db-14a46aa351e4','兵行褒斜谷作','武元衡','唐','唐诗','tang','','[]','古地接龜沙，邊風送征鴈。',96,'全唐诗/poet.tang.16000.json','["古地接龜沙，邊風送征鴈。", "霜明草正腓，峰逼日易晏。", "集旅布嵌谷，驅馬歷層澗。", "岷河源涉屢，蜀甸途行慣。", "矢橐弧室豈領軍，儋爵食祿由從宦。", "注意奏凱赴都畿，速令提兵還石坂。", "三川頓使氣象清，賣刀買犢消憂患。"]'),
('83f707b8-0404-464e-94dd-2ab8ba345ed9','西亭早秋送徐員外','武元衡','唐','唐诗','tang','','[]','鼎鉉辭台座，麾幢領益州。',48,'全唐诗/poet.tang.16000.json','["鼎鉉辭台座，麾幢領益州。", "曲池連月曉，橫角滿城秋。", "有美皇華使，曾同白社遊。", "今年重相見，偏覺豔歌愁。"]'),
('364673e8-596d-48fe-88bd-87dd2d433947','送徐員外還京','武元衡','唐','唐诗','tang','','[]','九折朱輪動，三巴白露生。',48,'全唐诗/poet.tang.16000.json','["九折朱輪動，三巴白露生。", "蕙蘭秋意晚，關塞別魂驚。", "寶瑟連宵怨，金罍盡醉傾。", "旄頭星未落，分手轆轤鳴。"]'),
('3619812f-2589-4209-a9c3-e23163d5632a','送柳郎中裴起居','武元衡','唐','唐诗','tang','','[]','沱江水綠波，喧鳥去喬柯。',48,'全唐诗/poet.tang.16000.json','["沱江水綠波，喧鳥去喬柯。", "南浦別離處，東風蘭杜多。", "長亭春婉娩，層漢路蹉跎。", "會有歸朝日，班超奈老何。"]'),
('91a1ff6c-4cf8-497f-8c79-2e5f9a997e9d','八月十五酬從兄常望月有懷','武元衡','唐','唐诗','tang','','[]','坐愛圓景滿，況茲秋夜長。',48,'全唐诗/poet.tang.16000.json','["坐愛圓景滿，況茲秋夜長。", "寒光生露草，夕韻出風篁。", "地遠驚金奏，天高失鴈行。", "如何北樓望，不得共池塘。"]'),
('87a501b5-58c6-40d4-a1bd-ad8319227268','酬太常從兄留別','武元衡','唐','唐诗','tang','','[]','鄉路日茲始，征軒行復留。',48,'全唐诗/poet.tang.16000.json','["鄉路日茲始，征軒行復留。", "張騫隨漢節，王濬守刀州。", "澤國煙花度，銅梁霧雨愁。", "別離無可奈，萬恨錦江流。"]'),
('680c2d30-359c-475e-8e95-069f7018fdb0','春日與諸公汎舟','武元衡','唐','唐诗','tang','','[]','千里雪山開，沱江春水來。',48,'全唐诗/poet.tang.16000.json','["千里雪山開，沱江春水來。", "駐帆雲縹緲，吹管鶴裴回。", "身外流年駛，尊前落景催。", "不應歸棹遠，明月在高臺。"]'),
('4fc80155-a4b9-42e8-a28e-492b621dfbe2','送兄歸洛使謁嚴司空','武元衡','唐','唐诗','tang','','[]','六歲蜀城守，千莖蓬鬢絲。',48,'全唐诗/poet.tang.16000.json','["六歲蜀城守，千莖蓬鬢絲。", "憂心不自遣，骨肉又傷離。", "楚峽饒雲雨，巴江足夢思。", "殷勤孔北海，時節易流移。"]'),
('4f2ba0af-e9ae-4140-90f9-a023c565867a','同洛陽諸公餞盧起居','武元衡','唐','唐诗','tang','','[]','蕭條寒日晏，悽慘別魂驚。',48,'全唐诗/poet.tang.16000.json','["蕭條寒日晏，悽慘別魂驚。", "寶瑟無聲怨，金囊故贈輕。", "赤墀方載筆，油幕尚言兵。", "暮宿青泥驛，煩君淚滿纓。"]'),
('7a509b7e-925b-4491-adea-fc0ad238486c','臺中題壁','武元衡','唐','唐诗','tang','','[]','柏臺年未老，蓬鬢忽蒼蒼。',48,'全唐诗/poet.tang.16000.json','["柏臺年未老，蓬鬢忽蒼蒼。", "無事裨明主，何心弄憲章。", "雀聲愁霰雪，鴻思恨關梁。", "會脫簪纓去，故山瑤草芳。"]'),
('6a44e09a-a28d-49b8-849f-33cb5d4c4d1e','江上寄隱者','武元衡','唐','唐诗','tang','','[]','歸舟不計程，江月屢虧盈。',48,'全唐诗/poet.tang.16000.json','["歸舟不計程，江月屢虧盈。", "靄靄滄波路，悠悠離別情。", "蒹葭連水國，鼙鼓近梁城。", "却憶沿江叟，汀洲春草生。"]'),
('73c79950-a19d-4340-aa2f-71af524cae13','送嚴紳遊蘭溪','武元衡','唐','唐诗','tang','','[]','剡嶺窮邊海，君遊別嶺西。',36,'全唐诗/poet.tang.16000.json','["剡嶺窮邊海，君遊別嶺西。", "暮雲秋水闊，寒雨夜猿啼。", "地僻秦人少，山多越路迷。"]'),
('5849dc58-0b5b-4181-ad61-285eb6ca25f5','秋思','武元衡','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','秋室浩煙霧，風柳怨寒蜩。',48,'全唐诗/poet.tang.16000.json','["秋室浩煙霧，風柳怨寒蜩。", "機杼夜聲切，蕙蘭芳意消。", "美人湘水曲，桂檝洞庭遙。", "常恐時光謝，蹉跎紅豔凋。"]'),
('4f63732c-24f6-45ec-804b-b183463f66dc','夏日別盧太卿','武元衡','唐','唐诗','tang','','[]','漢水清且廣，江波渺復深。',48,'全唐诗/poet.tang.16000.json','["漢水清且廣，江波渺復深。", "葉舟煙雨夜，之子別離心。", "汀草結春怨，山雲連暝陰。", "年年南北淚，今古共霑襟。"]'),
('87184327-e070-4689-b718-15d9213fd8b4','西亭題壁寄中書李相公','武元衡','唐','唐诗','tang','','[]','昏旦倦興寢，端憂力尚微。',48,'全唐诗/poet.tang.16000.json','["昏旦倦興寢，端憂力尚微。", "廉頗不覺老，蘧瑗始知非。", "授鉞虛三顧，持衡曠萬機。", "空餘蝴蝶夢，迢遰故山歸。"]'),
('062b7acd-b84f-4fe3-a61f-27d5123ac326','八月十五夜與諸公錦樓望月得中字','武元衡','唐','唐诗','tang','','[]','玉輪初滿空，迥出錦城東。',48,'全唐诗/poet.tang.16000.json','["玉輪初滿空，迥出錦城東。", "相向秦樓鏡，分飛碣石鴻。", "桂香隨窈窕，珠綴隔玲瓏。", "不及前秋月，圓輝鳳沼中。"]'),
('36b74977-35c1-4475-b261-5327f9bdcae0','四川使宅有韋令公時孔雀存焉暇日與諸公同翫座中兼故府賓妓興嗟久之因賦此詩用廣其意','武元衡','唐','唐诗','tang','','[]','荀令昔居此，故巢留越禽。',48,'全唐诗/poet.tang.16000.json','["荀令昔居此，故巢留越禽。", "動搖金翠尾，飛舞碧梧陰。", "上客徹瑤瑟，美人傷蕙心。", "會因南國使，得放海雲深。"]'),
('c1332edf-9a0b-4b95-8ea7-ea76bf7f6fa5','竇三中丞去歲有臺中五言四韻未及酬報今領黔南途經蜀門百里而近願言欵覿封略間然因追曩篇持以贈之','武元衡','唐','唐诗','tang','','[]','在昔謬司憲，常僚惟有君。',48,'全唐诗/poet.tang.16000.json','["在昔謬司憲，常僚惟有君。", "報恩如皎日，致位等青雲。", "削藁書難見，除苛事早吟。", "雙旌不可駐，風雪路岐分。"]'),
('2a9e9484-43c6-4426-91d3-bd3525ff18e0','春分與諸公同宴呈陸三十四郎中','武元衡','唐','唐诗','tang','','[]','南國宴佳賓，交情老倍親。',48,'全唐诗/poet.tang.16000.json','["南國宴佳賓，交情老倍親。", "月慙紅燭淚，花笑白頭人。", "寶瑟常餘怨，瓊枝不讓春。", "更聞歌子夜，桃李豔妝新。"]'),
('a1273143-471c-408a-aa03-3880e9c4b6bd','津梁寺採新茶與幕中諸公遍賞芳香尤異因題四韻兼呈陸郎中','武元衡','唐','唐诗','tang','','[]','靈州碧巖下，荑英初散芳。',48,'全唐诗/poet.tang.16000.json','["靈州碧巖下，荑英初散芳。", "塗塗猶宿露，采采不盈筐。", "陰竇藏煙濕，單衣染焙香。", "幸將調鼎味，一爲奏明光。"]'),
('110c9e6d-a4d8-4d69-ba7d-f6382955c10b','元和癸巳余領蜀之七年奉詔徴還二月二十八日清明途經百牢關因題石門洞','武元衡','唐','唐诗','tang','','[]','昔佩兵符去，今持相印還。',48,'全唐诗/poet.tang.16000.json','["昔佩兵符去，今持相印還。", "天光臨井絡，春物度巴山。", "鳥道青冥外，風泉洞壑間。", "何慙班定遠，辛苦玉門關。"]'),
('21461387-1e42-4761-8936-ee3ae85b549d','夕次潘山下','武元衡','唐','唐诗','tang','','[]','南國獨行日，三巴春草齊。',48,'全唐诗/poet.tang.16000.json','["南國獨行日，三巴春草齊。", "漾波歸海疾，危棧入雲迷。", "錦谷嵐煙裏，刀州晚照西。", "旅情方浩蕩，蜀魄滿林啼。"]'),
('8fc09639-9e38-402f-9827-589c1cc161ff','夏日對雨寄朱放拾遺','武元衡','唐','唐诗','tang','','[]','才非谷永傳，無意謁王侯。',48,'全唐诗/poet.tang.16000.json','["才非谷永傳，無意謁王侯。", "小暑金將伏，微涼麥正秋。", "遠山欹枕見，暮雨閉門愁。", "更憶東林寺，詩家第一流。"]'),
('953887a3-ceb3-460f-b178-499ba1b1f0b8','早春送歐陽鍊師歸山','武元衡','唐','唐诗','tang','','[]','雙鶴五雲車，初辭漢帝家。',48,'全唐诗/poet.tang.16000.json','["雙鶴五雲車，初辭漢帝家。", "人寰新甲子，天路舊煙霞。", "羽節臨風駐，霓裳逐雨斜。", "崑崙有琪樹，相憶寄瑤華。"]'),
('9d506e1b-6e66-4c4e-907f-8347430a7594','長安春望','武元衡','唐','唐诗','tang','','[]','宿雨淨煙霞，春風綻百花。',48,'全唐诗/poet.tang.16000.json','["宿雨淨煙霞，春風綻百花。", "綠楊中禁路，朱戟五侯家。", "草色金隄晚，鶯聲御柳斜。", "無媒猶未達，應共惜年華。"]'),
('8833b8b1-067f-4b02-bf16-4315e7df3d5e','經嚴祕校維故宅','武元衡','唐','唐诗','tang','','[]','掩淚山陽宅，生涯此路窮。',48,'全唐诗/poet.tang.16000.json','["掩淚山陽宅，生涯此路窮。", "香銷芸閣閉，星落草堂空。", "麗藻浮名裏，哀聲夕照中。", "不堪投釣處，隣笛怨春風。"]'),
('f5435aa2-b351-4a3e-9035-5aab719775f0','秋夜寄江南舊遊','武元衡','唐','唐诗','tang','','[]','寥落九秋晚，端憂時物殘。',48,'全唐诗/poet.tang.16000.json','["寥落九秋晚，端憂時物殘。", "隔林螢影度，出禁漏聲寒。", "愁雨洞房掩，孤燈遙夜闌。", "懷賢夢南國，興盡水漫漫。"]'),
('30963db0-027c-4aa1-8627-c4312bde6991','送陸書還吳','武元衡','唐','唐诗','tang','','[]','君住包山下，何年入帝鄉。',48,'全唐诗/poet.tang.16000.json','["君住包山下，何年入帝鄉。", "成名歸舊業，歎別見秋光。", "橘柚吳洲遠，蘆花楚水長。", "我行經此路，京口向雲陽。"]'),
('3d2c1165-a191-4109-9b8d-8d0afd1e773c','山中月夜寄朱張二舍人','武元衡','唐','唐诗','tang','','[]','午夜更漏裏，九重霄漢間。',48,'全唐诗/poet.tang.16000.json','["午夜更漏裏，九重霄漢間。", "月華雲闕迥，秋色鳳池閑。", "御錦通清禁，天書出暗關。", "嵇康不求達，終歲在空山。"]'),
('e37763c5-6ff1-4e3f-b562-1f8f473ae119','送馮諫議赴河北宣慰','武元衡','唐','唐诗','tang','','["\u9ec4\u6cb3"]','漢代衣冠盛，堯年雨露多。',48,'全唐诗/poet.tang.16000.json','["漢代衣冠盛，堯年雨露多。", "恩榮辭紫禁，冰雪渡黃河。", "待詔孤城啓，宣風萬歲和。", "今宵燕分野，應見使星過。"]'),
('86958501-1766-4e82-9993-4f6958a5830c','夜坐聞雨寄嚴十少府','武元衡','唐','唐诗','tang','','[]','多負雲霄志，生涯歲序侵。',48,'全唐诗/poet.tang.16000.json','["多負雲霄志，生涯歲序侵。", "風翻涼葉亂，雨滴洞房深。", "迢遰三秋夢，殷勤獨夜心。", "懷賢不覺寐，清磬發東林。"]'),
('c698e805-b9af-4674-9526-4cfe5df6217c','資聖寺賁法師晚春茶會','武元衡','唐','唐诗','tang','','[]','虛室晝常掩，心源知悟空。',48,'全唐诗/poet.tang.16000.json','["虛室晝常掩，心源知悟空。", "禪庭一雨後，蓮界萬花中。", "時節流芳暮，人天此會同。", "不知方便理，何路出樊籠。"]'),
('c0d6e3cd-5aeb-4b92-9548-2eb6da3ed0f0','慈恩寺起上人院','武元衡','唐','唐诗','tang','','[]','禪堂支許同，清論道源窮。',48,'全唐诗/poet.tang.16000.json','["禪堂支許同，清論道源窮。", "起滅秋雲盡，虛無夕靄空。", "池澄山倒影，林動葉翻風。", "他日焚香待，還來禮惠聰。"]'),
('97c270ca-9b1d-46f7-a349-c2650b0828de','送魏正則擢第歸江陵','武元衡','唐','唐诗','tang','','[]','客路商山外，離筵小暑前。',48,'全唐诗/poet.tang.16000.json','["客路商山外，離筵小暑前。", "高文常獨步，折桂及齠年。", "關國通秦限，波濤隔漢川。", "叨同會府選，分手倍依然。"]'),
('4c4dde49-e849-405e-8587-caa4ae37af11','酬韓弇歸崖見寄','武元衡','唐','唐诗','tang','','[]','惆悵人間事，東山遂獨遊。',48,'全唐诗/poet.tang.16000.json','["惆悵人間事，東山遂獨遊。", "露凝瑤草晚，魚戲石潭秋。", "軒冕應相待，煙霞莫遽留。", "君看仲連意，功立始滄洲。"]'),
('d044cf9f-c166-47c0-bd58-e9124cb2900b','河東贈別鍊師','武元衡','唐','唐诗','tang','','[]','多累有行役，相逢秋節分。',48,'全唐诗/poet.tang.16000.json','["多累有行役，相逢秋節分。", "游人甘失路，野鶴亦離羣。", "戎馬犯邊壘，天兵屯塞雲。", "孔璋才素健，羽檄定紛紛。"]'),
('cba6cf4f-5a8d-45a7-ad4a-c84ab053b9c1','秋日將赴江上楊弘微時任鳳翔寄詩別','武元衡','唐','唐诗','tang','','[]','寂寞兩相阻，悠悠南北心。',48,'全唐诗/poet.tang.16000.json','["寂寞兩相阻，悠悠南北心。", "燕驚滄海遠，鴻避朔雲深。", "夜夢江亭月，離憂隴樹陰。", "兼秋無限思，惆悵屬瑤琴。"]'),
('0b3e5eb5-cd73-4302-a588-c1a9c2f50299','夏與熊王二秀才同宿僧院','武元衡','唐','唐诗','tang','','[]','共將纓上塵，來問雪山人。',48,'全唐诗/poet.tang.16000.json','["共將纓上塵，來問雪山人。", "世網從知累，禪心自證真。", "境空宜入夢，藤古不留春。", "一聽林公法，靈嘉願寄身。"]'),
('a5242c06-b49d-4162-b1bc-ad478bfb6686','宜陽所居白蜀葵荅詠柬諸公','武元衡','唐','唐诗','tang','','[]','冉冉衆芳歇，亭亭虛室前。',48,'全唐诗/poet.tang.16000.json','["冉冉衆芳歇，亭亭虛室前。", "敷榮時已背，幽賞地宜偏。", "紅豔世方重，素華徒可憐。", "何當君子願，知不競喧妍。"]'),
('a7e7bd1f-e3b7-40f8-8fb2-08539c80acbe','送寇侍御司馬之明州','武元衡','唐','唐诗','tang','','[]','斗酒上河梁，驚魂去越鄉。',48,'全唐诗/poet.tang.16000.json','["斗酒上河梁，驚魂去越鄉。", "地窮滄海闊，雲入剡山長。", "蓮唱蒲萄熟，人煙橘柚香。", "蘭亭應駐楫，今古共風光。"]'),
('a964c4bd-9c7b-4294-94b4-51e0ee5e20b0','送嚴侍御','武元衡','唐','唐诗','tang','','[]','巴檄故人去，蒼蒼楓樹林。',48,'全唐诗/poet.tang.16000.json','["巴檄故人去，蒼蒼楓樹林。", "雲山千里合，霧雨四時陰。", "峽路猨聲斷，桃源犬吠深。", "不須貪勝賞，漢節待南侵。"]'),
('64e805a4-12a0-40f9-afd1-3a94aefca0a4','酬元十二','武元衡','唐','唐诗','tang','','[]','偶尋烏府客，同醉習家池。',48,'全唐诗/poet.tang.16000.json','["偶尋烏府客，同醉習家池。", "積雪初迷徑，孤雲遂失期。", "風前勞引領，月下重相思。", "何必因尊酒，幽心兩自知。"]'),
('7c43f117-eb55-4a6e-b931-45e7c65dce39','秋晚途次坊州界寄崔玉員外','武元衡','唐','唐诗','tang','','[]','崎嶇崖谷迷，寒雨暮成泥。',48,'全唐诗/poet.tang.16000.json','["崎嶇崖谷迷，寒雨暮成泥。", "征路出山頂，亂雲生馬蹄。", "望鄉程杳杳，懷遠思悽悽。", "欲識分麾重，孤城萬壑西。"]'),
('05009d88-f526-447a-b90f-4bb0bf358429','度東徑嶺','武元衡','唐','唐诗','tang','','[]','又過鴈門北，不勝南客悲。',48,'全唐诗/poet.tang.16000.json','["又過鴈門北，不勝南客悲。", "三邊上巖見，雙淚望鄉垂。", "暮角雲中戍，殘陽天際旗。", "更看飛白羽，胡馬在封陲。"]'),
('3b3c5a9c-fc55-465e-a297-f097c787f0c6','送李正字之蜀','武元衡','唐','唐诗','tang','','[]','已獻甘泉賦，仍登片玉科。',48,'全唐诗/poet.tang.16000.json','["已獻甘泉賦，仍登片玉科。", "漢官新組綬，蜀國舊煙蘿。", "劒壁秋雲斷，巴江夜月多。", "無窮別離思，遙寄竹枝歌。"]'),
('4d3e991c-f883-4233-98b7-20da065f8e1c','玉泉寺與潤上人望秋山懷張少尹','武元衡','唐','唐诗','tang','','[]','山寒天降霜，煙月共蒼蒼。',48,'全唐诗/poet.tang.16000.json','["山寒天降霜，煙月共蒼蒼。", "況此綠巖晚，尚餘丹桂芳。", "禪心殊衆樂，人世滿秋光。", "莫怪頻回首，孤雲思帝鄉。"]'),
('270f49d1-7cec-4cd8-8638-b6db2913228a','酬崔使君寄麈尾','武元衡','唐','唐诗','tang','','[]','賢人嘉尚同，今製古遺風。',48,'全唐诗/poet.tang.16000.json','["賢人嘉尚同，今製古遺風。", "寄我襟懷裏，辭君掌握中。", "金聲勞振遠，玉柄借談空。", "執玩馳心處，迢迢巴峽東。"]'),
('3fcda882-c433-461b-9dee-3a85a1156d1b','送鄧州潘使君赴任','武元衡','唐','唐诗','tang','','[]','川陸一都會，旌旗千里舒。',48,'全唐诗/poet.tang.16000.json','["川陸一都會，旌旗千里舒。", "虎符中禁授，熊軾上流居。", "橘柚金難並，池塘練不如。", "春風行部日，應駐士元車。"]'),
('6772b365-5daf-4975-9989-621aa7c0d99b','和李中丞題故將軍林亭','武元衡','唐','唐诗','tang','','[]','帝里清和節，侯家邸第春。',48,'全唐诗/poet.tang.16000.json','["帝里清和節，侯家邸第春。", "煙霏瑤草露，苔暗杏梁塵。", "城郭悲歌舊，池塘麗句新。", "年年車馬客，鐘鼓樂他人。"]'),
('3622e042-00ac-4616-a5fb-438d5570defe','送韋侍御司議赴東都','武元衡','唐','唐诗','tang','','[]','洛京千里近，離緒亦紛紛。',48,'全唐诗/poet.tang.16000.json','["洛京千里近，離緒亦紛紛。", "文憲芙蓉沼，元方羔鴈羣。", "河關連鞏樹，嵩少接秦雲。", "獨有臨風思，睽攜不可聞。"]'),
('9dc15e9a-78d4-4f51-8a43-dfa771be0d59','送吳侍御司馬赴台州','武元衡','唐','唐诗','tang','','[]','盧耽佐郡遙，川陸共迢迢。',48,'全唐诗/poet.tang.16000.json','["盧耽佐郡遙，川陸共迢迢。", "風景輕吳會，文章變越謠。", "煙林繁橘柚，雲海浩波潮。", "余有靈山夢，前君到石橋。"]'),
('1880dfff-1b23-4609-af56-9b9a4904552e','送七兄赴歙州','武元衡','唐','唐诗','tang','','[]','車馬去憧憧，都門聞曉鐘。',48,'全唐诗/poet.tang.16000.json','["車馬去憧憧，都門聞曉鐘。", "客程將日遠，離緒與春濃。", "流水踰千度，歸雲隔萬重。", "玉杯傾酒盡，不換慘悽容。"]'),
('329663b5-4641-4a41-8f0a-106406d9592f','德宗皇帝挽歌詞三首 一','武元衡','唐','唐诗','tang','','[]','道啓軒皇聖，威揚夏禹功。',48,'全唐诗/poet.tang.16000.json','["道啓軒皇聖，威揚夏禹功。", "謳歌亭育外，文武盛明中。", "日月光連璧，煙塵屏大風。", "爲人祈福處，臺樹與天通。"]'),
('dec50ec6-d485-4b06-87e2-bbdeece9bab7','德宗皇帝挽歌詞三首 二','武元衡','唐','唐诗','tang','','[]','聖曆囗勤政，瑤圖慶運長。',48,'全唐诗/poet.tang.16000.json','["聖曆囗勤政，瑤圖慶運長。", "壽宮開此地，仙駕緲何鄉。", "風斷清笳調，雲愁綠斾揚。", "上升知不恨，弘濟任城王。"]'),
('0f3ef68d-e13f-441e-8c9c-0ad85fb66181','德宗皇帝挽歌詞三首 三','武元衡','唐','唐诗','tang','','[]','嘗聞閶闔前，星拱北辰籙。',48,'全唐诗/poet.tang.16000.json','["嘗聞閶闔前，星拱北辰籙。", "今來大明祖，輦駕橋山曲。", "松柏韻幽音，魚龍焰寒燭。", "歲歲秋風辭，兆人歌不足。"]'),
('ce49e8c5-8745-4999-b5ab-7cc04b8cd424','順宗至德大聖皇帝挽歌詞三首 一','武元衡','唐','唐诗','tang','','[]','橋山同軌會，軒后葬衣冠。',48,'全唐诗/poet.tang.16000.json','["橋山同軌會，軒后葬衣冠。", "東海風波變，西陵松柏攢。", "鼎湖仙已去，金掌露寧乾。", "萬木泉扃月，空憐鳧雁寒。"]'),
('2958c332-2b46-42d8-83c2-088c78ae1e49','順宗至德大聖皇帝挽歌詞三首 二','武元衡','唐','唐诗','tang','','["\u9ec4\u6cb3"]','容衛曉徘徊，嚴城閶闔開。',48,'全唐诗/poet.tang.16000.json','["容衛曉徘徊，嚴城閶闔開。", "烏號龍馭遠，遏密鳳聲哀。", "崑浪黃河注，崦嵫白日頹。", "恭聞天子孝，不忍望銅臺。"]'),
('5cded4d5-abd7-43ce-926b-7f6a4e94d2c2','順宗至德大聖皇帝挽歌詞三首 三','武元衡','唐','唐诗','tang','','[]','哀挽渭川曲，空歌汾水陽。',48,'全唐诗/poet.tang.16000.json','["哀挽渭川曲，空歌汾水陽。", "夜泉愁更咽，秋日慘無光。", "纘夏功傳啓，興周業繼昌。", "回瞻五陵上，煙雨爲蒼蒼。"]'),
('d3419bfd-ba8d-4451-b2f8-3891803eff63','昭德皇后挽歌詞','武元衡','唐','唐诗','tang','','[]','玉扆將遷坐，金雞忽報晨。',48,'全唐诗/poet.tang.16000.json','["玉扆將遷坐，金雞忽報晨。", "珮環僊馭遠，星月夜臺新。", "劍沒川空冷，菱寒鏡不春。", "國門車馬會，多是濯龍親。"]'),
('7c5d45b6-fb33-4fc8-91d0-2f7a8377ca98','春晚奉陪相公西亭宴集','武元衡','唐','唐诗','tang','','[]','林花春向闌，高會重邀歡。',48,'全唐诗/poet.tang.16000.json','["林花春向闌，高會重邀歡。", "感物惜芳景，放懷因綵翰。", "玉顏穠處並，銀燭焰中看。", "若折持相贈，風光益別難。"]'),
('04bcd6fd-df30-47c1-b489-e32f35dc1140','送崔判官使太原','武元衡','唐','唐诗','tang','','[]','勞君車馬此逡巡，我與劉君本世親。',64,'全唐诗/poet.tang.16000.json','["勞君車馬此逡巡，我與劉君本世親。", "兩地山河分節制，十年京洛共風塵。", "笙歌幾處胡天月，羅綺長留蜀國春。", "報主由來須盡敵，相期萬里寶刀新。"]'),
('dc387d29-7565-4b01-9156-47070e954306','幕中諸公有觀獵之作因繼之','武元衡','唐','唐诗','tang','','[]','刀州城北劒山東，甲士屯雲騎散風。',64,'全唐诗/poet.tang.16000.json','["刀州城北劒山東，甲士屯雲騎散風。", "旌斾遍張林嶺動，豺狼驅盡塞垣空。", "銜蘆遠雁愁縈繳，繞樹啼猨怯避弓。", "爲報府中諸從事，燕然未勒莫論功。"]'),
('d953b4b3-ab99-402a-aa87-3c342403c268','同幕中諸公送李侍御歸朝','武元衡','唐','唐诗','tang','','[]','昔年專席奉清朝，今日持書即舊僚。',64,'全唐诗/poet.tang.16000.json','["昔年專席奉清朝，今日持書即舊僚。", "珠履會中簫管思，白雲歸處帝鄉遙。", "巴江暮雨連三峽，劍壁危梁上九霄。", "歲月不堪相送盡，頹顏更被別離凋。"]'),
('76a21f2c-6033-4e0e-8d3e-dfbe798bd745','送張六諫議歸朝','武元衡','唐','唐诗','tang','','[]','詔書前日下丹霄，頭戴儒冠脫皂貂。',64,'全唐诗/poet.tang.16000.json','["詔書前日下丹霄，頭戴儒冠脫皂貂。", "笛怨柳營煙漠漠，雲愁江館雨蕭蕭。", "鴛鴻得路爭先翥，松柏凌寒獨後凋。", "歸去朝端如有問，玉關門外老班超。"]'),
('7ea9eba2-8921-40c2-8e52-a8ff4f2a881b','酬嚴司空荆南見寄','武元衡','唐','唐诗','tang','','[]','金貂再領三公府，玉帳連封萬戶侯。',64,'全唐诗/poet.tang.16000.json','["金貂再領三公府，玉帳連封萬戶侯。", "簾捲青山巫峽曉，煙開碧樹渚宮秋。", "劉琨坐嘯風清塞，謝朓題詩月滿樓。", "白雪調高歌不得，美人南國翠蛾愁。"]'),
('57379322-b132-4c32-a039-d5300ecb42f6','南徐別業早春有懷','武元衡','唐','唐诗','tang','','[]','生涯擾擾竟何成，自愛深居隱姓名。',64,'全唐诗/poet.tang.16000.json','["生涯擾擾竟何成，自愛深居隱姓名。", "遠雁臨空翻夕照，殘雲帶雨過春城。", "花枝入戶猶含潤，泉水侵堦乍有聲。", "虛度年華不相見，離腸懷土併關情。"]'),
('006a5958-9564-44f8-9192-f43eea6732a4','摩訶池宴','武元衡','唐','唐诗','tang','','[]','摩訶池上春光早，愛水看花日日來。',64,'全唐诗/poet.tang.16000.json','["摩訶池上春光早，愛水看花日日來。", "穠李雪開歌扇掩，綠楊風動舞腰回。", "蕪臺事往空留恨，金谷時危悟惜才。", "晝短欲將清夜繼，西園自有月裴回。"]'),
('2d8b4a47-338d-4496-aa9b-efaa652b04a0','至櫟陽崇道寺聞嚴十少府趨侍','武元衡','唐','唐诗','tang','','[]','雲連萬木夕沈沈，草色泉聲古院深。',64,'全唐诗/poet.tang.16000.json','["雲連萬木夕沈沈，草色泉聲古院深。", "聞說羊車趨盛府，何言瓊樹在東林。", "松筠自古多年契，風月懷賢此夜心。", "惆悵送君身未達，不堪搖落聽秋砧。"]'),
('e4cafa82-3850-44d1-8db1-65a0c983d8ee','春暮郊居寄朱舍人','武元衡','唐','唐诗','tang','','[]','幽深不讓子真居，度日閑眠世事疎。',64,'全唐诗/poet.tang.16000.json','["幽深不讓子真居，度日閑眠世事疎。", "春水滿池新雨霽，香風入戶落花餘。", "目隨鴻雁窮蒼翠，心寄溪雲任卷舒。", "回首知音青瑣闥，何時一爲薦相如。"]'),
('92786fed-bd1f-4b19-bbe1-145d5120f253','送溫況遊蜀','武元衡','唐','唐诗','tang','','[]','遊人西去客三巴，身逐孤蓬不定家。',64,'全唐诗/poet.tang.16000.json','["遊人西去客三巴，身逐孤蓬不定家。", "山近峨眉飛暮雨，江連濯錦起朝霞。", "雲深九折刀州遠，路繞千巖劍閣斜。", "應到嚴君開卦處，將余一爲問生涯。"]'),
('2807db58-9cdd-448f-9381-d33a361a2a63','崔敷歎春物將謝恨不同覽時余方爲事牽束及往尋不遇題之留贈','武元衡','唐','唐诗','tang','','[]','九陌遲遲麗景斜，禁街西訪隱淪賒。',64,'全唐诗/poet.tang.16000.json','["九陌遲遲麗景斜，禁街西訪隱淪賒。", "門依高柳空飛絮，身逐閑雲不在家。", "軒冕強來趨世路，琴尊空負賞年華。", "殘陽寂寞東城去，惆悵春風落盡花。"]'),
('3f218bb2-5f46-423d-869b-fa166ac8ba49','秋燈對雨寄史近崔積','武元衡','唐','唐诗','tang','','[]','坐聽宮城傳晚漏，起看衰葉下寒枝。',64,'全唐诗/poet.tang.16000.json','["坐聽宮城傳晚漏，起看衰葉下寒枝。", "空庭綠草結離念，細雨黃花贈所思。", "蟋蟀已驚良節度，茱萸偏憶故人期。", "相逢莫厭尊前醉，春去秋來自不知。"]'),
('77ffead6-d168-4e78-9468-6677c93c6ac5','春題龍門香山寺','武元衡','唐','唐诗','tang','','[]','衆香天上梵仙宮，鐘磬寥寥半碧空。',64,'全唐诗/poet.tang.16000.json','["衆香天上梵仙宮，鐘磬寥寥半碧空。", "清景乍開松嶺月，亂流長響石樓風。", "山河杳映春雲外，城闕參差茂樹中。", "欲盡出尋那可得，三千世界本無窮。"]'),
('f2ffb461-56cb-4e79-99b4-b2eed80d739c','酬陸三與鄒十八侍御','武元衡','唐','唐诗','tang','','[]','城分流水郭連山，拂露開懷一解顏。',64,'全唐诗/poet.tang.16000.json','["城分流水郭連山，拂露開懷一解顏。", "令尹關中仙史會，河陽縣裏玉人閑。", "共憐秋隼驚飛至，久想雲鴻待侶還。", "莫恨殷勤留此地，東崖桂樹昔同攀。"]'),
('6686869d-f1aa-43f9-9159-7a55ba801eaf','酬談校書長安秋夜對月寄諸故舊','武元衡','唐','唐诗','tang','','[]','故園千里渺遐情，黃葉蕭條白露生。',64,'全唐诗/poet.tang.16000.json','["故園千里渺遐情，黃葉蕭條白露生。", "驚鵲遶枝風滿幌，寒鐘送曉月當楹。", "蓬山高價傳新韻，槐市芳年挹盛名。", "莫怪孔融悲歲序，五侯門館重婁卿。"]'),
('5ef0bce0-bb24-434c-97ae-e58f3f64cb11','送田三端公還鄂州','武元衡','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','孤雲迢遰戀滄洲，勸酒梨花對白頭。',64,'全唐诗/poet.tang.16000.json','["孤雲迢遰戀滄洲，勸酒梨花對白頭。", "南陌送歸車騎合，東城怨別管弦愁。", "青油幕裏人如玉，黃鶴樓中月並鉤。", "君去庾公應借問，馳心千里大江流。"]'),
('25cbb64b-a015-4a1a-a76a-1cc554f0495d','送李秀才赴滑州詣大夫舅','武元衡','唐','唐诗','tang','','[]','陌頭車馬去翩翩，白面懷書美少年。',64,'全唐诗/poet.tang.16000.json','["陌頭車馬去翩翩，白面懷書美少年。", "東武楊公姻婭重，西州謝傅舅甥賢。", "長亭叫月新秋雁，官渡含風古樹蟬。", "知己滿朝留不住，貴臣河上擁旌旃。"]'),
('1d65129a-ea27-4ec6-b8ed-8c12ee3d0d0a','秋日書懷','武元衡','唐','唐诗','tang','','[]','金貂玉鉉奉君恩，夜漏晨鐘老掖垣。',64,'全唐诗/poet.tang.16000.json','["金貂玉鉉奉君恩，夜漏晨鐘老掖垣。", "參決萬機空有媿，靜觀羣動亦無言。", "杯中壯志紅顏歇，林下秋聲絳葉翻。", "倦鳥不知歸去日，青蕪白露滿郊園。"]'),
('4c9b4547-74bf-416f-9f05-8f0e73350cf7','南昌灘','武元衡','唐','唐诗','tang','','["\u9ec4\u5c71"]','渠江明淨峽逶迤，船到名灘拽𥮘遲。',64,'全唐诗/poet.tang.16000.json','["渠江明淨峽逶迤，船到名灘拽𥮘遲。", "櫓窡動搖妨作夢，巴童指點笑吟詩。", "畬餘宿麥黃山腹，日背殘花白水湄。", "物色可憐心莫限，此行都是獨行時。"]'),
('c0ec2762-0412-493a-8c83-ed182eb41db0','奉和聖製豐年多慶九日示懷','武元衡','唐','唐诗','tang','','[]','令節寰宇泰，神都佳氣濃。',72,'全唐诗/poet.tang.16000.json','["令節寰宇泰，神都佳氣濃。", "賡歌禹功盛，擊壤堯年豐。", "九奏碧霄裏，千官皇澤中。", "南山澄凝黛，曲水清涵空。", "金玉美王度，歡康謠國風。", "睿文垂日月，永與天無窮。"]'),
('efdc20e0-6f18-4acd-b3d4-a4d6ad7cdbb4','夏日陪馮許二侍郎與嚴祕書遊昊天觀覽舊題寄同里楊華州中丞','武元衡','唐','唐诗','tang','','[]','三伏草木變，九城車馬煩。',72,'全唐诗/poet.tang.16000.json','["三伏草木變，九城車馬煩。", "碧霄迴騎射，丹洞入桃源。", "臺殿雲浮棟，緌纓鶴在軒。", "莫將真破妄，聊用靜持喧。", "石甃古苔冷，水筠涼簟翻。", "黃公壚下歎，旌斾國東門。"]'),
('16a990e0-e926-434c-9150-229f494df28c','奉和聖製重陽日即事','武元衡','唐','唐诗','tang','','[]','玉燭降寒露，我皇歌古風。',72,'全唐诗/poet.tang.16000.json','["玉燭降寒露，我皇歌古風。", "重陽德澤展，萬國歡娛同。", "綺陌擁行騎，香塵凝曉空。", "神都自藹藹，佳氣助葱葱。", "律呂陰陽暢，景光天地通。", "徒然被鴻霈，無以報玄功。"]'),
('7bdd44ad-6a7e-4c17-802a-c88127770ca2','秋日臺中寄懷簡諸僚','武元衡','唐','唐诗','tang','','[]','憲府日多事，秋光照碧林。',96,'全唐诗/poet.tang.16000.json','["憲府日多事，秋光照碧林。", "干雲巖翠合，布石地苔深。", "憂悔耿遐抱，塵埃緇素襟。", "物情牽跼促，友道曠招尋。", "頹節風霜變，流年芳景侵。", "池荷足幽氣，煙竹又繁陰。", "簪組赤墀戀，池魚滄海心。", "滌煩滯幽賞，永度瑤華音。"]'),
('bd5ea081-ba07-43c1-b11e-39afe809736a','奉酬淮南中書相公見寄','武元衡','唐','唐诗','tang','','[]','揚州隋故都，竹使漢名儒。',146,'全唐诗/poet.tang.16000.json','["揚州隋故都，竹使漢名儒。", "翊聖恩華異，持衡節制殊。", "朝廷連受脤，台座接訐謨。", "金玉裁王度，丹書奉帝俞。", "九重辭象魏，千[里]握兵符。", "鐵馬秋臨塞，虹旌夜渡瀘。", "江長梅笛怨，天遠桂輪孤。", "浩歎煙霜曉，芳期蘭蕙蕪。", "雅言書一札，賓海雁東隅。", "歲月奔波盡，音徽霧雨濡。", "蜀江分井絡，錦浪入淮湖。", "獨抱相思恨，關山不可踰。"]'),
('1d91c1f1-898f-43ed-86f5-4442aa7b1332','甫搆西亭偶題因呈監軍及幕中諸公','武元衡','唐','唐诗','tang','','[]','瀛海無因泛，崑丘豈易尋。',120,'全唐诗/poet.tang.16000.json','["瀛海無因泛，崑丘豈易尋。", "數峰聊在目，一境暫清心。", "悅彼松柏性，愛茲桃李陰。", "列芳憑有土，叢幹聚成林。", "信矣子牟戀，歸歟尼父吟。", "暗香蘭露滴，空翠蕙樓深。", "負鼎位嘗忝，荷戈年屢侵。", "百城煩鞅掌，九仞喜嶇嶔。", "巴漢泝沿楫，岷峨千萬岑。", "恩偏不敢去，范蠡畏鎔金。"]'),
('a6bc760d-d420-42bb-981a-177263452906','和楊弘微春日曲江南望','武元衡','唐','唐诗','tang','','[]','遲景靄悠悠，傷春南陌頭。',120,'全唐诗/poet.tang.16000.json','["遲景靄悠悠，傷春南陌頭。", "暄風一澹蕩，遐思幾殷憂。", "龍去空仙沼，鸞飛掩妓樓。", "芳菲餘雨露，冠蓋舊公侯。", "朱戟千門閉，黃鸝百囀愁。", "煙濛宮樹晚，花咽石泉流。", "寒谷律潛應，中林蘭自幽。", "商山將避漢，晉室正藩周。", "黍稷聞興歎，瓊瑤畏見投。", "君心即吾事，微向在滄洲。"]'),
('679f0501-efc8-480c-ae38-3c95b10b9c70','長安秋夜懷陳京昆季','武元衡','唐','唐诗','tang','','[]','鐘鼓九衢絕，出門千里同。',120,'全唐诗/poet.tang.16000.json','["鐘鼓九衢絕，出門千里同。", "遠情高枕夜，秋思北窗空。", "靜見煙凝燭，閑聽葉墜桐。", "玉壺思洞徹，瓊樹憶葱籠。", "螢影疎簾外，鴻聲暗雨中。", "羇愁難會面，嬾慢責微躬。", "甲乙科攀桂，圖書閣踐蓬。", "一瓢非可樂，六翮未因風。", "寥落悲秋盡，蹉跎惜歲窮。", "明朝不相見，流淚菊花叢。"]'),
('8674fa82-1c80-400d-b329-2c6ef1c5fee2','冬日漢江南行將赴夏口途次江陵界寄裴尚書','武元衡','唐','唐诗','tang','','[]','五部擁雙旌，南依墨客卿。',120,'全唐诗/poet.tang.16000.json','["五部擁雙旌，南依墨客卿。", "關山迥梁甸，波浪接湓城。", "煙景迷時候，雲帆渺去程。", "蛤珠馮月吐，蘆雁觸羅驚。", "浦樹凝寒晦，江天湛鏡清。", "賞心隨處愜，壯志逐年輕。", "舟檝不可駐，提封如任情。", "向方曾指路，射策許言兵。", "蘭渚歇芳意，菱歌非應聲。", "元戎武昌守，羊祜幸連營。"]'),
('2e9ade9a-2235-4368-9bc2-c8435380a20e','奉酬中書李相公早朝於中書候傳點偶書所懷','武元衡','唐','唐诗','tang','','[]','寥落曙鍾斷，微明煙月沈。',120,'全唐诗/poet.tang.16000.json','["寥落曙鍾斷，微明煙月沈。", "翠霞仙仗合，清漏掖垣深。", "北極星遙拱，南山闕迥臨。", "蘭釭竟曉燄，琪樹欲秋陰。", "霄漢慙聯步，貂蟬媿並簪。", "德容溫比玉，王度式如金。", "魚水千里運，簫韶九奏音。", "代天驚度日，擲地喜開襟。", "文武時方泰，唐虞道可尋。", "忝陪申及甫，清淨奉堯心。"]'),
('1bf75e10-ba3d-40d6-935c-890040648101','甲午歲相國李公有北園寄贈之作吟翫歷時屢促酬答機務不暇未及報章今古遽分電波增感留墓劒而心許感鄰笛而意傷寓哀冥寞以廣遺韻云','武元衡','唐','唐诗','tang','','[]','機事勞西掖，幽懷寄北園。',96,'全唐诗/poet.tang.16000.json','["機事勞西掖，幽懷寄北園。", "鶴巢深更靜，蟬噪斷猶喧。", "仙醞百花馥，豔歌雙袖翻。", "碧雲詩變雅，皇澤葉流根。", "未報雕龍贈，俄傷淚劒痕。", "佳城關白日，哀挽向青門。", "禮命公台重，煙霜隴樹繁。", "天高不可問，空使輔星昏。"]'),
('fe65064b-17cb-4690-b640-903a94145fa9','和楊三舍人晚秋與崔二舍人張祕監苗考功同遊昊天觀時中書寓直不得陪隨因追往年曾與舊僚聯遊此觀紀題在壁已有淪亡書事感懷輙以呈寄兼呈東省三給事之作楊君見徴鄙詞因以繼和','武元衡','唐','唐诗','tang','','[]','瑤圃高秋會，金閨奉詔辰。',96,'全唐诗/poet.tang.16000.json','["瑤圃高秋會，金閨奉詔辰。", "朱輪天上客，白石洞中人。", "珮響泉聲雜，朝衣羽服親。", "九重青瑣閉，三秀紫芝新。", "化藥秦方士，偷桃漢侍臣。", "玉笙王子駕，遼鶴令威身。", "歎逝頹波速，緘詞麗曲春。", "重將悽恨意，苔壁問遺塵。"]'),
('8be65627-6edb-4233-8cc5-cc61311253aa','酬李十一尚書西亭暇日書懷見寄十二韻之作','武元衡','唐','唐诗','tang','','[]','鼎鉉昔云忝，西南分主憂。',144,'全唐诗/poet.tang.16000.json','["鼎鉉昔云忝，西南分主憂。", "煙塵開僰道，旌節護蠻陬。", "任重功無立，力微恩未酬。", "據鞍慙齒髮，責帥懼春秋。", "高德聞鄭履，儉居稱晏裘。", "三刀君入夢，九折我回輈。", "時景屢遷易，茲言期退休。", "方追故山事，豈謂台堦留。", "遐抱清淨理，眷言蘭杜幽。", "一緘瓊玖贈，萬里別離愁。", "巴嶺雲外沒，蜀江天際流。", "懷賢耿遙思，相望鳳池頭。"]'),
('e7e92d31-202f-4ab2-9cf3-fdfc4176541b','秋懷奉寄朱補闕','武元衡','唐','唐诗','tang','','[]','上苑繁霜降，騷人起恨初。',72,'全唐诗/poet.tang.16000.json','["上苑繁霜降，騷人起恨初。", "白雲深陋巷，衰草遍閑居。", "暮色秋煙重，寒聲牖葉虛。", "潘生秋思苦，陶令世情疎。", "已製歸田賦，猶陳諫獵書。", "不知青瑣客，投分竟何如。"]'),
('8a77fedb-d9b8-417a-9d70-26c41f0adc68','奉酬中書相公至日圜丘行事合於中書宿齋移止於集賢院敘情見寄之什','武元衡','唐','唐诗','tang','','[]','郊廟祗嚴祀，齋莊覿上玄。',72,'全唐诗/poet.tang.16000.json','["郊廟祗嚴祀，齋莊覿上玄。", "別開金虎觀，不離紫微天。", "樹古長楊接，池清太液連。", "仲山方補衮，文舉自傷年。", "風溢銅壺漏，香凝綺閣煙。", "仍聞白雪唱，流詠滿鵾弦。"]'),
('7b6164d7-7d64-4f68-9f6b-138d67ebb18f','途次','武元衡','唐','唐诗','tang','','[]','去國策羸馬，勞歌行路難。',72,'全唐诗/poet.tang.16000.json','["去國策羸馬，勞歌行路難。", "地崇秦制險，人樂漢恩寬。", "御沼澄泉碧，宮梨拂露丹。", "鼎成仙馭遠，龍化宿雲殘。", "不問三苗寵，誰陪萬國歡。", "至今松桂色，長助玉樓寒。"]'),
('3a768c8d-8fc9-4267-8893-7a6973f092e1','題故蔡國公主九華觀上池院','武元衡','唐','唐诗','tang','','[]','朱門臨九衢，雲木藹仙居。',72,'全唐诗/poet.tang.16000.json','["朱門臨九衢，雲木藹仙居。", "曲沼天波接，層臺鳳舞餘。", "曙煙深碧篠，香露濕紅蕖。", "瑤瑟含風韻，紗窗積翠虛。", "秦樓今寂寞，真界竟何如。", "不與蓬瀛異，迢迢遠玉除。"]'),
('362a7588-6f4e-41f5-bf4e-787b98cb0f18','酬嚴維秋夜見寄','武元衡','唐','唐诗','tang','','[]','遙夜思悠悠，聞鐘遠夢休。',96,'全唐诗/poet.tang.16000.json','["遙夜思悠悠，聞鐘遠夢休。", "亂林螢燭暗，零露竹風秋。", "啓戶雲歸棟，褰簾月上鉤。", "昭明逢聖代，羈旅別滄洲。", "騎省潘郎思，衡闈宋玉愁。", "神仙慙李郭，詞賦謝曹劉。", "松柏應無變，瓊瑤不可酬。", "誰堪此時景，寂寞下高樓。"]'),
('685aaf3f-2a67-44f6-b2c7-278457aa960d','途次近蜀驛蒙恩賜寶刀及飛龍廏馬使還奉寄中書李鄭二公','武元衡','唐','唐诗','tang','','[]','草草事行役，遲遲違故關。',72,'全唐诗/poet.tang.16000.json','["草草事行役，遲遲違故關。", "碧幃遙隱霧，紅斾漸依山。", "感激酬恩淚，星霜去國顏。", "捧刀金錫字，歸馬玉連環。", "威鳳翔雙闕，征夫縱百蠻。", "應憐宣室召，溫樹不同攀。"]'),
('2f1175f4-16cc-4a34-acda-983fcb2021d9','歸燕','武元衡','唐','唐诗','tang','','[]','春色遍芳菲，閑簷雙燕歸。',72,'全唐诗/poet.tang.16000.json','["春色遍芳菲，閑簷雙燕歸。", "還同舊侶至，來遶故巢飛。", "敢望煙霄達，多慙羽翮微。", "銜泥傍金砌，拾蘂到荆扉。", "雲海經時別，雕梁長日依。", "主人能一顧，轉盻自光輝。"]'),
('c5aeeb83-14fb-4498-b270-42593d2ae1ca','送許著作分司東都','武元衡','唐','唐诗','tang','','[]','瑤瑟激悽響，征鴻翻夕陽。',60,'全唐诗/poet.tang.16000.json','["瑤瑟激悽響，征鴻翻夕陽。", "署分刊竹簡，書蠹護芸香。", "馬色關城曉，蟬聲驛路長。", "石渠榮正禮，蘭室重元方。", "不作經年別，離魂亦暫傷。"]'),
('81dd66ce-a15f-47fb-83bd-dde434d551db','聞相公三兄小園置宴以元衡寓直因寄上兼呈中書三兄','武元衡','唐','唐诗','tang','','[]','休沐限中禁，家山傳勝遊。',72,'全唐诗/poet.tang.16000.json','["休沐限中禁，家山傳勝遊。", "露寒潘省夜，木落庾園秋。", "蘭菊迴幽步，壺觴洽舊儔。", "位高天祿閣，詞異畔牢愁。", "孤思琴先覺，馳暉水競流。", "明朝不相見，清祀在圜丘。"]'),
('7ff2ebbc-b1c0-4661-89c6-b022af75a633','酬陸員外歙州許員外郢州二使君','武元衡','唐','唐诗','tang','','[]','吳洲雲海接，楚驛夢林長。',72,'全唐诗/poet.tang.16000.json','["吳洲雲海接，楚驛夢林長。", "符節分憂重，鵷鴻去路翔。", "豔歌愁翠黛，寶瑟韻清商。", "洲草遙池合，春風曉斾張。", "晉臣多樂廣，漢主識馮唐。", "不作經年別，離魂亦未傷。"]'),
('26f3e892-a633-4286-a597-0eb6707607c8','漸至涪州先寄王使君','武元衡','唐','唐诗','tang','','[]','治敎通夷俗，均輸問大田。',72,'全唐诗/poet.tang.16000.json','["治敎通夷俗，均輸問大田。", "江分巴字水，樹入夜郎煙。", "毒霧含秋氣，陰巖蔽曙天。", "路難空計日，身老不由年。", "將命寧知遠，歸心詎可傳。", "星郎復何事，出守五溪邊。"]'),
('b323c71f-ed8e-49cd-8baf-42089fa17706','石州城','武元衡','唐','唐诗','tang','','[]','丈夫心愛橫行，報國知嫌命輕。',50,'全唐诗/poet.tang.16000.json','["丈夫心愛橫行，報國知嫌命輕。", "樓蘭徑百戰，更道戍龍城。", "錦字竇車騎，胡笳李少卿。", "生離兩不見，萬古難爲情。"]'),
('a8ddf0f5-ccbc-4e18-ab1e-fa3f78b70b52','寒食下第','武元衡','唐','唐诗','tang','','[]','柳挂九衢絲，花飄萬家雪。',24,'全唐诗/poet.tang.16000.json','["柳挂九衢絲，花飄萬家雪。", "如何憔悴人，對此芳菲節。"]'),
('6f502cd6-45ad-40ad-be9e-008ecaf3b5ee','途中即事','武元衡','唐','唐诗','tang','','[]','南征復北還，擾擾百年間。',24,'全唐诗/poet.tang.16000.json','["南征復北還，擾擾百年間。", "自笑紅塵裏，生涯不暫閑。"]'),
('bfec44d3-f3cc-448c-ac00-14a74136052a','春日偶作','武元衡','唐','唐诗','tang','','[]','縱橫桃李枝，淡蕩春風吹。',24,'全唐诗/poet.tang.16000.json','["縱橫桃李枝，淡蕩春風吹。", "美人歌白苧，萬恨在蛾眉。"]'),
('adbb2adc-c1a8-46e8-bae3-8e1560d723d6','夏夜作','武元衡','唐','唐诗','tang','','[]','夜久喧暫息，池臺惟月明。',24,'全唐诗/poet.tang.16000.json','["夜久喧暫息，池臺惟月明。", "無因駐清景，日出事還生。"]'),
('27b07714-e121-47ce-8c42-5517591d40fc','左掖梨花','武元衡','唐','唐诗','tang','','[]','巧笑解迎人，晴雪香堪惜。',24,'全唐诗/poet.tang.16000.json','["巧笑解迎人，晴雪香堪惜。", "隨風蝶影翻，誤點朝衣赤。"]'),
('d70d3707-c751-4237-9b57-6f0e897d6c4d','同陳六侍御寒食遊禪定藏山上人院','武元衡','唐','唐诗','tang','','[]','年少輕行樂，東城南陌頭。',24,'全唐诗/poet.tang.16000.json','["年少輕行樂，東城南陌頭。", "與君寂寞意，共作草堂遊。"]'),
('12b3652c-fcf4-4109-9fa0-3318b6aa26fb','贈佳人','武元衡','唐','唐诗','tang','','[]','步搖金翠玉搔頭，傾國傾城勝莫愁。',32,'全唐诗/poet.tang.17000.json','["步搖金翠玉搔頭，傾國傾城勝莫愁。", "若逞仙姿遊洛浦，定知神女謝風流。"]'),
('1b314252-f4df-4c66-aeb1-545a3950294d','休暇日中書相公致齋禁省因以寄贈','武元衡','唐','唐诗','tang','','[]','嘗聞聖主得賢臣，三接能令四海春。',32,'全唐诗/poet.tang.17000.json','["嘗聞聖主得賢臣，三接能令四海春。", "月滿禁垣齋沐夜，清吟屬和更何人。"]'),
('9f088449-9e08-4505-ac55-379919d5f89d','春興','武元衡','唐','唐诗','tang','','["\u6625\u5929", "\u601d\u4e61"]','楊柳陰陰細雨晴，殘花落盡見流鶯。',32,'全唐诗/poet.tang.17000.json','["楊柳陰陰細雨晴，殘花落盡見流鶯。", "春風一枝吹香夢，夢逐春風到洛城。"]'),
('e021303d-f151-47aa-a459-2c7237b84037','酬裴起居西亭留題','武元衡','唐','唐诗','tang','','[]','豔歌能起關山恨，紅燭偏凝寒塞情。',32,'全唐诗/poet.tang.17000.json','["豔歌能起關山恨，紅燭偏凝寒塞情。", "況是池塘風雨夜，不堪絲管盡離聲。"]'),
('780d5e37-4d28-4b8e-bf85-416afe322d0e','送張侍御赴京','武元衡','唐','唐诗','tang','','[]','江南煙雨塞鴻飛，西府文章謝掾歸。',32,'全唐诗/poet.tang.17000.json','["江南煙雨塞鴻飛，西府文章謝掾歸。", "相送汀州蘭棹晚，菱歌一曲淚霑衣。"]'),
('16d39ffc-d7f3-4bf3-b94a-cef47b6cf26c','鄂渚送友','武元衡','唐','唐诗','tang','','[]','雲帆淼淼巴陵渡，煙樹蒼蒼故郢城。',32,'全唐诗/poet.tang.17000.json','["雲帆淼淼巴陵渡，煙樹蒼蒼故郢城。", "江上梅花無數落，送君南浦不勝情。"]'),
('5e77fae8-1435-4119-abd0-a25d4091acce','送裴戡行軍','武元衡','唐','唐诗','tang','','[]','珠履三千醉不歡，玉人猶苦夜冰寒。',32,'全唐诗/poet.tang.17000.json','["珠履三千醉不歡，玉人猶苦夜冰寒。", "送君偏有無言淚，天下關山行路難。"]'),
