('c0608acf-1273-4b33-a4ef-75432cbc542f','學仙難','武元衡','唐','唐诗','tang','','[]','玉殿笙歌漢帝愁，鸞龍儼駕望瀛洲。',32,'全唐诗/poet.tang.17000.json','["玉殿笙歌漢帝愁，鸞龍儼駕望瀛洲。", "黃金化盡方士死，青天欲上無緣由。"]'),
('68a0ab81-87c5-4af5-a27a-9c6032f35b21','唐昌觀玉蘂花','武元衡','唐','唐诗','tang','','[]','琪樹芊芊玉蘂新，洞宮長閉綵霞春。',32,'全唐诗/poet.tang.17000.json','["琪樹芊芊玉蘂新，洞宮長閉綵霞春。", "日暮落英鋪地雪，獻花應過九天人。"]'),
('d7b2cf6c-d8c3-4e6f-99e0-9fa24dc3a111','春曉聞鶯','武元衡','唐','唐诗','tang','','[]','寥寥蘭臺曉夢驚，綠林殘月思孤鶯。',32,'全唐诗/poet.tang.17000.json','["寥寥蘭臺曉夢驚，綠林殘月思孤鶯。", "猶疑蜀魄千年恨，化作寃禽萬囀聲。"]'),
('0d2b82b1-d43a-490c-aaca-cda5b53f87e3','聞嚴祕書與正字及諸客夜會因寄','武元衡','唐','唐诗','tang','','[]','衡門寥落歲陰窮，露濕莓苔葉厭風。',32,'全唐诗/poet.tang.17000.json','["衡門寥落歲陰窮，露濕莓苔葉厭風。", "聞道今宵阮家會，竹林明月七人同。"]'),
('2d20674e-0477-4f34-b9c0-5e0035b0de1a','戲贈韓二秀才','武元衡','唐','唐诗','tang','','[]','名高折桂方年少，心苦爲文命未通。',32,'全唐诗/poet.tang.17000.json','["名高折桂方年少，心苦爲文命未通。", "聞說東堂今有待，飛鳴何處及春風。"]'),
('d44dcb5d-8d29-4df0-8df3-7ede18b32157','聞王仲周所居牡丹花發因戲贈','武元衡','唐','唐诗','tang','','[]','聞說庭花發暮春，長安才子看須頻。',32,'全唐诗/poet.tang.17000.json','["聞說庭花發暮春，長安才子看須頻。", "花開花落無人見，借問何人是主人。"]'),
('396222af-6881-4647-8a15-89bc112edccf','酬王十八見招','武元衡','唐','唐诗','tang','','[]','王昌家直在城東，落盡庭花昨夜風。',32,'全唐诗/poet.tang.17000.json','["王昌家直在城東，落盡庭花昨夜風。", "高興不辭千日醉，隨君走馬向新豐。"]'),
('8a707722-b597-4d05-ab3b-b8b417a6607a','贈道者','武元衡','唐','唐诗','tang','','[]','麻衣如雪一枝梅，笑掩微妝入夢來。',32,'全唐诗/poet.tang.17000.json','["麻衣如雪一枝梅，笑掩微妝入夢來。", "若到越溪逢越女，紅蓮池裏白蓮開。"]'),
('50ec944a-86b4-4da6-9044-11805b384ebd','重送白將軍','武元衡','唐','唐诗','tang','','[]','紅燭芳筵惜夜分，歌樓管咽思難聞。',32,'全唐诗/poet.tang.17000.json','["紅燭芳筵惜夜分，歌樓管咽思難聞。", "早知怨別人間世，不下青山老白雲。"]'),
('9113a4ff-cf7f-43d4-b9e0-3afcd64ae623','和李丞題李將軍林園','武元衡','唐','唐诗','tang','','[]','落英飄蘂雪紛紛，啼鳥如悲霍冠軍。',32,'全唐诗/poet.tang.17000.json','["落英飄蘂雪紛紛，啼鳥如悲霍冠軍。", "逝水不迴弦管絕，玉樓迢遰鎖浮雲。"]'),
('2dcc415e-5b0e-4fc1-9ed5-2138a36a0859','同張惟送霍總','武元衡','唐','唐诗','tang','','[]','春風簫管怨津樓，三奏行人醉不留。',32,'全唐诗/poet.tang.17000.json','["春風簫管怨津樓，三奏行人醉不留。", "別後相思江上岸，落花飛處杜鵑愁。"]'),
('e303e0c4-2c11-4a79-aa5e-42c35340f111','贈別崔起居','武元衡','唐','唐诗','tang','','[]','三十年前會府同，紅顏銷盡兩成翁。',32,'全唐诗/poet.tang.17000.json','["三十年前會府同，紅顏銷盡兩成翁。", "別淚共將何處灑，錦江南渡足春風。"]'),
('0383d7f2-5f68-4f59-b0b6-9bc78141ac8d','春日偶題','武元衡','唐','唐诗','tang','','[]','山川百戰古刀州，龍節來分聖主憂。',32,'全唐诗/poet.tang.17000.json','["山川百戰古刀州，龍節來分聖主憂。", "靜守化條無一事，春風獨上望京樓。"]'),
('3f9b8c66-73e1-4e8e-bf47-b86227d04865','聽歌','武元衡','唐','唐诗','tang','','[]','月上重樓絲管秋，佳人夜唱古梁州。',32,'全唐诗/poet.tang.17000.json','["月上重樓絲管秋，佳人夜唱古梁州。", "滿堂誰是知音者，不惜千金與莫愁。"]'),
('c8f03f75-1b1a-4b4c-89d8-838c23527d7d','酬韋胄曹','武元衡','唐','唐诗','tang','','[]','相逢異縣蹉跎意，無復少年容易歡。',32,'全唐诗/poet.tang.17000.json','["相逢異縣蹉跎意，無復少年容易歡。", "桃李美人攀折盡，何如松柏四時寒。"]'),
('ae6fed07-a7f9-4283-b5c8-1d330730630f','同幕府夜宴惜花','武元衡','唐','唐诗','tang','','[]','芳草落花明月榭，朝雲暮雨錦城春。',32,'全唐诗/poet.tang.17000.json','["芳草落花明月榭，朝雲暮雨錦城春。", "莫愁紅豔風前散，自有青蛾鏡裏人。"]'),
('36140ae0-9376-4462-bdcf-89497be3482e','代佳人贈張郎中','武元衡','唐','唐诗','tang','','[]','洛陽佳麗本神仙，冰雪顏容桃李年。',32,'全唐诗/poet.tang.17000.json','["洛陽佳麗本神仙，冰雪顏容桃李年。", "心愛阮郎留不住，獨將珠淚濕紅鉛。"]'),
('3276545b-c16b-4f60-a05a-890a32a2f989','餞裴行軍赴朝命','武元衡','唐','唐诗','tang','','[]','來時聖主假光輝，心恃朝恩計日歸。',32,'全唐诗/poet.tang.17000.json','["來時聖主假光輝，心恃朝恩計日歸。", "誰料忽成雲雨別，獨將邊淚灑戎衣。"]'),
('599f85c6-76cb-4af5-bc51-67b9c36b2ab4','秋日經潼關感寓','武元衡','唐','唐诗','tang','','[]','昔年曾逐漢征東，三授兵符百戰中。',32,'全唐诗/poet.tang.17000.json','["昔年曾逐漢征東，三授兵符百戰中。", "力保山河嗟下世，秋風牢落故營空。"]'),
('e2fe3516-46f7-4dfd-a920-81ea1183946c','贈歌人','武元衡','唐','唐诗','tang','','[]','仙歌靜轉玉簫催，疑是流鶯禁苑來。',32,'全唐诗/poet.tang.17000.json','["仙歌靜轉玉簫催，疑是流鶯禁苑來。", "他日相思夢巫峽，莫敎雲雨晦陽臺。"]'),
('0f4b11ce-41f7-4601-bf8c-8b71fdffbd85','見郭侍郎題壁','武元衡','唐','唐诗','tang','','[]','萬里楓江偶問程，青苔壁上故人名。',32,'全唐诗/poet.tang.17000.json','["萬里楓江偶問程，青苔壁上故人名。", "悠悠身世限南北，一別十年空復情。"]'),
('44ed1bc9-3783-42a6-bc48-82485dbb977f','癸巳歲吉甫圜丘攝事合於中書後閣宿齋常負忝媿移止於集賢院會門下相公以七言垂寄亦有所酬短章絕韻不足抒意因敘所懷奉寄相公兼呈集賢院諸學士','李吉甫','唐','唐诗','tang','','[]','淮海同三入，樞衡過六年。',72,'全唐诗/poet.tang.17000.json','["淮海同三入，樞衡過六年。", "廟齋兢永夕，書府會羣仙。", "粉壁連霜曙，冰池對月圓。", "歲時憂裏換，鐘漏靜中傳。", "蓬髮顏空老，松心契獨全。", "贈言因傅說，垂訓在三篇。"]'),
('2ed7ffff-815f-4eb6-a6c6-889e3c0f5726','夏夜北園即事寄門下武相公','李吉甫','唐','唐诗','tang','','[]','結構非華宇，登臨似古原。',72,'全唐诗/poet.tang.17000.json','["結構非華宇，登臨似古原。", "僻殊蕭相宅，蕪勝邵平園。", "避暑依南廡，追涼在北軒。", "煙霞霄外靜，草露月中繁。", "鵲繞驚還止，蟲吟思不喧。", "懷君欲有贈，宿昔貴忘言。"]'),
('fe5c016a-8068-4c6c-884c-673000384992','九日小園獨謠贈門下武相公','李吉甫','唐','唐诗','tang','','[]','小園休沐暇，暫與故山期。',72,'全唐诗/poet.tang.17000.json','["小園休沐暇，暫與故山期。", "樹杪懸丹棗，苔陰落紫梨。", "舞叢新菊徧，繞格古藤垂。", "受露紅蘭晚，迎霜白薤肥。", "上公留鳳沼，冠劒侍清祠。", "應念端居者，長慙補衮詩。"]'),
('7fdc955d-2299-4c7f-b87a-70debfcda2cf','懷伊川賦','李吉甫','唐','唐诗','tang','','[]','龍門南岳盡伊原，草樹人煙目所存。',32,'全唐诗/poet.tang.17000.json','["龍門南岳盡伊原，草樹人煙目所存。", "正是北州梨棗熟，夢魂秋日到郊園。"]'),
('8e108a00-ae84-4160-8ff3-5248a1e5613d','奉和武相公省中宿齋酬李相公見寄','鄭絪','唐','唐诗','tang','','[]','高閣安仁省，名園廣武廬。',72,'全唐诗/poet.tang.17000.json','["高閣安仁省，名園廣武廬。", "沐蘭朝太一，種竹詠華胥。", "禁靜疎鐘徹，庭開爽韻虛。", "洪鈞齊萬物，縹帙整羣書。", "寒露滋新菊，秋風落故蕖。", "同懷不同賞，幽意竟何如。"]'),
('09b66e08-96ee-4d27-ad2f-0df7aab9bff8','寒夜聞霜鐘','鄭絪','唐','唐诗','tang','','[]','霜鐘初應律，寂寂出重林。',72,'全唐诗/poet.tang.17000.json','["霜鐘初應律，寂寂出重林。", "拂水宜清聽，凌空散逈音。", "舂容時未歇，搖曳夜方深。", "月下和虛籟，風前間遠砧。", "淨兼寒漏徹，閑畏曙更侵。", "遙想千山外，泠泠何處尋。"]'),
('065ec845-0d17-47f0-92ff-9b433fa200d7','奉酬宣上人九月十五日東亭望月見贈因懷紫閣舊遊','鄭絪','唐','唐诗','tang','','[]','中年偶逐鴛鸞侶，弱歲多從麋鹿羣。',64,'全唐诗/poet.tang.17000.json','["中年偶逐鴛鸞侶，弱歲多從麋鹿羣。", "紫閣道流今不見，紅樓禪客早曾聞。", "松齋月朗星初散，苔砌霜繁夜欲分。", "一覽綵牋佳句滿，何人更詠惠休文。"]'),
('f7973e61-9631-48b9-853d-839a9b51da9c','九日登高懷邵二','鄭絪','唐','唐诗','tang','','[]','簪茱泛菊俯平阡，飲過三杯却惘然。',32,'全唐诗/poet.tang.17000.json','["簪茱泛菊俯平阡，飲過三杯却惘然。", "十歲此辰同醉友，登高各處已三年。"]'),
('f4c9fd5b-7d00-4a57-9799-f255cf4c34ea','享太廟樂章','鄭絪','唐','唐诗','tang','','[]','於穆時文，受天明命。',40,'全唐诗/poet.tang.17000.json','["於穆時文，受天明命。", "允恭玄默，化成理定。", "出震嗣德，應乾傳聖。", "猗歟緝熙，千億流慶。"]'),
('1f99ba34-200a-466e-85e8-db551714528c','句','鄭絪','唐','唐诗','tang','','[]','情人共惆悵，良友不同遊。',12,'全唐诗/poet.tang.17000.json','["情人共惆悵，良友不同遊。"]'),
('48c02ec1-d54a-4a91-8e03-e7e37e7c02d8','和黃門相公詔還題石門洞','鄭餘慶','唐','唐诗','tang','','[]','紫氛隨馬處，黃閣駐車情。',48,'全唐诗/poet.tang.17000.json','["紫氛隨馬處，黃閣駐車情。", "嵌壑驚山勢，周灘戀水聲。", "地分三蜀限，關志百牢名。", "琬琰攀酬郢，微言鼎飪情。"]'),
('59d4fa99-b2bd-4cfa-88a7-3e43888a9173','享太廟樂章','鄭餘慶','唐','唐诗','tang','','[]','開邸除暴，時邁勛尊。',40,'全唐诗/poet.tang.17000.json','["開邸除暴，時邁勛尊。", "三元告命，四極駿奔。", "金枝翠葉，輝燭瑤琨。", "象德億載，貽慶湯孫。"]'),
('84c837f5-7ccb-4252-8592-d509e7792ced','和黃門武相公詔還題石門洞','趙宗儒','唐','唐诗','tang','','[]','益部恩輝降，同榮漢相還。',48,'全唐诗/poet.tang.17000.json','["益部恩輝降，同榮漢相還。", "韶芳滿歸路，軒騎出重關。", "望日朝天闕，披雲過蜀山。", "更題風雅韻，永絕翠嵓間。"]'),
('672a206d-370a-4d5a-ad33-fe74689475ba','和武相公錦樓翫月得濃字','柳公綽','唐','唐诗','tang','','[]','此夜年年月，偏宜此地逢。',48,'全唐诗/poet.tang.17000.json','["此夜年年月，偏宜此地逢。", "近看江水淺，遙辨雪山重。", "萬井金花肅，千林玉露濃。", "不唯樓上思，飛蓋亦陪從。"]'),
('88cfcd1d-7f8b-48ce-bd8a-f8b24f96b06c','題梓州牛頭寺','柳公綽','唐','唐诗','tang','','[]','一出西城第二橋，兩邊山木晚蕭蕭。',32,'全唐诗/poet.tang.17000.json','["一出西城第二橋，兩邊山木晚蕭蕭。", "井花淨洗行人耳，留聽溪聲入夜潮。"]'),
('33aca5e5-8e74-4ba9-8ba1-cc083d6f93f5','贈毛仙翁','柳公綽','唐','唐诗','tang','','[]','桃源千里遠，花洞四時春。',48,'全唐诗/poet.tang.17000.json','["桃源千里遠，花洞四時春。", "中有含真客，長爲不死人。", "松高枝葉茂，鶴老羽毛新。", "莫遣同籬槿，朝榮暮化塵。"]'),
('1b9d00c7-3128-4bee-b338-2d354d51c002','和武相公中秋錦樓翫月得蒼字','張正一','唐','唐诗','tang','','[]','高秋今夜月，皓色正蒼蒼。',48,'全唐诗/poet.tang.17000.json','["高秋今夜月，皓色正蒼蒼。", "遠水澄如練，孤鴻逈帶霜。", "旅人方積思，繁宿稍沈光。", "朱檻叨陪賞，尤宜清漏長。"]'),
('d1647555-1944-4bdb-9515-7ab825db789b','奉和武相公中秋錦樓翫月得來字','徐放','唐','唐诗','tang','','[]','玉露中秋夜，金波碧落開。',48,'全唐诗/poet.tang.17000.json','["玉露中秋夜，金波碧落開。", "鵲驚初泛濫，鴻思共裴回。", "遠月清光徧，高空爽氣來。", "此時陪永望，更得上燕臺。"]'),
('26812d7f-e7f0-4936-be69-3dc2cf0bc0c8','和武相公中秋錦樓翫月 一','崔備','唐','唐诗','tang','','[]','清景同千里，寒光盡一年。',48,'全唐诗/poet.tang.17000.json','["清景同千里，寒光盡一年。", "竟天多鴈過，通夕少人眠。", "照別江樓上，添愁野帳前。", "隋侯恩未報，猶有夜珠圓。"]'),
('80e7683d-5fdb-4cb6-96a0-c6fe3caac9fd','和武相公中秋錦樓翫月 二','崔備','唐','唐诗','tang','','[]','四時皆有月，一夜獨當秋。',48,'全唐诗/poet.tang.17000.json','["四時皆有月，一夜獨當秋。", "照耀初含露，裴回正滿樓。", "遙連雪山淨，逈入錦江流。", "願以清光末，年年許從遊。"]'),
('ded1278e-fc9c-4144-a9b8-909dedc80ed1','奉陪武相公西亭夜宴陸郎中','崔備','唐','唐诗','tang','','[]','賓閣玳筵開，通宵遞玉杯。',48,'全唐诗/poet.tang.17000.json','["賓閣玳筵開，通宵遞玉杯。", "塵隨歌扇起，雪逐舞衣迴。", "剪燭清光發，添香煖氣來。", "令君敦宿好，更爲一裴回。"]'),
('7f96292d-2984-443f-bf6e-bf8d9a0bca98','清溪路中寄諸公','崔備','唐','唐诗','tang','','[]','偏郡隔雲岑，迴溪路更深。',48,'全唐诗/poet.tang.17000.json','["偏郡隔雲岑，迴溪路更深。", "少留攀桂樹，長渴望梅林。", "野筍資公膳，山花慰客心。", "別來無信息，可謂井瓶沈。"]'),
('7535fc40-4a58-4d17-8a62-49ec015d16e5','奉酬中書相公至日圜丘行事合於中書宿直移止於集賢院敘情見寄之什','崔備','唐','唐诗','tang','','[]','典籍開書府，恩榮避鼎司。',72,'全唐诗/poet.tang.17000.json','["典籍開書府，恩榮避鼎司。", "郊丘資有事，齋戒守無爲。", "宿霧蒙瓊樹，餘香覆玉墀。", "進經逢乙夜，展禮值明時。", "勳共山河列，名同竹帛垂。", "年年佐堯舜，相與致雍熙。"]'),
('69326a4a-873d-48a0-aa55-4b0100b4dbe9','使院憶山中道侶兼懷李約','崔備','唐','唐诗','tang','','[]','松竹去名嶽，衡茅思舊居。',96,'全唐诗/poet.tang.17000.json','["松竹去名嶽，衡茅思舊居。", "山君水上印，天女月中書。", "舊秩芸香在，空匳藥氣餘。", "褐衣寬易攬，白髮少難梳。", "病柳傷摧折，殘花惜掃除。", "憶巢同倦鳥，避網甚跳魚。", "阮巷慚交絕，商嵓愧跡疎。", "與君非宦侶，何日共樵漁。"]'),
('81b16cce-4a73-4c69-9ce0-2064143e3f13','奉陪武相公西亭夜[宴]陸郎中','蕭祜','唐','唐诗','tang','','[]','弘閣陳芳宴，佳賓此會難。',48,'全唐诗/poet.tang.17000.json','["弘閣陳芳宴，佳賓此會難。", "交逢貴日重，醉得少時歡。", "舒黛凝歌思，求音足筆端。", "一聞清佩動，珠玉夜珊珊。"]'),
('7c0b2801-38db-4c5a-95c1-9a8f1a65a1b9','遊石堂觀','蕭祜','唐','唐诗','tang','','[]','西山高高何所如，上有古昔真人居。',386,'全唐诗/poet.tang.17000.json','["西山高高何所如，上有古昔真人居。", "嶔崖巨石自成室，其下磅礴含清虛。", "我來斯邑訪遺迹，乃遇沈生躭載籍。", "沈生爲政哀惸[嫠]，又能索隱探靈奇。", "欣然向我話佳境，與我崎嶇到山頂。", "甘瓜剖綠出寒泉，碧甌浮花酌春茗。", "嚼瓜啜茗身清涼，汗消絺綌如迎霜。", "胡爲空山百草花，倏爾籩豆肆我旁。", "始驚知周無小大，力寡多方驗斯在。", "妙用騰聲冠蓋間，勝遊恣意煙霞外。", "故碑石像凡幾年，雲鬱雨霏生綠煙。", "我知遊此多靈仙，縹緲月中飛下天。", "天風微微夕露委，松梢颼颼曉聲起。", "鳳去空遺簫管音，星翻寥落銀河水。", "勸君學道此時來，結茅獨宿何遼哉。", "齋心玄默感靈衛，必見鸞鶴相裴回。", "我愛崇山雙劒北，峰如人首拄天黑。", "羣仙傴僂勢奔走，壯若歸尊趨有德。", "半巖有洞頂有池，出入靈怪潛蛟螭。", "我去不得晝夜思，夢遊曾信南風吹。", "南風吹我到林嶺，故國不見秦天逈。", "山花名藥撲地香，月色泉聲洞心冷。", "蔭松散髮逢異人，寂寞曠然口不言。", "道陵公遠莫能識，髮短耳長誰獨存。"]'),
('2e1dec45-4d55-43be-a12d-fe17aeee05b8','奉陪武相公西亭夜宴陸郎中','王良士','唐','唐诗','tang','','[]','芳氣襲猗蘭，青雲展舊歡。',48,'全唐诗/poet.tang.17000.json','["芳氣襲猗蘭，青雲展舊歡。", "仙來紅燭下，花發綵毫端。", "海嶽期方遠，松筠歲正寒。", "仍聞言贈處，一字重琅玕。"]'),
('62e9f763-eff2-4c64-bfcf-e343f318082c','南至日隔霜仗望含元殿爐煙','王良士','唐','唐诗','tang','','[]','抗殿疏龍首，高高接上玄。',72,'全唐诗/poet.tang.17000.json','["抗殿疏龍首，高高接上玄。", "節當南至日，星是北辰天。", "寶戟羅仙仗，金爐引御煙。", "霏微雙闕麗，容曳九門連。", "拂曙祥光滿，分晴瑞色鮮。", "一陽今在曆，生植仰陶甄。"]'),
('2d340e52-7750-4d46-a3d8-cc0afcdeead2','奉陪武相公西亭夜宴陸郎中','獨孤實','唐','唐诗','tang','','[]','仙郎膺上才，夜宴接三台。',48,'全唐诗/poet.tang.17000.json','["仙郎膺上才，夜宴接三台。", "燭引銀河轉，花連錦帳開。", "靜看歌扇舉，不覺舞腰回。", "寥落東方曙，無辭盡玉杯。"]'),
('0d37fc42-ae4e-40c3-930a-e1f645a78493','奉陪武相公西亭夜宴陸郎中','盧士政','唐','唐诗','tang','','[]','華堂良宴開，星使自天來。',48,'全唐诗/poet.tang.17000.json','["華堂良宴開，星使自天來。", "舞轉朱絲逐，歌餘素扇回。", "水光凌曲檻，夜色靄高臺。", "不在賓階末，何由接上台。"]'),
('0eb43102-8924-4e6d-a2f8-7304c15df2df','聞鶯','于敖','唐','唐诗','tang','','[]','玉繩河漢曉縱橫，萬籟潛收鶯獨鳴。',32,'全唐诗/poet.tang.17000.json','["玉繩河漢曉縱橫，萬籟潛收鶯獨鳴。", "能將百囀清心骨，寧止閑窗夢不成。"]'),
('d13cbe7c-4d3e-4ca5-8913-9e71a3de0a7c','和武相公聞鶯','皇甫鏞','唐','唐诗','tang','','[]','華館沈沈曙境清，伯勞初囀月微明。',32,'全唐诗/poet.tang.17000.json','["華館沈沈曙境清，伯勞初囀月微明。", "不知台座宵吟久，猶向花窗驚夢聲。"]'),
('15d66ae7-0b76-4946-be9d-6f6e053cd9f7','白露爲霜','顏粲','唐','唐诗','tang','','[]','悲秋將歲晚，繁露已成霜。',72,'全唐诗/poet.tang.17000.json','["悲秋將歲晚，繁露已成霜。", "徧渚蘆先白，霑籬菊自黃。", "應鐘鳴遠寺，擁雁度三湘。", "氣逼襦衣薄，寒侵宵夢長。", "滿庭添月色，拂水斂荷香。", "獨念蓬門下，窮年在一方。"]'),
('9a912702-845a-4342-a933-c304a12c956a','吳宮敎美人戰','顏粲','唐','唐诗','tang','','[]','有客陳兵畫，功成欲霸吳。',72,'全唐诗/poet.tang.17000.json','["有客陳兵畫，功成欲霸吳。", "玉顏承將略，金鈿指軍符。", "轉佩風雲暗，鳴鼙錦繡趨。", "雪花頻落粉，香汗盡流珠。", "掩笑誰干令，嚴刑必用誅。", "至今孫子術，猶可靜邊隅。"]'),
('9bab503a-923c-48d1-b22d-9002d3828eb7','月暎清淮流','徐敞','唐','唐诗','tang','','[]','遙夜淮彌淨，浮空月正明。',72,'全唐诗/poet.tang.17000.json','["遙夜淮彌淨，浮空月正明。", "虛無含氣白，凝澹暎波清。", "見底深還淺，居高缺復盈。", "處柔知坎德，持潔表陰精。", "利物功難並，和光道已成。", "安流方利涉，應鑒此時情。"]'),
('fa7c671f-a287-48ca-b682-88f0b3a52f5f','圓靈水鏡','徐敞','唐','唐诗','tang','','[]','浮光上東洛，楊彩滿圓靈。',72,'全唐诗/poet.tang.17000.json','["浮光上東洛，楊彩滿圓靈。", "明滅淪江水，盈虛逐砌蓂。", "不分沙岸白，偏照海山清。", "練色臨窗牖，蟾光靄戶庭。", "成輪疑璧影，初魄類弓形。", "遠近凝清質，娟娟出衆星。"]'),
('fc1ccfae-5091-4e0a-9b84-2e2cdecd6f78','虹藏不見','徐敞','唐','唐诗','tang','','[]','迎冬小雪至，應節晚虹藏。',72,'全唐诗/poet.tang.17000.json','["迎冬小雪至，應節晚虹藏。", "玉氣徒成象，星精不散光。", "美人初比色，飛鳥罷呈祥。", "石澗收晴影，天津失彩梁。", "霏霏空暮雨，杳杳暎殘陽。", "舒卷應時令，因知聖曆長。"]'),
('9cc0df2b-7f6a-49a4-845a-256909e1640f','白露爲霜','徐敞','唐','唐诗','tang','','[]','早寒青女至，零露結爲霜。',72,'全唐诗/poet.tang.17000.json','["早寒青女至，零露結爲霜。", "入夜飛清景，凌晨積素光。", "駟星初皙皙，葭菼復蒼蒼。", "色冒沙灘白，威加木葉黃。", "鮮輝襲紈扇，殺氣掩干將。", "葛屨那堪履，徒令君子傷。"]'),
('f0e11484-7829-42a7-9ba1-fef44fd90e8c','賦得金莖露','徐敞','唐','唐诗','tang','','[]','武帝貴長生，延年餌玉英。',72,'全唐诗/poet.tang.17000.json','["武帝貴長生，延年餌玉英。", "銅盤貯珠露，仙掌抗金莖。", "拂曙氛埃斂，凌空沆瀣清。", "岧嶤捧瑞氣，巃嵸出宮城。", "勢入浮雲聳，形標霽色明。", "大君當御宇，何必去蓬瀛。"]'),
('ecd26238-3ff4-426f-991c-db5f7e2fa663','圓靈水鏡','張聿','唐','唐诗','tang','','[]','鳳池開月鏡，清瑩寫寥天。',72,'全唐诗/poet.tang.17000.json','["鳳池開月鏡，清瑩寫寥天。", "影散微波上，光含片玉懸。", "菱花凝泛灧，桂樹暎清鮮。", "樂廣披雲日，山濤卷霧年。", "濯纓何處去，鑒物自堪妍。", "迴首看雲液，蟾蜍勢正圓。"]'),
('3f1665d5-167e-466e-b78c-205026af40af','景風扇物','張聿','唐','唐诗','tang','','[]','何處青蘋末，呈祥起遠空。',72,'全唐诗/poet.tang.17000.json','["何處青蘋末，呈祥起遠空。", "曉來搖草樹，輕度淨塵蒙。", "水上微波動，林前媚景通。", "寥天鳴萬籟，蘭徑長幽藂。", "漸颺摶扶勢，應從槖籥功。", "開襟若有日，願覩大王風。"]'),
('fd2121e3-0b68-418f-ac3e-25f3f8f8d38b','劒化爲龍','張聿','唐','唐诗','tang','','[]','古劒誠難屈，精明有所從。',72,'全唐诗/poet.tang.17000.json','["古劒誠難屈，精明有所從。", "沈埋方出獄，合會却成龍。", "牛斗光初歇，蜿蜒氣漸濃。", "雲濤透百丈，水府躍千重。", "拖尾迷蓮鍔，張鱗露錦容。", "至今沙岸下，誰得覩玄蹤。"]'),
('c0d67b0e-00be-4415-bb75-0a67874a70c9','餘瑞麥','張聿','唐','唐诗','tang','','[]','瑞麥生堯日，芃芃雨露偏。',72,'全唐诗/poet.tang.17000.json','["瑞麥生堯日，芃芃雨露偏。", "兩岐分更合，異畝頴仍連。", "冀獲明王慶，寧唯太守賢。", "仁風吹靡靡，甘雨長芊芊。", "聖德應多稔，皇家配有年。", "已聞天下泰，誰爲濟西田。"]'),
('a5c514d3-ced1-4f5d-a11b-eaee03666fe9','賦得[首夏]猶清和','張聿','唐','唐诗','tang','','[]','早夏宜春景，和光起禁城。',72,'全唐诗/poet.tang.17000.json','["早夏宜春景，和光起禁城。", "祝融將御節，炎帝啓朱明。", "日送殘花晚，風過御苑清。", "郊原浮麥氣，池沼發荷英。", "樹影臨山動，禽飛入漢輕。", "幸逢堯禹化，全勝谷中情。"]'),
('113ed055-c563-4624-b599-60de7d6246d2','移居洞庭','麴信陵','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','重林將疊嶂，此處可逃秦。',48,'全唐诗/poet.tang.17000.json','["重林將疊嶂，此處可逃秦。", "水隔人間世，花開洞裏春。", "荷鋤分地利，縱酒樂天真。", "萬事更何有，吾今已外身。"]'),
('806341c7-a221-4bbd-bee8-7eab466a2407','吳門送客','麴信陵','唐','唐诗','tang','','[]','亂山吳苑外，臨水讓王祠。',48,'全唐诗/poet.tang.17000.json','["亂山吳苑外，臨水讓王祠。", "素是傷情處，春非送客時。", "不須愁落日，且願駐青絲。", "千里會應到，一尊誰共持。"]'),
('11031562-0934-42be-af76-285639fa65b7','長安道','麴信陵','唐','唐诗','tang','','[]','朱門暎綠楊，雙闕抵通莊。',24,'全唐诗/poet.tang.17000.json','["朱門暎綠楊，雙闕抵通莊。", "玉珮聲逾遠，紅塵猶自香。"]'),
('05175d05-24bb-49e9-9dd1-c92703cb2205','出自賊中謁恒上人','麴信陵','唐','唐诗','tang','','[]','再拜吾師喜復悲，誓心從此永歸依。',32,'全唐诗/poet.tang.17000.json','["再拜吾師喜復悲，誓心從此永歸依。", "浮生恍忽若真夢，何事于中有是非。"]'),
('ea82d3a9-ada3-46ff-8f7a-f9f089f6d955','過真律師舊院','麴信陵','唐','唐诗','tang','','[]','寂然秋院閉秋光，過客閑來禮影堂。',32,'全唐诗/poet.tang.17000.json','["寂然秋院閉秋光，過客閑來禮影堂。", "堅冰銷盡還成水，本自無形何足傷。"]'),
('e7936063-a47b-4210-b514-a7216f177260','酬談上人詠海石榴','麴信陵','唐','唐诗','tang','','[]','真僧相勸外浮華，萬法無常可歎嗟。',32,'全唐诗/poet.tang.17000.json','["真僧相勸外浮華，萬法無常可歎嗟。", "但試尋思階下樹，何人種此我看花。"]'),
('ddcdf931-6f87-4344-bd7b-105f5d478859','句','麴信陵','唐','唐诗','tang','','[]','臺笠冒山雨，渚田耕荇花。',12,'全唐诗/poet.tang.17000.json','["臺笠冒山雨，渚田耕荇花。"]'),
('01e7f9b0-19a0-4ec7-b334-c12ecc904137','冬日可愛','張正元','唐','唐诗','tang','','[]','寒日臨清晝，遼天一望時。',72,'全唐诗/poet.tang.17000.json','["寒日臨清晝，遼天一望時。", "未消埋徑雪，先暖讀書帷。", "屬思光難駐，舒情影若遺。", "晉臣曾比德，謝客昔言詩。", "散彩寧偏煦，流陰信不追。", "餘輝如可就，迴燭幸無私。"]'),
('23f4dae2-e951-44ba-896e-790e78c8a291','臨川羨魚','張正元','唐','唐诗','tang','','[]','有客百愁侵，求魚正在今。',72,'全唐诗/poet.tang.17000.json','["有客百愁侵，求魚正在今。", "廣川何渺漫，高岸幾登臨。", "風水寧相阻，煙霞豈憚深。", "不應同逐鹿，詎肯比從禽。", "結網非無力，忘筌自有心。", "永存芳餌在，佇立思沈沈。"]'),
('a4d6fab0-17cf-448c-97f9-d1345ad69217','青雲干呂','王履貞','唐','唐诗','tang','','[]','異方占瑞氣，干呂見青雲。',72,'全唐诗/poet.tang.17000.json','["異方占瑞氣，干呂見青雲。", "表聖興中國，來王謁大君。", "迎祥殊大樂，叶慶類橫汾。", "自感明時起，非因觸石分。", "暎霄難辨色，從吹乍成文。", "須使流千載，垂芳在典墳。"]'),
('c620865d-0ff1-4861-9847-114e33be2f18','青雲干呂 一','彭伉','唐','唐诗','tang','','[]','祥輝上干呂，郁郁又紛紛。',72,'全唐诗/poet.tang.17000.json','["祥輝上干呂，郁郁又紛紛。", "遠示無爲化，將明至道君。", "勢凝千里靜，色向九霄分。", "已見從龍意，寧知觸石文。", "狀煙殊散漫，捧日更氛氳。", "自使來賓國，西瞻仰瑞雲。"]'),
('dd4c60cf-6385-48a0-86b2-2020cdf70f36','青雲干呂 二','彭伉','唐','唐诗','tang','','[]','聖布中區化，祥符異域雲。',72,'全唐诗/poet.tang.17000.json','["聖布中區化，祥符異域雲。", "含春初應呂，暈碧已成文。", "東起隨風暖，西流共日曛。", "升時嘉異月，爲慶等凝汾。", "輕與晴煙比，高將曉霧分。", "飄飄如可致，願此翊明君。"]'),
('5c4ab5cc-b027-4c39-a422-336422b6ac0c','寄妻','彭伉','唐','唐诗','tang','','[]','莫訝相如獻賦遲，錦書誰道淚沾衣。',32,'全唐诗/poet.tang.17000.json','["莫訝相如獻賦遲，錦書誰道淚沾衣。", "不須化作山頭石，待我堂前折桂枝。"]'),
('e5a97aba-72cd-4663-81fe-1f0af4375e15','青雲干呂','林藻','唐','唐诗','tang','','[]','應節偏干呂，亭亭在紫氛。',72,'全唐诗/poet.tang.17000.json','["應節偏干呂，亭亭在紫氛。", "綴空初布影，捧日已成文。", "結蓋祥光迥，爲樓翠色分。", "還同起封上，更似出橫汾。", "作瑞來藩國，呈形表聖君。", "裴回如有託，誰道比閑雲。"]'),
('b1a8a5bb-0c34-40a7-a065-e90994eff6c0','吳宮敎戰','林藻','唐','唐诗','tang','','[]','強吳矜霸略，講武在深宮。',72,'全唐诗/poet.tang.17000.json','["強吳矜霸略，講武在深宮。", "盡出嬌娥輩，先觀上將風。", "揮戈羅袖卷，擐甲汗裝紅。", "輕笑分旗下，含羞入隊中。", "鼓停行未整，刑舉令方崇。", "自可威鄰國，何勞騁戰功。"]'),
('82506631-692c-4f17-96a4-9fcb52ca6d5a','梨嶺','林藻','唐','唐诗','tang','','[]','曾向嶺頭題姓字，不穿楊葉不言歸。',32,'全唐诗/poet.tang.17000.json','["曾向嶺頭題姓字，不穿楊葉不言歸。", "弟兄各折一枝桂，還向嶺頭聯影飛。"]'),
('9da11f1c-210d-4a69-96f9-35afae382cf9','贈馮宿','李觀','唐','唐诗','tang','','[]','寒城上秦原，遊子衣飄飄。',60,'全唐诗/poet.tang.17000.json','["寒城上秦原，遊子衣飄飄。", "黑雲截萬里，獵火從中燒。", "陰空蒸長煙，殺氣獨不銷。", "冰交石可裂，風疾山如搖。", "時無青松心，顧我獨不凋。"]'),
('2fca1edc-5d1c-4217-9fe2-fac9e7f6537a','宿裴友書齋','李觀','唐','唐诗','tang','','[]','臥君山窗下，山鳥與我言。',60,'全唐诗/poet.tang.17000.json','["臥君山窗下，山鳥與我言。", "清風何颼飀，松栢中夜繁。", "久遊失歸趣，宿此似故園。", "林煙橫近郊，谿月落古原。", "穉子不待曉，花間出柴門。"]'),
('2e5826d9-ab69-4819-8157-bd37264e9ec5','御溝新柳','李觀','唐','唐诗','tang','','[]','御溝迴廣陌，芳柳對行人。',72,'全唐诗/poet.tang.17000.json','["御溝迴廣陌，芳柳對行人。", "翠色枝枝滿，年光樹樹新。", "畏逢攀折客，愁見別離辰。", "近暎章臺騎，遙分禁苑春。", "嫩陰初覆水，高影漸離塵。", "莫入胡兒笛，還令淚溼巾。"]'),
('4a1d5bd1-5ed5-4872-a6b9-1536e85ad04e','試中和節詔賜公卿尺詩','李觀','唐','唐诗','tang','','[]','淑節韶光媚，皇明寵錫崇。',72,'全唐诗/poet.tang.17000.json','["淑節韶光媚，皇明寵錫崇。", "具寮頒玉尺，成器幸良工。", "豈止尋常用，將傳度量同。", "人何不取利，物亦賴其功。", "紫翰宣殊造，丹誠厲匪躬。", "奉之無失墜，恩澤自天中。"]'),
('1bd0ff02-ddc1-46cb-8684-23c70acb437f','省試恩賜耆老布帛','李絳','唐','唐诗','tang','','[]','渙汗中天發，殊私海外存。',72,'全唐诗/poet.tang.17000.json','["渙汗中天發，殊私海外存。", "衰顏逢聖代，華髮受皇恩。", "燭物明堯日，垂衣闢禹門。", "惜時悲落景，賜帛慰餘魂。", "厚澤沾翔泳，微生保子孫。", "盛明今尚齒，歡奉九衢罇。"]'),
('66a2150d-f0f0-479f-ac3c-b3b06cc38818','和裴相國荅張秘書贈馬詩','李絳','唐','唐诗','tang','','[]','高才名價欲凌雲，上駟光華遠贈君。',64,'全唐诗/poet.tang.17000.json','["高才名價欲凌雲，上駟光華遠贈君。", "念舊露垂丞相簡，感知星動客卿文。", "縱橫逸氣寧稱力，馳騁長途定出羣。", "伏櫪莫令空度歲，黃金結束取功勳。"]'),
('8502f5c2-f556-45e4-a3ec-f49fc4517daa','賜耆老布帛','崔樞','唐','唐诗','tang','','[]','殊私及耆老，聖德賑黎元。',72,'全唐诗/poet.tang.17000.json','["殊私及耆老，聖德賑黎元。", "布帛忻天賜，生涯作主恩。", "情均皆挾纊，禮異賁丘園。", "慶洽時方泰，仁沾月告存。", "寧知酬雨露，空識荷乾坤。", "擊壤將何幸，裴回望九門。"]'),
('bc401494-86e9-4133-93fc-b5fa6e701280','齊優開籠飛去所獻楚王鵠','崔樞','唐','唐诗','tang','','[]','受命籠齊鵠，交歡獻楚王。',72,'全唐诗/poet.tang.17000.json','["受命籠齊鵠，交歡獻楚王。", "惠心先巧辯，戢羽見迴翔。", "意適清風遠，憂除白日長。", "度雲搖舊影，過樹閱新芳。", "直取名翻重，寧唯好不傷。", "誰言滑稽理，千載戒禽荒。"]'),
('b05520d2-309a-490a-8627-74508d568f42','試中和節詔賜公卿尺詩','陸復禮','唐','唐诗','tang','','[]','春仲令初吉，歡娛樂大中。',72,'全唐诗/poet.tang.17000.json','["春仲令初吉，歡娛樂大中。", "皇恩貞百度，寶尺賜羣公。", "欲使方隅法，還令規矩同。", "捧觀珍質麗，拜受聖恩崇。", "如荷丘山重，思酬方寸功。", "從茲度天地，與國慶無窮。"]'),
('92f47c36-d77a-4ab5-b5df-893d6ea09e28','賦得白雲起封中','李正辭','唐','唐诗','tang','','["\u6cf0\u5c71"]','千年泰山頂，雲起漢皇封。',72,'全唐诗/poet.tang.17000.json','["千年泰山頂，雲起漢皇封。", "不作奇峯狀，寧分觸石容。", "爲霖雖易得，表聖自難逢。", "冉冉排空上，依依疊影重。", "素光非曳練，靈貺是從龍。", "豈學無心出，東西任所從。"]'),
('4fd38375-40cc-4666-8ab8-e46b1fd2460f','賦得白雲起封中','張嗣初','唐','唐诗','tang','','[]','英英白雲起，呈瑞出封中。',72,'全唐诗/poet.tang.17000.json','["英英白雲起，呈瑞出封中。", "表聖寧因地，逢時豈待風。", "浮光彌皎潔，流影更沖融。", "自叶堯年美，誰云漢日同。", "金泥光乍掩，玉檢氣潛通。", "欲與非煙並，亭亭不散空。"]'),
('2b151a64-7aad-4661-8b12-2cd02bcb16e2','春色滿皇州','張嗣初','唐','唐诗','tang','','[]','何處年華好，皇州淑氣勻。',72,'全唐诗/poet.tang.17000.json','["何處年華好，皇州淑氣勻。", "韶陽潛應律，草木暗迎春。", "柳變金堤畔，蘭抽曲水濱。", "輕黃垂輦道，微綠映天津。", "麗景浮丹闕，晴光擁紫宸。", "不知幽遠地，今日幾枝新。"]'),
('8df1473f-b50e-43d1-9320-217239903d4b','日暮碧雲合','許康佐','唐','唐诗','tang','','[]','日際愁陰生，天涯暮雲碧。',72,'全唐诗/poet.tang.17000.json','["日際愁陰生，天涯暮雲碧。", "重重不辨蓋，沈沈乍如積。", "林色黯疑暝，隟光俄已夕。", "出岫且從龍，縈空寧觸石。", "餘輝澹瑤草，浮影凝綺席。", "時景詎能留，幾思輕尺璧。"]'),
('eb0d7610-5904-4de0-a7e3-7d2b3c6dd666','白雲起封中','許康佐','唐','唐诗','tang','','[]','英英白雲起，呈瑞出封中。',72,'全唐诗/poet.tang.17000.json','["英英白雲起，呈瑞出封中。", "表聖寧依地，逢時豈待風。", "浮輝彌皎潔，流影更沖融。", "自叶堯天美，誰言漢日同。", "泥金光乍掩，檢玉氣俄通。", "猶願非煙瑞，亭亭不散空。"]'),
('f7e6ff35-96d5-4a24-961c-d06262597051','石季倫金谷園','許堯佐','唐','唐诗','tang','','[]','石氏遺文在，淒涼見故園。',72,'全唐诗/poet.tang.17000.json','["石氏遺文在，淒涼見故園。", "輕風思奏樂，衰草憶行軒。", "舞榭蒼苔掩，歌臺落葉繁。", "斷雲歸舊壑，流水咽新源。", "曲沼殘煙斂，叢篁宿鳥喧。", "唯餘池上月，猶似對金尊。"]'),
('5627b5d9-f801-4942-9fd2-5b6b9da22dfe','石季倫金谷園','李君房','唐','唐诗','tang','','[]','梓澤風流地，淒涼跡尚存。',72,'全唐诗/poet.tang.17000.json','["梓澤風流地，淒涼跡尚存。", "殘芳迷妓女，衰草憶王孫。", "舞態隨人謝，歌聲寄鳥言。", "池平森灌木，月落弔空園。", "流水悲難駐，浮雲影自翻。", "賓階餘蘚石，車馬詎喧喧。"]'),
('d5193221-e81f-4603-9afd-26dc0e8f4583','享惠昭太子廟樂章登歌','杜羔','唐','唐诗','tang','','[]','因心克孝，位震遺芬。',40,'全唐诗/poet.tang.17000.json','["因心克孝，位震遺芬。", "賓天道茂，軫懷氣分。", "發祇乃祀，咳歎如聞。", "二歌斯升，以詠德薰。"]'),
('9b07bc6b-8022-4278-a691-a47120a1da16','南至日隔仗望含元殿香鑪','車𬘔','唐','唐诗','tang','','[]','抗殿疏元首，高高接上元。',72,'全唐诗/poet.tang.17000.json','["抗殿疏元首，高高接上元。", "節當南至日，星是北辰天。", "寶戟羅仙仗，金鑪引瑞煙。", "霏微雙闕麗，溶曳九州連。", "拂曙祥光滿，分晴曉色鮮。", "一陽今在曆，生植願陶甄。"]'),
('96df8c5c-0f1a-471f-90f7-7b785f3c9e84','奉和聖製九月十八日賜百寮追賞因書所懷','權德輿','唐','唐诗','tang','','[]','錫宴朝野洽，追歡堯舜情。',72,'全唐诗/poet.tang.17000.json','["錫宴朝野洽，追歡堯舜情。", "秋堂絲管動，水榭煙霞生。", "黃花媚新霽，碧樹含餘清。", "同和六律應，交泰萬宇平。", "春藻下中天，湛恩闡文明。", "小臣諒何以，亦此彯華纓。"]'),
('3a142d6c-8897-4ed1-80d3-b705d9cba724','奉和聖製九日言懷賜中書門下及百寮','權德輿','唐','唐诗','tang','','[]','令節在豐歲，皇情喜乂安。',72,'全唐诗/poet.tang.17000.json','["令節在豐歲，皇情喜乂安。", "絲竹調六律，簪裾列千官。", "煙霜暮景清，水木秋光寒。", "筵開曲池上，望盡終南端。", "天文麗慶霄，墨妙驚飛鸞。", "願言黃花酒，永奉今日歡。"]'),
('4c623213-b98c-4b41-af11-f0206208ac1e','奉和聖製重陽日中外同歡以詩言志因示百僚','權德輿','唐','唐诗','tang','','[]','玉醴宴嘉節，拜恩歡有餘。',84,'全唐诗/poet.tang.17000.json','["玉醴宴嘉節，拜恩歡有餘。", "煌煌菊花秀，馥馥萸房舒。", "白露秋稼熟，清風天籟虛。", "和聲度簫韶，瑞氣深儲胥。", "百辟皆醉止，萬方今宴如。", "宸衷在化成，藻思煥瓊琚。", "微臣徒竊抃，豈足歌唐虞。"]'),
('1f2d3368-1624-4bcb-93ba-9909ff3d9eab','奉和聖製中春麟德殿會百寮觀新樂','權德輿','唐','唐诗','tang','','[]','仲春藹芳景，內庭宴羣臣。',96,'全唐诗/poet.tang.17000.json','["仲春藹芳景，內庭宴羣臣。", "森森列干戚，濟濟趨鉤陳。", "大樂本天地，中和序人倫。", "正聲邁咸濩，易象含羲文。", "玉俎映朝服，金鈿明舞茵。", "韶光雪初霽，聖藻風自薫。", "時泰恩澤溥，功成行綴新。", "賡歌仰昭回，竊比華封人。"]'),
('a754b0bd-8cfc-434c-b56d-17c9c02ecff4','奉和聖製中和節賜百官宴集因示後懷','權德輿','唐','唐诗','tang','','[]','萬方慶嘉節，宴喜皇澤均。',72,'全唐诗/poet.tang.17000.json','["萬方慶嘉節，宴喜皇澤均。", "曉開蓂葉初，景麗星鳥春。", "藻思貞百度，著明並三辰。", "物情舒在陽，時令弘至仁。", "衢酒和樂被，薰弦聲曲新。", "賡歌武弁側，永荷玄化醇。"]'),
('5b8928c7-3964-4370-8eee-5426e1e25eba','奉和聖製重陽日即事六韻','權德輿','唐','唐诗','tang','','[]','嘉節在陽數，至歡朝野同。',72,'全唐诗/poet.tang.17000.json','["嘉節在陽數，至歡朝野同。", "恩隨千鍾洽，慶屬五稼豐。", "時菊洗露華，秋池涵霽空。", "金絲響仙樂，劒舃羅宗公。", "天道光下濟，睿詞敷大中。", "多慙撃壤曲，何以荅堯聰。"]'),
('3c902514-da71-4264-9cce-a13f36059c29','奉和聖制豐年多慶九日示懷','權德輿','唐','唐诗','tang','','[]','寒露應秋杪，清光澄曙空。',72,'全唐诗/poet.tang.17000.json','["寒露應秋杪，清光澄曙空。", "澤均行葦厚，年慶華黍豐。", "聲明暢八表，宴喜陶九功。", "文麗日月合，樂和天地同。", "聖言在推誠，臣職惟匪躬。", "瑣細何以報，翾飛淳化中。"]'),
('e521d234-7da4-4003-95b4-dc726a6dd1ad','贈文敬太子廟時享退文舞迎武舞樂章','權德輿','唐','唐诗','tang','','[]','干旄羽籥相虧蔽，一進一退殊行綴。',32,'全唐诗/poet.tang.17000.json','["干旄羽籥相虧蔽，一進一退殊行綴。", "昔獻三雍盛禮容，今陳六佾崇儀制。"]'),
('4fe37e01-7122-47ef-a8f6-cdfae4b5a7f1','讀穀梁傳二首 一','權德輿','唐','唐诗','tang','','[]','荀寅士吉射，誠乃蔽聰明。',48,'全唐诗/poet.tang.17000.json','["荀寅士吉射，誠乃蔽聰明。", "奈何趙志父，專舉晉陽兵。", "下令漢七國，借此以爲名。", "吾嘉徙薪智，禍亂何由生。"]'),
('a45b0aa0-ad57-4200-8d05-5f428e88abf1','讀穀梁傳二首 二','權德輿','唐','唐诗','tang','','[]','憶昔溴梁會，豈伊無諸侯。',51,'全唐诗/poet.tang.17000.json','["憶昔溴梁會，豈伊無諸侯。", "羣臣自盟歃，君政如贅旒。", "有力則宗楚，何人復尊周。", "空文徒爾貶，見此[眥]□血流。"]'),
('5872eadd-43a8-4f85-9389-25746a2246bd','劉紹相訪夜話因書即事','權德輿','唐','唐诗','tang','','[]','故人愴久別，茲夕欵郊扉。',72,'全唐诗/poet.tang.17000.json','["故人愴久別，茲夕欵郊扉。", "山僮漉野醖，穉子褰書帷。", "清露泫珠瑩，金波流玉徽。", "忘言我造適，瞪視君無違。", "但令靜勝躁，自使癯者肥。", "不待蘧生年，從此知昔非。"]'),
('3bf908a6-4359-4c8a-ae66-43a5911afa29','臥病喜惠上人李鍊師茅處士見訪因以贈','權德輿','唐','唐诗','tang','','[]','沈疴結繁慮，臥見書窗曙。',120,'全唐诗/poet.tang.17000.json','["沈疴結繁慮，臥見書窗曙。", "方外三賢人，惠然來相親。", "整巾起曳策，喜非車馬客。", "支郎有佳文，新句淩碧雲。", "霓裳何飄飄，浩志淩紫氛。", "復有沈冥士，遠係三茅君。", "各言麋鹿性，不與簪組羣。", "清言出象繫，曠跡逃玄纁。", "心源蹔澄寂，世故方糺紛。", "終當逐師輩，巖桂香氳芬。"]'),
('27ad7462-8d75-4ddf-895a-94b244da9487','多病戲書因示長孺','權德輿','唐','唐诗','tang','','[]','行年未四十，已覺百病生。',48,'全唐诗/poet.tang.17000.json','["行年未四十，已覺百病生。", "眼眩飛蠅影，耳厭遠蟬聲。", "甘辛敗六藏，冰炭交七情。", "唯思曲肱枕，搔首擲華纓。"]'),
('0fdfd45f-a4ae-48c5-8127-d55223988f0d','古興','權德輿','唐','唐诗','tang','','["\u9ec4\u6cb3"]','月中有桂樹，無翼難上天。',88,'全唐诗/poet.tang.17000.json','["月中有桂樹，無翼難上天。", "海底有龍珠，下隔萬丈淵。", "人生大限雖百歲，就中三十稱一世。", "晦明烏兔相推遷，雪霜漸到雙鬢邊。", "沈憂戚戚多浩歎，不得如意居太半。", "一氣暫聚常恐散，黃河清兮白石爛。"]'),
('4ab6a053-a0d9-4005-a5ce-d82d72340d2a','感寓','權德輿','唐','唐诗','tang','','[]','殘雨倦欹枕，病中時序分。',96,'全唐诗/poet.tang.17000.json','["殘雨倦欹枕，病中時序分。", "秋蟲與秋葉，一夜隔窗聞。", "虛室對搖落，晤言無與羣。", "冥心試觀化，世故如絲棼。", "但看鳶戾天，豈見山出雲。", "下里徒撃節，朱弦秘南薰。", "梧桐秀朝陽，上有威鳳文。", "終待九成奏，來儀瑞吾君。"]'),
('7efba240-bbd8-45d9-b687-4af3a1b140bd','跌傷伏枕有勸醲酒者蹔忘所苦因有一絕','權德輿','唐','唐诗','tang','','[]','一杯宜病士，四體委胡牀。',24,'全唐诗/poet.tang.17000.json','["一杯宜病士，四體委胡牀。", "蹔得遺形處，陶然在醉鄉。"]'),
('deedbd74-074e-49df-9161-7a524d6d2b36','病中苦熱','權德輿','唐','唐诗','tang','','[]','三伏鼓洪爐，支離一病夫。',48,'全唐诗/poet.tang.17000.json','["三伏鼓洪爐，支離一病夫。", "倦眠身似火，渴歠汗如珠。", "悸乏心難定，沈煩氣欲無。", "何時灑微雨，因與好風俱。"]'),
('add678d3-b662-4c8a-836b-17c30382f378','覽鏡見白髮數莖光鮮特異','權德輿','唐','唐诗','tang','','[]','秋來皎潔白鬚光，試脫朝簪學酒狂。',32,'全唐诗/poet.tang.17000.json','["秋來皎潔白鬚光，試脫朝簪學酒狂。", "一曲酣歌還自樂，兒孫嬉笑挽衣裳。"]'),
('9cefb93d-3695-483a-8ed9-9d15ce5d39b8','南亭曉坐因以示璩','權德輿','唐','唐诗','tang','','[]','隱几日無事，風交松桂枝。',72,'全唐诗/poet.tang.17000.json','["隱几日無事，風交松桂枝。", "園廬含曉霽，草木發華姿。", "跡似南山隱，官從小宰移。", "萬殊同野馬，方寸即靈龜。", "弱質常多病，流年近始衰。", "圖書傳授處，家有一男兒。"]'),
('a5d3f266-dd2f-4608-a407-2218fff81515','竹逕偶然作','權德輿','唐','唐诗','tang','','[]','退朝此休沐，閉戶無塵氛。',48,'全唐诗/poet.tang.17000.json','["退朝此休沐，閉戶無塵氛。", "杖策入幽逕，清風隨此君。", "琴觴恣偃傲，蘭蕙相氛氳。", "幽賞方自適，林西煙景曛。"]'),
('350dc47e-e3c6-4f08-b35d-d71134d35578','拜昭陵過咸陽墅','權德輿','唐','唐诗','tang','','[]','季子乏二頃，楊雄才一廛。',168,'全唐诗/poet.tang.17000.json','["季子乏二頃，楊雄才一廛。", "伊予此南畝，數已踰前賢。", "頃歲辱明命，銘勳鏤貞堅。", "遂茲操書致，內顧增缺然。", "乃葺場圃事，迨今三四年。", "適因昭陵拜，得抵咸陽田。", "田夫競致辭，鄉耋爭來前。", "村盤既羅列，雞黍皆珍鮮。", "古稱祿代耕，人以食爲天。", "自慙廩給厚，諒使井稅先。", "塗塗溝塍霧，漠漠桑柘煙。", "荒蹊沒古木，精舍臨秋泉。", "池籠豈所安，樵牧乃所便。", "終當解纓絡，田里諧因緣。"]'),
('f56195d2-9839-487d-b558-2c38488840ec','早春南亭即事','權德輿','唐','唐诗','tang','','[]','虛齋坐清晝，梅坼柳條鮮。',48,'全唐诗/poet.tang.17000.json','["虛齋坐清晝，梅坼柳條鮮。", "節候開新曆，筋骸減故年。", "振衣慙艾綬，闚鏡歎華顛。", "獨有開懷處，孫孩戲目前。"]'),
('91aec24e-d49f-4f78-a8c0-c2526f271c19','璩授京兆府參軍戲書以示兼呈獨孤郎','權德輿','唐','唐诗','tang','','[]','見爾府中趨，初官足慰吾。',48,'全唐诗/poet.tang.17000.json','["見爾府中趨，初官足慰吾。", "老牛還舐犢，凡鳥亦將雛。", "喜至翻成感，癡來或欲殊。", "因慙玉潤客，應笑此非夫。"]'),
('70273d46-92cd-40d2-b5c3-e4077a482d3b','書紳詩','權德輿','唐','唐诗','tang','','[]','和靜有真質，斯人稱最靈。',144,'全唐诗/poet.tang.17000.json','["和靜有真質，斯人稱最靈。", "感物惑天性，觸里紛多名。", "禍機生隱微，智者鑒未形。", "敗禮因近習，喆人自居貞。", "當令念慮端，鄙嫚不能萌。", "苟非不踰矩，焉得遂性情。", "謹之在事初，動用各有程。", "千里起步武，彗雲自纖莖。", "心源一流放，駭浪奔長鯨。", "淵木苟端深，枝流則貞清。", "和理通性術，悠久方昭明。", "先師留中庸，可以導此生。"]'),
('c94d51de-dc20-468d-a9ff-bc4fb0bfcc0b','侍從遊後湖讌坐','權德輿','唐','唐诗','tang','','[]','絕境殊不遠，湖塘直吾廬。',264,'全唐诗/poet.tang.17000.json','["絕境殊不遠，湖塘直吾廬。", "煙霞旦夕生，泛覽誠可娛。", "慈顏俯見喻，輟爾詩與書。", "清旭理輕舟，嬉遊散煩劬。", "宿雨蕩殘燠，惠風與之俱。", "心靈一開曠，機巧眇已疎。", "中流有荷花，花實相芬敷。", "田田綠葉映，豔豔紅姿舒。", "繁香好風結，淨質清露濡。", "丹霞無容輝，嫮色亦踟躕。", "穠芳射水木，欹葉游龜魚。", "化工若有情，生植皆不如。", "輕舟任沿泝，畢景乃躊躇。", "家人亦恬曠，稚齒皆忻愉。", "素弦激淒清，旨酒盈罇壺。", "壽觴既頻獻，樂極隨歌呼。", "圓月初出海，澄輝來滿湖。", "清光照酒酣，頫傾百慮無。", "以茲心目暢，敵彼名利途。", "輕肥何爲者，漿藿自有餘。", "願銷區中累，保此湖上居。", "無用誠自適，年年翫芙蕖。"]'),
('02615ab9-cfa6-48f0-8880-373d2c8bc9ab','晨坐寓興','權德輿','唐','唐诗','tang','','[]','清晨坐虛齋，羣動寂未諠。',72,'全唐诗/poet.tang.17000.json','["清晨坐虛齋，羣動寂未諠。", "泊然一室內，因見萬化源。", "得喪心既齊，清淨敎益敦。", "境來每自愜，理勝或不言。", "亭柯見榮枯，止水知清渾。", "悠悠世上人，此理法難論。"]'),
('3966f7e4-c1d9-4f20-848b-5fab69db1d5c','郊居歲暮因書所懷','權德輿','唐','唐诗','tang','','[]','養拙方去諠，深居絕人事。',216,'全唐诗/poet.tang.17000.json','["養拙方去諠，深居絕人事。", "返耕忘帝力，樂道疎代累。", "翛然衡茅下，便有江海意。", "寧知肉食尊，自覺儒衣貴。", "煙霜當暮節，水石多幽致。", "三徑日閑安，千峯對深邃。", "策藜出村渡，岸幘尋古寺。", "月魄清夜琴，猨聲警朝寐。", "地偏芝桂長，境勝煙霞異。", "獨鳥帶晴光，疎篁淨寒翠。", "窗前風葉下，枕上溪雲至。", "散髮對農書，齋心看道記。", "清言覈名理，開卷窮精義。", "求譽觀朵頤，危身陷芳餌。", "紛吾守孤直，世業常恐墜。", "就學緝韋編，銘心對欹器。", "元和暢萬物，動植咸使遂。", "素履期不渝，永懷丘中志。"]'),
('0e34ee41-2947-4078-930d-c337323c95eb','暮春閑居示同志','權德輿','唐','唐诗','tang','','[]','避諠非傲世，幽興樂郊園。',144,'全唐诗/poet.tang.17000.json','["避諠非傲世，幽興樂郊園。", "好古每開卷，居貧常閉門。", "曙鐘來古寺，旭日上西軒。", "稍與清境會，蹔無塵事煩。", "靜看雲起滅，閑望鳥飛翻。", "乍問山僧偈，時聽漁父言。", "體羸諳藥性，事簡見心源。", "冠帶驚年長，詩書喜道存。", "小池泉脈湊，危棟燕雛喧。", "風入松陰靜，花添竹影繁。", "灌園輸井稅，學稼奉晨昏。", "此外知何有，怡然向一罇。"]'),
('c1dbc932-5ffe-4c31-9842-3eb04250ae38','田家即事','權德輿','唐','唐诗','tang','','[]','閑臥藜牀對落暉，翛然便覺世情非。',64,'全唐诗/poet.tang.17000.json','["閑臥藜牀對落暉，翛然便覺世情非。", "漠漠稻花資旅食，青青荷葉製儒衣。", "山僧相訪期中飯，漁父同遊或夜歸。", "待學尚平婚稼畢，渚煙溪月共忘機。"]'),
('bb895ffd-c47f-4f2a-9372-d537c55a2775','寓興','權德輿','唐','唐诗','tang','','[]','弱冠無所就，百憂鍾一身。',96,'全唐诗/poet.tang.17000.json','["弱冠無所就，百憂鍾一身。", "世德既顛墜，素懷亦堙淪。", "風煙隔嵩丘，羸疾滯漳濱。", "昭代未通籍，豐年猶食貧。", "敢求庖有魚，但慮甑生塵。", "俛首愧僮僕，蹇步羞親賓。", "豈伊當途者，一一由中人。", "已矣勿復言，吾將問秋旻。"]'),
('dc7ec377-73c4-4253-b590-8006ebefba2c','浩歌','權德輿','唐','唐诗','tang','','[]','杖策出蓬蓽，浩歌秋興長。',192,'全唐诗/poet.tang.17000.json','["杖策出蓬蓽，浩歌秋興長。", "北風吹荷衣，簫颯景氣涼。", "通逵抵山郭，里巷連湖光。", "孤雲淨遠峯，綠水溢芳塘。", "魚鳥樂天性，雜英互芬芳。", "我心獨何爲，萬慮縈中腸。", "履道身未泰，主家謀不臧。", "心爲世敎牽，跡寄翰墨場。", "出處兩未定，羈羸空自傷。", "沈憂不可裁，佇立河之梁。", "晚歸茅簷下，左右陳壺觴。", "獨酌復長謠，放心遊八荒。", "得喪同一域，是非亦何常。", "胡爲苦此生，矻矻徒自強。", "乃知杯中物，可使憂患忘。", "因茲謝時輩，棲息無何鄉。"]'),
('25317c49-f336-448b-9a56-2afbf5c4e049','與道者同守庚申','權德輿','唐','唐诗','tang','','[]','洞真善救世，守夜看仙經。',192,'全唐诗/poet.tang.17000.json','["洞真善救世，守夜看仙經。", "俾我外持內，當茲申配庚。", "齋心已恬愉，澡身自澂明。", "沈沈簾幃下，靄靄燈燭清。", "四支動用息，一室虛白生。", "收視忘趨舍，叩齒集神靈。", "伊予嗜欲寡，居常痾恙輕。", "三尸既伏竄，九藏乃和平。", "無令耳目勝，則使性命傾。", "窅然深夜中，若與元氣幷。", "釋宗稱定慧，儒師著誠明。", "派分示三敎，理詣無二名。", "吉祥能止止，委順則生生。", "視履苟無咎，天祐期永貞。", "應物智不勞，虛中理自冥。", "豈資金丹術，即此駐頹齡。"]'),
('8fefe96e-e5b5-4787-92c5-d94cac659653','丙庚歲苦貧戲題','權德輿','唐','唐诗','tang','','[]','清朝起藜牀，雪霜對枯籬。',255,'全唐诗/poet.tang.17000.json','["清朝起藜牀，雪霜對枯籬。", "家人來告予，今日無晨炊。", "鹺醯一已整，薪炭固難期。", "厚生彼何人，工拙各異宜。", "間歲從使檄，親賓苦川馳。", "雖非悖而[入]□，[與出]□□常相随。", "吳門與南畝，頗亦持鎡基。", "有時[遇豐年]□□□，歲計猶不支。", "顏淵諒賢人，陋巷能自怡。", "[中憶裴]□□□子野，泰然傾薄糜。", "愧非古人心，戚戚愁[朝飢]□□。", "[近]□古猶不及，太上那可希。", "奈何時風扇，使[我正性]□□□衰。", "巧智競憂勞，展轉生澆漓。", "吾觀黃金[印]□，[未]□勝青松枝。", "麤令有魚菽，豈復求輕肥。", "顧慙[主家]□□拙，甘使羣下嗤。", "如何致一杯，醉後無所知。"]'),
('1195763f-2db9-4952-9590-484f779faed8','獨酌','權德輿','唐','唐诗','tang','','[]','獨酌復獨酌，滿盞流霞色。',36,'全唐诗/poet.tang.17000.json','["獨酌復獨酌，滿盞流霞色。", "身外皆虛名，酒中有全德。", "風清與月朗，對此情何極。"]'),
('a13f6647-8e74-49a0-9eac-d66cba88be77','知非','權德輿','唐','唐诗','tang','','[]','名敎自可樂，搢紳貴行道。',24,'全唐诗/poet.tang.17000.json','["名敎自可樂，搢紳貴行道。", "何必學狂歌，深山對豐草。"]'),
('ef17370a-d05e-4929-bbcf-fc07a197c13a','誡言','權德輿','唐','唐诗','tang','','[]','言之或未行，前哲所不取。',24,'全唐诗/poet.tang.17000.json','["言之或未行，前哲所不取。", "方寸雖浩然，因之三緘口。"]'),
('5afbc76d-f8df-433e-afd9-427578401a1d','醉後','權德輿','唐','唐诗','tang','','[]','美祿與賢人，相逢自可親。',24,'全唐诗/poet.tang.17000.json','["美祿與賢人，相逢自可親。", "願將花柳月，盡賞醉鄉春。"]'),
('576d674f-e294-45b1-9cf7-d99a379caf43','奉和李相公早朝於中書候傳點偶書所懷奉呈門下相公中書相公','權德輿','唐','唐诗','tang','','[]','五更鐘漏歇，千門扃鑰開。',120,'全唐诗/poet.tang.17000.json','["五更鐘漏歇，千門扃鑰開。", "紫宸殘月下，黃道曉光來。", "辨色趨中禁，分班列上台。", "祥煙初繚繞，威鳳正裴回。", "斧藻歸全德，輪轅適衆材。", "化成風偃草，道合鼎調梅。", "渥命隨三接，皇恩暢九垓。", "嘉言造膝去，喜氣沃心迴。", "東閣延多士，南山賦有臺。", "陽春那敢和，空此詠康哉。"]'),
('f0b13a02-62ae-42fe-a743-ab4eb09cb744','奉和于司空二十五丈新卜城南郊居接司徒公別墅即事書情奉獻兼呈李裴相公','權德輿','唐','唐诗','tang','','[]','一德承昌運，三公翊至尊。',120,'全唐诗/poet.tang.17000.json','["一德承昌運，三公翊至尊。", "雲龍諧理代，魚水見深恩。", "別墅池塘曉，晴郊草木蕃。", "溝塍連杜曲，茅土盛于門。", "卜築因登覽，經邦每討論。", "退朝鳴玉會，入室斷金言。", "材俊依東閣，壺觴接後園。", "逕深雲自起，風靜葉初翻。", "宰物歸心匠，虛中即化源。", "巴人寧敢和，空此媿遊藩。"]'),
('302ea12d-1497-4d4f-b3f4-86c7c4574197','奉和新卜城南郊居得與衛右丞鄰舍因賦詩寄贈','權德輿','唐','唐诗','tang','','[]','上宰坐論道，郊居仍里仁。',120,'全唐诗/poet.tang.17000.json','["上宰坐論道，郊居仍里仁。", "六符既昭晰，萬象隨陶鈞。", "旭旦下玉墀，鳴騶拂車茵。", "軒窗退殘暑，風物迎蕭辰。", "山澤蜃雨出，林塘魚鳥馴。", "豈同求羊逕，共是羲皇人。", "石君五曹重，左戶三壤均。", "居止煙火接，逢迎雞黍頻。", "大方本無隅，盛德必有鄰。", "千年郢曲後，復此聞陽春。"]'),
('9cc49168-b18c-4c44-aef6-a559c2a407e5','奉和韋曲莊言懷貽東曲外族諸弟','權德輿','唐','唐诗','tang','','[]','韋曲冠蓋里，鮮原鬱青蔥。',120,'全唐诗/poet.tang.17000.json','["韋曲冠蓋里，鮮原鬱青蔥。", "公台睦中外，墅舍鄰西東。", "騶馭出國門，晨曦正曈曨。", "燕居平外土，野服參華蟲。", "疆畎分古渠，煙霞連灌叢。", "長幼序以齒，歡言無不同。", "憶昔全盛時，勛劬播休功。", "代業擴宇內，光塵藹墟中。", "慨息多永歎，歌詩厚時風。", "小生忝瓜葛，慕義斯無窮。"]'),
('6adac152-9779-40b7-a7dd-58a4144a7845','和王侍郎病中領度支煩迫之餘過西園書堂閑望','權德輿','唐','唐诗','tang','','[]','憑檻輟繁務，晴光煙樹分。',48,'全唐诗/poet.tang.17000.json','["憑檻輟繁務，晴光煙樹分。", "中邦均禹貢，上藥驗桐君。", "滿逕風轉蕙，卷簾山出雲。", "鏘然玉音發，餘興在斯文。"]'),
('693a0842-0d81-45fc-a1af-5539ffc88e39','奉和度支李侍郎早朝','權德輿','唐','唐诗','tang','','[]','夙駕趨北闕，曉星啓東方。',72,'全唐诗/poet.tang.17000.json','["夙駕趨北闕，曉星啓東方。", "鳴騶分騎吏，列燭散康莊。", "照灼華簪並，逶迤綺陌長。", "腰金初辨色，噴玉自生光。", "獻替均三壤，貞明集百祥。", "下才叨接武，空此媿文昌。"]'),
('8bb587f0-50bf-4a26-888f-60b5aa12bcc2','奉和劉侍郎司徒奉詔伐叛書情呈宰相','權德輿','唐','唐诗','tang','','[]','玉帳元侯重，黃樞上宰雄。',48,'全唐诗/poet.tang.17000.json','["玉帳元侯重，黃樞上宰雄。", "緣情詞律外，宣力廟謀中。", "震耀恭天討，嚴凝助歲功。", "行看畫麟閣，凜凜有英風。"]'),
('bad7958c-eafc-4acb-8c6a-663f745cb133','奉和鄜州劉大夫麥秋出師遮虜有懷中朝親故','權德輿','唐','唐诗','tang','','[]','天子愛全才，故人雄外臺。',144,'全唐诗/poet.tang.17000.json','["天子愛全才，故人雄外臺。", "綠油登上將，青綬亞中台。", "亭障鳴笳入，風雲轉斾來。", "蘭坊分杳杳，麥壠望莓莓。", "月向琱弓滿，蓮依寶劒開。", "行師齊鶴列，錫馬盡龍媒。", "壯志徵梁甫，嘉招萃楚材。", "千尋推直幹，百鍊去纖埃。", "間闊勞相望，歡言幸早陪。", "每聯花下騎，幾泛竹間杯。", "芳訊雙魚遠，流年兩鬢催。", "何時介圭覲，攜手詠康哉。"]'),
('5ec3cb79-610a-41c8-ac87-601a64b29d72','太原鄭尚書遠寄新詩走筆酬贈因代書賀','權德輿','唐','唐诗','tang','','[]','曉開閶闔出絲言，共喜全才鎮北門。',192,'全唐诗/poet.tang.17000.json','["曉開閶闔出絲言，共喜全才鎮北門。", "職重油幢推上略，榮兼革履見深恩。", "昔歲經過同二仲，登朝並命慙無用。", "曲臺分季奉齋祠，直筆繫年陪侍從。", "芬芳雞舌向南宮，伏奏丹墀跡又同。", "公望數承黃紙詔，虛懷自號白雲翁。", "戎裝躞蹀紛出祖，金印煌煌寵司武。", "時看介士閱犀渠，每狎儒生冠章甫。", "晉祠汾水古幷州，千騎雙旌居上頭。", "新握兵符應感激，遠緘詩句更風流。", "緇衣諸侯諒稱美，白衣尚書何可比。", "只今麟閣待丹青，努力加餐報天子。"]'),
('3fcbc9fd-9c0f-4ecd-a97b-0a996f02acb7','奉和許閣老酬淮南崔十七端公見寄','權德輿','唐','唐诗','tang','','[]','文行蘊良圖，聲華挹大巫。',288,'全唐诗/poet.tang.17000.json','["文行蘊良圖，聲華挹大巫。", "掄才超粉署，駮議在黃樞。", "自得環中辨，偏推席上儒。", "八音諧雅樂，六轡騁康衢。", "密侍仝鏘珮，雄才本棄繻。", "爐煙霏瑣闥，宮漏滴銅壺。", "舊友雙魚至，新文六義敷。", "斷金揮麗藻，比玉詠生芻。", "交辟嘗推重，單辭忽受誣。", "風波疲賈誼，岐路泣楊朱。", "溟漲前程險，炎荒旅夢孤。", "空悲鳶跕水，翻羨鴈銜蘆。", "故國方迢遰，羈愁自鬱紆。", "遠猷來象魏，霈澤過番禺。", "盡室扁舟客，還家萬里途。", "索居因仕宦，著論擬潛夫。", "帆席來應駛，郊園半已蕪。", "夕陽尋古逕，涼吹動纖枯。", "憶昔同驅傳，忘懷或據梧。", "幕庭依古剎，緡稅給中都。", "瓜步經過慣，龍沙眺聽殊。", "春山嵐漠漠，秋渚露塗塗。", "孰謂原思病，非關甯武愚。", "方看簪獬豸，俄歎縶騊駼。"]'),
('b4be0f59-bf02-4900-a8e2-6bba2e0f9cd8','奉和李給事省中書情寄劉苗崔三曹長因呈許陳二閣老','權德輿','唐','唐诗','tang','','[]','常寮幾處伏明光，新詔聯翩夕拜郎。',64,'全唐诗/poet.tang.17000.json','["常寮幾處伏明光，新詔聯翩夕拜郎。", "五夜漏清天欲曙，萬年枝暖日初長。", "分曹列侍登文石，促膝閑謠接羽觴。", "共說漢朝榮上賞，豈令三友滯馮唐。"]'),
('b25f5fac-fce1-471d-bf7a-3de59c7a6337','過張監閣老宅對酒奉酬見贈','權德輿','唐','唐诗','tang','','[]','里仁無外事，徐步一開顏。',48,'全唐诗/poet.tang.17000.json','["里仁無外事，徐步一開顏。", "荆玉收難盡，齊竽喜暫閑。", "秋風傾菊酒，霽景下蓬山。", "不用投車轄，甘從倒載還。"]'),
('2aabe1f5-d767-4f15-b802-18717c5bfb86','奉和張舍人閣老閣中直夜思聞雅琴因以書事通簡僚友','權德輿','唐','唐诗','tang','','[]','紫垣宿清夜，藹藹復沈沈。',72,'全唐诗/poet.tang.17000.json','["紫垣宿清夜，藹藹復沈沈。", "圓月衡漢淨，好風松滌深。", "軒窗韻虛籟，蘭雪懷幽音。", "珠露銷暑氣，玉徽結遐心。", "盛才本殊倫，雅誥方在今。", "佇見舒彩翮，翻飛歸鳳林。"]'),
('7e511cab-22be-4eaf-bb9e-13bdccd5a8d7','和兵部李尚書東亭詩','權德輿','唐','唐诗','tang','','[]','三接履聲退，東亭斯曠然。',48,'全唐诗/poet.tang.17000.json','["三接履聲退，東亭斯曠然。", "風流披鶴氅，操割佩龍泉。", "雲卷巖巘疊，雨餘松桂鮮。", "豈煩禽尚遊，所貴天理全。"]'),
('adf0c2fc-4c31-4f42-9a62-08d58d8ac0e0','和司門殷員外早秋省中書直夜寄荆南衛象端公','權德輿','唐','唐诗','tang','','[]','共嗟王粲滯荆州，才子爲郎憶舊遊。',64,'全唐诗/poet.tang.17000.json','["共嗟王粲滯荆州，才子爲郎憶舊遊。", "涼夜偏宜粉署直，清言遠待玉人酬。", "風生北渚煙波闊，露下南宮星漢秋。", "早晚得爲同舍侶，知君兩地結離憂。"]'),
('f03f7085-be14-4c97-b540-77f2e8fa5811','酬陸三十二參浙東見寄','權德輿','唐','唐诗','tang','','[]','驄馬別已久，鯉魚來自烹。',48,'全唐诗/poet.tang.17000.json','["驄馬別已久，鯉魚來自烹。", "殷懃故人意，怊悵中林情。", "茫茫重江外，杳杳一枝瓊。", "搔首望良覿，爲君華髮生。"]'),
('4ca9a7ec-615d-40a3-8bb4-bb3a0e4dc79e','奉酬張監閣老雪後過中書見贈加兩韻簡南省僚舊','權德輿','唐','唐诗','tang','','[]','寓直久叨榮，新恩倍若驚。',72,'全唐诗/poet.tang.17000.json','["寓直久叨榮，新恩倍若驚。", "風清五夜永，節換一陽生。", "潘鬢年空長，齊竽藝本輕。", "常時望連茹，今日劇懸旌。", "枉步歡方接，含毫思又縈。", "煩君白雪句，歲晏若爲情。"]'),
('3fe10fdc-cd5e-4562-a7b2-2f6361695fa9','酬主客仲員外見賀正除','權德輿','唐','唐诗','tang','','[]','五年承乏奉如綸，才薄那堪侍從臣。',64,'全唐诗/poet.tang.17000.json','["五年承乏奉如綸，才薄那堪侍從臣。", "禁署獨聞清漏曉，命書慙對紫泥新。", "周班每喜簪裾接，郢曲偏宜諷詠頻。", "憶昔曲臺嘗議禮，見君論著最相親。"]'),
('87bc3c81-8852-4d74-9a63-965bec0fd17b','奉和太府韋卿閣老左藏庫中假山之作','權德輿','唐','唐诗','tang','','[]','春山仙掌百花開，九棘腰金有上才。',64,'全唐诗/poet.tang.17000.json','["春山仙掌百花開，九棘腰金有上才。", "忽向庭中摹峻極，如從洞裏見昭回。", "小松已負干霄狀，片石皆疑縮地來。", "都內今朝似方外，仍傳麗曲寄雲臺。"]'),
('2f69baba-03d2-488d-b585-db29502e5d1c','奉和崔評事寄外甥劉同州幷呈杜賓客許給事王侍郎昆弟楊少尹李侍御幷見寄之作','權德輿','唐','唐诗','tang','','[]','芳訊來江湖，開緘粲瑤碧。',168,'全唐诗/poet.tang.17000.json','["芳訊來江湖，開緘粲瑤碧。", "詩因乘黃贈，才擅雕龍格。", "深陳名敎本，諒以仁義積。", "藻思成采章，雅音聞皦繹。", "清時左馮翊，貴士二千石。", "前日應星文，今茲敞華戟。", "謝公嘗乞墅，甯氏終相宅。", "往歲疲草玄，忘年齊舉白。", "酒酣吟更苦，夜艾談方劇。", "棗巷風雨秋，石頭煙水夕。", "多逢長者轍，不屑諸公辟。", "酷似仰牢之，雄詞挹亭伯。", "老驥念千里，飢鷹舒六翮。", "叵能捨郊扉，來偶朝中客。"]'),
('f10668fa-ca18-4fa7-92ff-d0cb7bdc2798','和職方殷郎中留滯江漢初至南宮呈諸公幷見寄','權德輿','唐','唐诗','tang','','[]','十載別文昌，藩符寄武當。',48,'全唐诗/poet.tang.17000.json','["十載別文昌，藩符寄武當。", "師貞上介辟，恩擢正員郎。", "藻思煙霞麗，歸軒印綬光。", "還希駐輦問，莫自嘆馮唐。"]'),
('8dff86ea-eb2f-42d3-8337-c68572d2f3c3','奉酬從兄南仲見示十九韻','權德輿','唐','唐诗','tang','','[]','晉季天下亂，安丘佐關中。',228,'全唐诗/poet.tang.17000.json','["晉季天下亂，安丘佐關中。", "德輝靄家牒，侯籍推時功。", "簪纓盛西州，清白傳素風。", "逢時有舒卷，繕性無窮通。", "吾兄挺奇資，向晦道自充。", "耕鑿汝山下，退然安困蒙。", "詩成三百篇，儒有一畝宮。", "琴書滿座右，芝朮生牆東。", "麗藻粲相鮮，晨輝豔芳叢。", "清光杳無際，皓魄流霜空。", "邦有賢諸侯，主盟詞律雄。", "薦賢比文舉，理郡邁文翁。", "樓中賞不獨，池畔醉每同。", "聖朝闢四門，發跡貴名公。", "小生何爲者，往歲學雕蟲。", "華簪映武弁，一年被微躬。", "開緘捧新詩，瓊玉寒青葱。", "謬進空內訟，結懷遠忡忡。", "時來無自疑，刷翮摩蒼穹。"]'),
('41eabf19-587b-48be-ab2d-d3eef3fa6b9c','酬崔千牛四郎早秋見寄','權德輿','唐','唐诗','tang','','[]','浩歌坐虛室，庭樹生涼風。',132,'全唐诗/poet.tang.17000.json','["浩歌坐虛室，庭樹生涼風。", "碧雲滅奇彩，白露萎芳叢。", "感此時物變，悠然遐想通。", "偶來被簪組，自覺如池龍。", "少年才藻新，金鼎世業崇。", "鳳文已彪炳，瓊樹何青蔥。", "聯鑣長安道，接武承明宮。", "君登玉墀上，我侍彤庭中。", "疲病多內愧，切磋常見同。", "起予覽新詩，逸韻凌秋空。", "相愛每不足，因茲寓深衷。"]'),
('28667b89-30c5-4ddf-af7f-f3acaec11dbc','酬靈徹上人以詩代書見寄','權德輿','唐','唐诗','tang','','[]','蓮花出水地無塵，中有南宗了義人。',64,'全唐诗/poet.tang.17000.json','["蓮花出水地無塵，中有南宗了義人。", "已取貝多翻半字，還將陽燄諭三身。", "碧雲飛處詩偏麗，白月圓時信本真。", "更喜開緘銷熱惱，西方社裏舊相親。"]'),
('47c3e3e3-d13c-4562-a582-caee84ee60f5','酬蔡十二博士見寄四韻','權德輿','唐','唐诗','tang','','[]','蕪城十年別，蓬轉居不足。',48,'全唐诗/poet.tang.17000.json','["蕪城十年別，蓬轉居不足。", "終歲白屋貧，獨謠清酒聖。", "風塵韋帶減，霜雪松心勁。", "何以浣相思，啓元能盡性。"]'),
('dc256848-2b70-483c-9247-71f44b705772','戲和三韻','權德輿','唐','唐诗','tang','','[]','墨翟突不黔，范丹甑生塵。',36,'全唐诗/poet.tang.17000.json','["墨翟突不黔，范丹甑生塵。", "君今復勞歌，鶴髮吹濕薪。", "前詔許真秩，何如巾軟輪。"]'),
('95325255-c38d-4a92-89ac-39205e88a187','李十韶州寄途中絕句使者取報修書之際口號酬贈','權德輿','唐','唐诗','tang','','[]','詔下忽臨山水郡，不妨從事恣攀登。',32,'全唐诗/poet.tang.17000.json','["詔下忽臨山水郡，不妨從事恣攀登。", "莫言向北千行鴈，別有圖南六月鵬。"]'),
('6e0958c1-07da-4a0e-9d69-9e7ff90b42c0','崔四郎協律以詩見寄兼惠蜀琴因以酬贈','權德輿','唐','唐诗','tang','','[]','臨風結煩想，客至傳好音。',48,'全唐诗/poet.tang.17000.json','["臨風結煩想，客至傳好音。", "白雪緘郢曲，朱弦亘蜀琴。", "泠泠響幽韻，欵欵寄遐心。", "歲晚何以報，與君期斷金。"]'),
('f17b3820-4da8-4199-a31b-1cb09d6b1cf9','酬馮絳州早秋絳臺感懷見寄','權德輿','唐','唐诗','tang','','[]','良牧閑無事，層臺思眇然。',120,'全唐诗/poet.tang.17000.json','["良牧閑無事，層臺思眇然。", "六條縈印綬，三晉辨山川。", "洗嫧謳謠合，開襟眺聽偏。", "秋光連大鹵，霽景下新田。", "葉落徑庭樹，人歸曲沃煙。", "武符頒美化，亥字訪疑年。", "經術推多識，卿曹亦累遷。", "齋祠常並冕，官品每差肩。", "按部青絲騎，裁詩白露天。", "知音媿相訪，商洛正閑眠。"]'),
('b3670d47-5a12-4688-84ed-0eb055ad95a7','酬趙尚書杏園花下醉後見寄','權德輿','唐','唐诗','tang','','[]','春光深處曲江西，八座風流信馬蹄。',32,'全唐诗/poet.tang.17000.json','["春光深處曲江西，八座風流信馬蹄。", "鶴髮杏花相映好，羨君終日醉如泥。"]'),
('cce2d4e2-5c21-4319-9b7e-10174f10519d','酬趙尚書城南看花日晚先歸見寄','權德輿','唐','唐诗','tang','','[]','杜城韋曲徧尋春，處處繁花滿目新。',32,'全唐诗/poet.tang.17000.json','["杜城韋曲徧尋春，處處繁花滿目新。", "日暮歸鞍不相待，與君同是醉鄉人。"]'),
('fd796b81-4dd2-4b56-8e43-87482b366545','伏蒙十六叔寄示喜慶感懷三十韻因獻之','權德輿','唐','唐诗','tang','','[]','受氏自有殷，樹功緬前秦。',288,'全唐诗/poet.tang.17000.json','["受氏自有殷，樹功緬前秦。", "圭田接土宇，侯籍相紛綸。", "道義集天爵，菁華極人文。", "握蘭中臺並，折桂東堂春。", "祖德蹈前哲，家風播清芬。", "先公秉明義，大節逢艱屯。", "獨立挺忠孝，至誠感神人。", "命書備追錫，跡遠道不伸。", "小生諒無似，積慶遭昌辰。", "九年西掖忝，五轉南宮頻。", "司理因曠職，曲臺仍禮神。", "愧非夔龍姿，忽佐堯舜君。", "內惟負且乘，徒以弱似仁。", "豈足議大政，所憂玷彝倫。", "叔父貞素履，含章窮典墳。", "百氏若珠貫，九流皆翬分。", "黃鍾蘊聲調，白玉那緇磷。", "清論坐虛室，長謠宜幅巾。", "開關接人祠，支策無俗賓。", "種杏當暑熱，烹茶含露新。", "井徑交碧蘚，軒窗棲白雲。", "飛沈禽魚樂，芬馥蘭桂薰。", "經術弘義訓，息男茂嘉聞。", "筮仕就色養，宴居忘食貧。"]'),
('6dcc533e-01af-48f9-835f-47f087bc81c7','酬李二十二兄主簿馬跡山見寄','權德輿','唐','唐诗','tang','','[]','杳杳塵外想，悠悠區中緣。',242,'全唐诗/poet.tang.17000.json','["杳杳塵外想，悠悠區中緣。", "如何戰未勝，曾是敎所牽。", "遠郊有靈峯，夙昔棲真仙。", "鸞聲去已久，馬跡空依然。", "丹崖轉初旭，碧落凝秋煙。", "松風共簫颯，蘿月想嬋娟。", "內兄蘊遐心，嘉遯性所便。", "不能棲枳棘，且復探雲泉。", "中有冥寂人，閑讀逍遙篇。", "聯袂共支[策]，摳衣賞絕編。", "徐行石上苔，靜韻風中弦。", "煙霞濕儒服，日月生寥天。", "新詩來起予，璀璨六義全。", "能盡含寫意，轉令山水鮮。", "若聞笙鶴聲，宛在耳目前。", "登攀阻心賞，愁絕空懷賢。", "出處豈異途，心冥即真筌。", "蹔從西府檄，終臥東菑田。", "不嫌予步蹇，但恐君行羶。", "如能固曠懷，谷口期窮年。"]'),
('49a4939a-31cb-47d3-a21e-e320c1609993','酬陸四十楚源春夜宿虎丘山對月寄梁四敬之兼見貽之作','權德輿','唐','唐诗','tang','','[]','東風變[蘅]薄，時景日妍和。',242,'全唐诗/poet.tang.17000.json','["東風變[蘅]薄，時景日妍和。", "更想千峯夜，浩然幽意多。", "蕙香襲閑趾，松露泫喬柯。", "潭影漾霞月，石牀封薜蘿。", "夫君非歲時，已負青冥姿。", "龍虎一門盛，淵雲四海推。", "駸駸步騕褭，婉婉翥長離。", "懸圃盡瓊樹，家林輕桂枝。", "聲榮徒外獎，恬淡方自適。", "逸氣凌顥清，仁祠訪金碧。", "芊眠瑤草秀，斷續雲竇滴。", "芳訊發幽緘，新詩比良覿。", "故人石渠署，美價滿中朝。", "落落杉松直，芬芬蘭杜飄。", "雄詞鼓溟海，曠達豁煙霄。", "營道幸同術，論心皆後凋。", "循環伐木詠，緬邈招隱情。", "慙茲擁腫才，愛彼潺湲清。", "拘牽尚多故，夢想何由幷。", "終結方外期，不待華髮生。"]'),
('14cdc107-6f24-4576-87fd-34160b594b09','酬穆七侍郎早登使院西樓感懷','權德輿','唐','唐诗','tang','','[]','耿耿宵欲半，振衣庭戶前。',240,'全唐诗/poet.tang.17000.json','["耿耿宵欲半，振衣庭戶前。", "浩歌撫長劒，臨風泛清弦。", "晴霜麗寒蕪，微月露碧鮮。", "杉梧韻幽籟，河漢明秋天。", "良夜雖可翫，沈憂逾浩然。", "樓中遲啓明，林際揮宿煙。", "晨風響鐘鼓，曙色映山川。", "滔滔天外駛，杲杲朝日懸。", "因窮西南永，得見天地全。", "動植相糺紛，車從競喧闐。", "鱣鮪躍洪流，麕麚倚荒阡。", "嗈嗈白雲鴈，嘒嘒清露蟬。", "一氣鼓萬殊，晦明相推遷。", "羲和無停鞅，不得常少年。", "當令志氣神，及此鬢髮玄。", "豈唯十六族，今古稱其賢。", "夫君才氣雄，振藻何翩翩。", "詩輕沈隱侯，賦擬王仲宣。", "小鳥搶榆枋，大鵬激三千。", "與君期晚歲，方結林棲緣。"]'),
('4b30e21a-0482-42e4-b8bb-75865ef3b787','奉和李大夫題鄭評事江樓','權德輿','唐','唐诗','tang','','[]','達士無外累，隱几依南郭。',120,'全唐诗/poet.tang.17000.json','["達士無外累，隱几依南郭。", "茅棟上江開，布帆當砌落。", "支頤散華髮，欹枕曝靈藥。", "入鳥不亂行，觀魚還自樂。", "何時金馬詔，早歲建安作。", "往事盡筌蹄，虛懷寄杯杓。", "邦君駐千騎，清論時間酌。", "憑檻出煙埃，振衣向寥廓。", "心源齊彼是，人境勝巖壑。", "何必栖冥冥，然爲避矰繳。"]'),
('1015196d-d1bc-4d98-89a5-a53328a3ddb7','春遊茅山酬杜評事見寄','權德輿','唐','唐诗','tang','','[]','喜得賞心處，春山豈計程。',48,'全唐诗/poet.tang.17000.json','["喜得賞心處，春山豈計程。", "連溪芳草合，半嶺白雲晴。", "絕澗漱冰碧，仙壇挹顥清。", "懷君在人境，不共此時情。"]'),
('644f3188-fc89-45d4-94a4-6df041708e61','和韓侍御白髮','權德輿','唐','唐诗','tang','','[]','白髮今朝見，虛齋曉鏡清。',48,'全唐诗/poet.tang.17000.json','["白髮今朝見，虛齋曉鏡清。", "乍分霜簡色，微映鐵冠生。", "幕下多能事，周行挹令名。", "流年未可歎，正遇太階平。"]'),
('2c4301ad-433e-4016-8db8-2e1d0c83b019','和邵端公醉後寄于諫議之作','權德輿','唐','唐诗','tang','','[]','莫羨簷前柳，春風獨早歸。',24,'全唐诗/poet.tang.17000.json','["莫羨簷前柳，春風獨早歸。", "陽和次第發，桃李更芳菲。"]'),
('709e3d66-2471-412f-98e4-4d9b0c76c91a','和李大夫西山祈雨因感張曲江故事十韻','權德輿','唐','唐诗','tang','','[]','亞相冠貂蟬，分憂統十聯。',120,'全唐诗/poet.tang.17000.json','["亞相冠貂蟬，分憂統十聯。", "火星當永日，雲漢倬炎天。", "齋禱期靈貺，精誠契昔賢。", "中宵出騶馭，清夜旅牲牷。", "觸日看初起，隨車應物先。", "雷音生絕巘，雨足晦平阡。", "瀟灑四冥合，空濛萬頃連。", "歌謠諠澤國，稼穡徧原田。", "故事三台盛，新文六義全。", "作霖應自此，天下待豐年。"]'),
('97e1c3a8-79a1-4b90-9516-54b1a18f4378','同陸太祝鴻漸崔法曹載華見蕭侍御留後說得衛撫州報推事使張侍御却迴前刺史戴員外無事喜而有作三首 一','權德輿','唐','唐诗','tang','','[]','專城書素至留臺，忽報張綱攬轡迴。',32,'全唐诗/poet.tang.17000.json','["專城書素至留臺，忽報張綱攬轡迴。", "共看昨日蠅飛處，併是今朝鵲喜來。"]'),
('5bada341-45a3-4536-8416-cab621e24674','同陸太祝鴻漸崔法曹載華見蕭侍御留後說得衛撫州報推事使張侍御却迴前刺史戴員外無事喜而有作三首 二','權德輿','唐','唐诗','tang','','[]','鶴髮州民擁使車，人人自說受恩初。',32,'全唐诗/poet.tang.17000.json','["鶴髮州民擁使車，人人自說受恩初。", "如今天下無冤氣，乞爲邦君雪謗書。"]'),
('6cd3d0f4-be9d-4fb8-8180-12cc07e4a3dd','同陸太祝鴻漸崔法曹載華見蕭侍御留後說得衛撫州報推事使張侍御却迴前刺史戴員外無事喜而有作三首 三','權德輿','唐','唐诗','tang','','[]','衆人哺啜喜君醒，渭水由來不雜涇。',32,'全唐诗/poet.tang.17000.json','["衆人哺啜喜君醒，渭水由來不雜涇。", "遮莫雪霜撩亂下，松枝竹葉自青青。"]'),
('9a962466-d078-403c-b2a4-a1aaaeca2ebc','荅韋秀才寄一首','權德輿','唐','唐诗','tang','','[]','中峯雲暗雨霏霏，水漲花塘未得歸。',32,'全唐诗/poet.tang.17000.json','["中峯雲暗雨霏霏，水漲花塘未得歸。", "心憶瓊枝望不見，幾迴虛濕薜蘿衣。"]'),
('bb916e9b-62ff-4906-b776-6d90690c684a','戶部王曹長楊考功崔刑部二院長並同鍾陵使府之舊因以寄贈又陪郎署喜甚常僚因書所懷且敘所知','權德輿','唐','唐诗','tang','','[]','忽驚西江侶，共作南宮郎。',264,'全唐诗/poet.tang.17000.json','["忽驚西江侶，共作南宮郎。", "宿昔芝蘭室，今茲鴛鷺行。", "子猷美風味，左戶推公器。", "含毫白雪飛，出匣青萍利。", "子雲嘗燕居，作賦似相如。", "閑成考課奏，別貢賢良書。", "子玉諒貞實，持刑慎丹筆。", "秋天鴻鵠姿，晚歲松筠質。", "伊予誠薄才，何幸復趨陪。", "偶來塵右掖，空此憶中臺。", "時節東流駛，悲歡追往事。", "待月登庾樓，排雲上蕭寺。", "盍簪蓮府讌，落帽龍沙醉。", "極浦送風帆，靈山眺煙翠。", "解頤通善謔，喻指窮精義。", "搦管或飛章，分曹時按吏。", "雨散與蓬飄，秦吳兩寂寥。", "方期全擁腫，豈望躡扶搖。", "夜直分三署，晨趨共九霄。", "外庭時接武，廣陌更連鑣。", "北極星辰拱，南薰氣序調。", "欣隨衆君子，並立聖明朝。"]'),
('e984c0b1-e3c0-47d1-a612-0ed51d47dabb','貢院對雪以絕句代八行奉寄崔閣老','權德輿','唐','唐诗','tang','','[]','寓宿春闈歲欲除，嚴風密雪絕雙魚。',32,'全唐诗/poet.tang.17000.json','["寓宿春闈歲欲除，嚴風密雪絕雙魚。", "思君獨步西垣裏，日日含香草詔書。"]'),
('5d294e60-8a47-47de-83c1-46008d6b2444','初秋月夜中書宿直因呈楊閣老','權德輿','唐','唐诗','tang','','[]','欹枕直廬暇，風蟬迎早秋。',48,'全唐诗/poet.tang.17000.json','["欹枕直廬暇，風蟬迎早秋。", "沈沈玉堂夕，皎皎金波流。", "對掌喜新命，分曹諧舊遊。", "相思翫華彩，因感庾公樓。"]'),
('1fe021dd-c5cf-4e34-a60a-ac5a86ee18f9','唐開州文編遠寄新賦累惠良藥詠嘆仰佩不覺斐然走筆代書聊書還荅','權德輿','唐','唐诗','tang','','[]','風雨竦庭柯，端憂坐空堂。',240,'全唐诗/poet.tang.17000.json','["風雨竦庭柯，端憂坐空堂。", "多病時節換，所思道里長。", "故人朱兩轓，出自尚書郎。", "下車今幾時，理行遠芬芳。", "瓊瑤覽良訊，芣苢滿素囊。", "結根在貴州，蠲疾傳古方。", "探擷當五月，慇懃逾八行。", "深情婉如此，善祝何可忘。", "復有金玉音，煥如龍鳳章。", "一聞靈洞說，若覩羣仙翔。", "三清飛慶霄，百汰成雄鋩。", "體物信無對，灑心願相將。", "昔年同旅食，終日窺文房。", "春風眺蕪城，秋水渡柳楊。", "君爲太史氏，弱質羈楚鄉。", "今來忝司諫，千騎遙相望。", "歸雲夕鱗鱗，圓魄夜蒼蒼。", "遠思結鈴閣，何人交羽觴。", "佇見徵穎川，無爲薄淮陽。", "政成看再入，列侍爐煙傍。"]'),
('3322ec4b-bc6b-4cfa-8fd6-a414edba0e26','待漏假寐夢歸江東舊居','權德輿','唐','唐诗','tang','','[]','十年江浦臥郊園，閑夜分明結夢魂。',64,'全唐诗/poet.tang.17000.json','["十年江浦臥郊園，閑夜分明結夢魂。", "舍下煙蘿通古寺，湖中雲雨到前軒。", "南宗長老知心法，東郭先生識化源。", "覺後忽聞清漏曉，又隨簪珮入君門。"]'),
('56efb3a0-a352-47bc-bdb0-f42d989b6bb1','祗命赴京途次淮口因書所懷','權德輿','唐','唐诗','tang','','[]','弱植素寡偶，趨時非所任。',120,'全唐诗/poet.tang.17000.json','["弱植素寡偶，趨時非所任。", "感恩再登龍，求友皆斷金。", "彪炳覩奇采，淒鏘聞雅音。", "適欣佳期接，遽嘆離思侵。", "靡靡遵遠道，忡忡勞寸心。", "難成獨酌謠，空奏伐木吟。", "泬寥清冬時，蕭索白晝陰。", "交歡諒如昨，滯念紛在今。", "因風試矯翼，倦飛會歸林。", "向晚清淮駛，回首楚雲深。"]'),
('dcc7fec6-a616-49b3-8a99-c1b47b8166cc','省中春晚忽憶江南舊居戲書所懷因寄兩浙親故雜言','權德輿','唐','唐诗','tang','','[]','前年冠獬豸，戎府隨賓介。',168,'全唐诗/poet.tang.17000.json','["前年冠獬豸，戎府隨賓介。", "去年簪進賢，贊導法宮前。", "今茲戴武弁，謬列金門彥。", "問我何所能，頭冠忽三變。", "野性慣疎閑，晨趨興暮還。", "花時限清禁，霽後愛南山。", "晚景支頤對尊酒，舊遊憶在江湖久。", "庾樓柳寺共開襟，楓岸煙塘幾攜手。", "結廬常占練湖春，猶寄藜牀與幅巾。", "疲羸只欲思三徑，戇直那堪備七人。", "更想東南多竹箭，懸圃琅玕共蔥蒨。", "裁書且附雙鯉魚，偏恨相思未相見。"]'),
('7d2712ba-cd12-413f-ba59-81123b59361a','寄李衡州','權德輿','唐','唐诗','tang','','[]','片石叢花畫不如，庇身三逕豈吾廬。',32,'全唐诗/poet.tang.17000.json','["片石叢花畫不如，庇身三逕豈吾廬。", "主人千騎東方遠，唯望衡陽鴈足書。"]'),
('83b0088c-2d7e-43e9-898d-737fa18a2602','寄臨海郡崔穉璋','權德輿','唐','唐诗','tang','','[]','美酒步兵廚，古人嘗宦遊。',72,'全唐诗/poet.tang.17000.json','["美酒步兵廚，古人嘗宦遊。", "赤城臨海嶠，君子今督郵。", "吏隱豐暇日，琴壺共冥搜。", "新詩寒玉韻，曠思孤雲秋。", "志士誠勇退，鄙夫自包羞。", "終當就知己，莫戀潺湲流。"]'),
('82cd7a23-37ac-4ed1-8130-4b6bee62d86b','李韶州著書常論釋氏之理貴州有能公遺跡詩以問之','權德輿','唐','唐诗','tang','','[]','常日區中暇，時聞象外言。',24,'全唐诗/poet.tang.17000.json','["常日區中暇，時聞象外言。", "曹溪有宗旨，一爲勘心源。"]'),
('e472ec64-b9ac-4d19-b5c1-179623bddbda','馬上贈虛公','權德輿','唐','唐诗','tang','','[]','馬足早塵深，飄纓又滿襟。',24,'全唐诗/poet.tang.17000.json','["馬足早塵深，飄纓又滿襟。", "吾師有甘露，爲洗此時心。"]'),
('ac3d4310-b07b-49fc-aaf3-b2afbf162a21','郴州換印緘遣之際率成三韻因寄李二兄員外使君','權德輿','唐','唐诗','tang','','[]','緘題桂陽印，持寄朗陵兄。',36,'全唐诗/poet.tang.17000.json','["緘題桂陽印，持寄朗陵兄。", "刺舉官猶屈，風謠政已成。", "行看換龜紐，奏最謁承明。"]'),
('d74688ac-a691-4410-a3cb-b79279450247','早發杭州泛富春江寄陸三十一公佐','權德輿','唐','唐诗','tang','','[]','候曉起徒馭，春江多好風。',120,'全唐诗/poet.tang.17000.json','["候曉起徒馭，春江多好風。", "白波連青雲，蕩漾晨光中。", "四望浩無際，沈憂將此同。", "未離奔走途，但恐成悲翁。", "俯見觸餌鱗，仰目淩霄鴻。", "纓塵日已厚，心累何時空。", "區區此人世，所向皆樊籠。", "唯應杯中物，醒醉爲窮通。", "故人懸圃姿，瓊樹紛青葱。", "終當此山去，共結蘭桂叢。"]'),
('560496ff-d961-4957-87e7-fa2b987fdb90','寄侍御從舅','權德輿','唐','唐诗','tang','','[]','靡靡南軒蕙，迎風轉芳滋。',98,'全唐诗/poet.tang.17000.json','["靡靡南軒蕙，迎風轉芳滋。", "落落幽澗松，百尺無附枝。", "世物自多故，達人心不羈。", "偶陳幕中畫，未負林間期。", "感恩從慰薦，循性難縶維。", "野鶴無俗質，孤雲多異姿。", "清[泠]松露泫，照灼巖花遲。", "終當稅塵駕，來就東山嬉。"]'),
('7e5b890a-e39b-4e7d-9d1f-b4d791e63274','湖上晚眺呈惠上人','權德輿','唐','唐诗','tang','','[]','湖上煙景好，鳥飛雲自還。',48,'全唐诗/poet.tang.17000.json','["湖上煙景好，鳥飛雲自還。", "幸因居止近，日覺性情閑。", "獨酌乍臨水，清機常見山。", "此時何所憶，淨侶話玄關。"]'),
('5aaa1ffc-68a1-465c-9825-9ced147d9631','新秋月夜寄故人','權德輿','唐','唐诗','tang','','[]','客心宜靜夜，月色澹新秋。',48,'全唐诗/poet.tang.17000.json','["客心宜靜夜，月色澹新秋。", "影落三湘水，詩傳八詠樓。", "何窮對酒望，幾處捲簾愁。", "若問相思意，隨君萬里遊。"]'),
('4d173a7c-df62-4a18-9e4d-3a1b905aac05','自楊子歸丹陽初遂閑居聊呈惠公','權德輿','唐','唐诗','tang','','[]','移疾喜無事，卷簾松竹寒。',48,'全唐诗/poet.tang.17000.json','["移疾喜無事，卷簾松竹寒。", "稍知名是累，日與靜相歡。", "蹇淺逢機少，迂疎應物難。", "只思閑夜月，共向沃州看。"]'),
('ac702011-08e5-41d5-9fdd-a89ff50501cc','月夜過靈徹上人房因贈','權德輿','唐','唐诗','tang','','[]','此身會逐白雲去，未洗塵纓還自傷。',32,'全唐诗/poet.tang.17000.json','["此身會逐白雲去，未洗塵纓還自傷。", "今夜幸逢清淨境，滿庭秋月對支郎。"]'),
('8f5beb73-918d-41e2-a864-05145271987d','戲贈張鍊師','權德輿','唐','唐诗','tang','','[]','月帔飄颻摘杏花，相邀洞口勸流霞。',32,'全唐诗/poet.tang.17000.json','["月帔飄颻摘杏花，相邀洞口勸流霞。", "半酣乍奏雲和曲，疑是龜山阿母家。"]'),
('8f505e12-13f0-4620-84aa-dac177d6c9d9','戲贈天竺靈隱二寺寺主','權德輿','唐','唐诗','tang','','[]','石路泉流兩寺分，尋常鐘磬隔山聞。',32,'全唐诗/poet.tang.17000.json','["石路泉流兩寺分，尋常鐘磬隔山聞。", "山僧半在中峰住，共占青巒與白雲。"]'),
('a3211c47-06df-4ac9-a7fb-1a36bc88ea8a','贈廣通上人','權德輿','唐','唐诗','tang','','[]','身隨猨鳥在深山，早有詩名到世間。',32,'全唐诗/poet.tang.17000.json','["身隨猨鳥在深山，早有詩名到世間。", "客至上方留盥漱，龍泓洞水晝潺潺。"]'),
('5fc10515-12d3-4cd8-8d2f-bf77179b2e1c','贈老將','權德輿','唐','唐诗','tang','','[]','白草黃雲塞上秋，曾隨驃騎出幷州。',32,'全唐诗/poet.tang.17000.json','["白草黃雲塞上秋，曾隨驃騎出幷州。", "轆轤劒折虬鬚白，轉戰功多獨不侯。"]'),
('6346fd58-f617-41e0-839e-abcdc09fffd0','戲贈表兄崔秀才','權德輿','唐','唐诗','tang','','[]','何事年年戀隱淪，成名須遣及青春。',32,'全唐诗/poet.tang.17000.json','["何事年年戀隱淪，成名須遣及青春。", "明時早獻甘泉去，若待公車却誤人。"]'),
('561a71fb-ee67-4894-a69c-209de8cfb222','醉後戲贈蘇九翛','權德輿','唐','唐诗','tang','','[]','白首書窗成鉅儒，不知簪組徧屠沽。',32,'全唐诗/poet.tang.17000.json','["白首書窗成鉅儒，不知簪組徧屠沽。", "勸君莫問長安路，且讀魯山于蔿于。"]'),
('d0459c0c-e0ed-47c3-86fd-f741f2e27865','奉送韋起居老舅百日假滿歸嵩陽舊居','權德輿','唐','唐诗','tang','','[]','威鳳翔紫氣，孤雲出寥天。',192,'全唐诗/poet.tang.17000.json','["威鳳翔紫氣，孤雲出寥天。", "奇采與幽姿，縹緲皆自然。", "嘗聞陶唐氏，亦有巢由全。", "以此聳風俗，豈必效羈牽。", "大君遂羣方，左史蹈前賢。", "振衣去朝市，賜告歸林泉。", "滑和固難久，循性得所便。", "有名皆畏途，無事乃真筌。", "舊壑窮杳窱，新潭漾淪漣。", "嵓花落又開，山月缺復圓。", "輕策逗蘿逕，幅巾淩翠煙。", "機閑魚鳥狎，體和芝朮鮮。", "四皓本違難，二疏猶待年。", "況今寰海清，復此鬢髮玄。", "顧慙纓上塵，未絕區中緣。", "齊竽終自退，心寄嵩峯巔。"]'),
('455c8a89-ecfb-4097-96b5-705f90d809c1','奉送孔十兄賓客承恩致政歸東都舊居','權德輿','唐','唐诗','tang','','[]','達人曠迹通出處，每憶安居舊山去。',128,'全唐诗/poet.tang.17000.json','["達人曠迹通出處，每憶安居舊山去。", "乞身已見抗疏頻，優禮新聞詔書許。", "家法遙傳闕里訓，心源早逐嵩丘侶。", "南史編年著盛名，東朝侍講常虛佇。", "角巾華髮忽自遂，命服金龜君更與。", "白雲出岫暫逶迤，鴻鵠入冥無處所。", "歸路依依童稚樂，都門藹藹壺觴舉。", "能將此道助皇風，自可殊途並伊呂。"]'),
('7e1ab4f4-8a13-44f1-a85c-4cceaa5c51f1','送密秀才吏部駮放後歸蜀應崔大理序','權德輿','唐','唐诗','tang','','[]','蜀國本多士，雄文似相如。',72,'全唐诗/poet.tang.17000.json','["蜀國本多士，雄文似相如。", "之子西南秀，名在賢能書。", "薄祿且未及，故山念歸歟。", "迢迢三千里，返駕一羸車。", "玉壘長路盡，錦江春物餘。", "此行無慍色，知爾戀林廬。"]'),
('9f6d507f-5fd4-4036-b62f-7c1d800eb64e','送袁中丞持節冊南詔五韻','權德輿','唐','唐诗','tang','','[]','西南使星去，遠徹通朝聘。',60,'全唐诗/poet.tang.17000.json','["西南使星去，遠徹通朝聘。", "煙雨僰道深，麾幢漢儀盛。", "途輕五尺險，水愛雙流淨。", "上國洽恩波，外臣遵禮命。", "離堂駐騶馭，且盡罇中聖。"]'),
('60453e5d-57f7-440f-95e6-53db619b33d6','人日送房二十六侍御歸越','權德輿','唐','唐诗','tang','','[]','驛騎歸時驄馬蹄，蓮花府映若邪溪。',32,'全唐诗/poet.tang.17000.json','["驛騎歸時驄馬蹄，蓮花府映若邪溪。", "帝城人日風光早，不惜離堂醉似泥。"]'),
('50344c05-b6e2-4fe6-af05-659fde2dd5b1','送張閣老中丞持節冊弔回鶻','權德輿','唐','唐诗','tang','','[]','旌斾翩翩擁漢官，君行常得遠人歡。',64,'全唐诗/poet.tang.17000.json','["旌斾翩翩擁漢官，君行常得遠人歡。", "分職南臺知禮重，輟書東觀見才難。", "金章玉節鳴騶遠，白草黃雲出塞寒。", "欲散別離唯有醉，暫煩賓從駐征鞍。"]'),
('7217f799-249f-4b71-a2b9-462d7fb67b64','送二十叔赴任餘杭尉','權德輿','唐','唐诗','tang','','[]','拜首直城陰，罇開意不任。',48,'全唐诗/poet.tang.17000.json','["拜首直城陰，罇開意不任。", "梅仙歸劇縣，阮巷奏離琴。", "春草吳門綠，秋濤浙水深。", "十年曾旅寓，應愜宦遊心。"]'),
('ff15b7d9-2977-4881-9ea4-6fba6a4401d2','春送十四叔赴任渝州錄事絕句','權德輿','唐','唐诗','tang','','[]','隨牒忽離南北巷，解巾都吏有清風。',32,'全唐诗/poet.tang.17000.json','["隨牒忽離南北巷，解巾都吏有清風。", "巴城鏁印六聯靜，盡日閑謠廨署中。"]'),
('752765da-dcb1-4d0b-b30d-3e118048b4a6','送韋十二丈赴襄城令三韻','權德輿','唐','唐诗','tang','','[]','留連出關騎，斟酌臨岐酒。',36,'全唐诗/poet.tang.17000.json','["留連出關騎，斟酌臨岐酒。", "舊業傳一經，新官栽五柳。", "去去望行塵，青門重迴首。"]'),
('c0c801f6-e310-4215-aefa-a1598b261fa4','送薛十九丈授將作主簿分司東都賦得春草','權德輿','唐','唐诗','tang','','[]','芊芊遠郊外，杳杳春嵓曲。',36,'全唐诗/poet.tang.17000.json','["芊芊遠郊外，杳杳春嵓曲。", "愁處映微波，望中連淨綠。", "日暮藉離觴，折芳心斷續。"]'),
('1590cafd-ccbd-4034-873d-9608699a69d7','送正字十九兄歸江東醉後絕句','權德輿','唐','唐诗','tang','','[]','命駕相思不爲名，春風歸騎出關程。',32,'全唐诗/poet.tang.17000.json','["命駕相思不爲名，春風歸騎出關程。", "離堂莫起臨岐歎，文舉終當薦禰衡。"]'),
('81351fe4-8335-432e-99df-a63661e50726','送張詹事致政歸嵩山舊隱','權德輿','唐','唐诗','tang','','[]','解龜辭漢庭，却憶少微星。',72,'全唐诗/poet.tang.17000.json','["解龜辭漢庭，却憶少微星。", "直指常持憲，平反更恤刑。", "閑思紫芝侶，歸臥白雲扃。", "明詔優筋力，安車適性靈。", "羣公來藹藹，獨鶴去冥冥。", "想到揮金處，嵩吟枕上青。"]'),
('b6e789ff-d82d-4a4a-a553-40cd3cf6cce5','送許著作分司東都','權德輿','唐','唐诗','tang','','[]','月旦繼平輿，風流仕石渠。',60,'全唐诗/poet.tang.17000.json','["月旦繼平輿，風流仕石渠。", "分曹向瀍洛，守職正圖書。", "棣萼榮相映，瓊枝色不如。", "賓朋爭漉酒，徒御侍巾車。", "異日始離抱，維思烹鯉魚。"]'),
('bc03748b-91c8-4a40-bc0d-3a608c296485','送少清赴潤州參軍因思練舊居','權德輿','唐','唐诗','tang','','[]','二紀樂簞瓢，煙霞暮與朝。',48,'全唐诗/poet.tang.17000.json','["二紀樂簞瓢，煙霞暮與朝。", "因君宦遊去，記得春江潮。", "遠別更搔首，初官方折腰。", "青門望離袂，魂爲阿連銷。"]'),
('3f49ff24-e742-45e8-8e54-fd253095e8dd','送濬上人歸揚州禪智寺','權德輿','唐','唐诗','tang','','[]','𥗤露宗通法已傳，麻衣筇杖去悠然。',32,'全唐诗/poet.tang.17000.json','["𥗤露宗通法已傳，麻衣筇杖去悠然。", "揚州後學應相待，遙想旛花古寺前。"]'),
('c2e767db-1d29-4027-90c9-d88cc5a38658','獻歲送李十兄赴黔中酒後絕句','權德輿','唐','唐诗','tang','','[]','一罇歲酒且留歡，三峽黔江去路難。',32,'全唐诗/poet.tang.17000.json','["一罇歲酒且留歡，三峽黔江去路難。", "志士感恩無遠近，異時應戴惠文冠。"]'),
('a818e3c1-b5a2-4f91-ba9e-d88e6108ff3d','送張僕射朝見畢歸鎮','權德輿','唐','唐诗','tang','','[]','青光照目青門曙，玉勒琱戈擁騶馭。',96,'全唐诗/poet.tang.17000.json','["青光照目青門曙，玉勒琱戈擁騶馭。", "東方連帥南陽公，文武吉甫如古風。", "獨奉新恩來謁帝，感深更見新詩麗。", "共看三接欲爲霖，却念百城同望歲。", "雙旌去去戀儲胥，歸路鶯花伴隼旟。", "今日漢庭求上略，留侯自有一編書。"]'),
('af167c8e-c7a2-4926-a8f9-9c7f7b27e3db','送韋行軍員外赴河陽','權德輿','唐','唐诗','tang','','[]','五代武弁侍明光，輟佐中權拜外郎。',96,'全唐诗/poet.tang.17000.json','["五代武弁侍明光，輟佐中權拜外郎。", "記事還同楚倚相，傳經遠自漢扶陽。", "離堂處處羅簪組，東望河橋壯鼙鼓。", "三城曉角啓軒門，一縣繁花照蓮府。", "上略儒風並者稀，翩翩騶騎有光輝。", "只今右職多虛位，應待他時伏奏歸。"]'),
('bce897c4-8d5e-45a3-9fba-6cb52a94c07b','送韋中丞奉使新羅','權德輿','唐','唐诗','tang','','[]','淳化洽聲明，殊方均惠養。',96,'全唐诗/poet.tang.17000.json','["淳化洽聲明，殊方均惠養。", "計書重譯至，錫命雙旌往。", "星辭北極遠，水泛東溟廣。", "斗柄辨宵程，天琛宜晝賞。", "孤光洲島迥，淨綠煙霞敞。", "展禮盛賓徒，交歡覿君長。", "經途勞視聽，愴別縈夢想。", "延頸旬歲期，新恩在歸鞅。"]'),
('aa6a9f02-6ef2-4bc1-8404-0b98ca82c9af','送從翁赴任長子縣令','權德輿','唐','唐诗','tang','','[]','家風本鉅儒，吏職化雙鳧。',48,'全唐诗/poet.tang.17000.json','["家風本鉅儒，吏職化雙鳧。", "啓事才方愜，臨人政自殊。", "地雄韓上黨，秩比魯中都。", "拜首春郊夕，離杯莫向隅。"]'),
('e2ddb99c-5b82-489d-b708-7d526364a738','送從弟廣東歸絕句','權德輿','唐','唐诗','tang','','[]','夏雲如火鑠晨輝，欵段羸車整素衣。',32,'全唐诗/poet.tang.17000.json','["夏雲如火鑠晨輝，欵段羸車整素衣。", "知爾業成還出谷，今朝莫愴斷行飛。"]'),
('6e22dbc4-0de1-4128-bdf0-0ae4e3a2a84d','送王鍊師赴王屋洞','權德輿','唐','唐诗','tang','','[]','稔歲在芝田，歸程入洞天。',48,'全唐诗/poet.tang.17000.json','["稔歲在芝田，歸程入洞天。", "白雲辭上國，青鳥會羣仙。", "自以碁銷日，寧資藥駐年。", "相看話離合，風馭忽泠然。"]'),
('05077568-a41b-41d8-99ba-2fd9282880f4','送薛溫州','權德輿','唐','唐诗','tang','','[]','昨日饋連營，今來刺列城。',48,'全唐诗/poet.tang.17000.json','["昨日饋連營，今來刺列城。", "方期建禮直，忽訪永嘉程。", "郡內裁詩暇，樓中遲客情。", "憑君減千騎，莫遣海鷗驚。"]'),
('eadbc859-a2de-45d3-bf08-8f043d84959d','送黔中裴中丞閣老赴任','權德輿','唐','唐诗','tang','','[]','五諫留中禁，雙旌輟上才。',96,'全唐诗/poet.tang.17000.json','["五諫留中禁，雙旌輟上才。", "內臣持鳳詔，天廄錫龍媒。", "宴語暌蘭室，輝榮亞柏臺。", "懷黃宜命服，舉白歎離杯。", "景霽山川迥，風清霧露開。", "辰溪分浩淼，僰道接縈迴。", "勝理環中得，殊琛徼外來。", "行看旬歲詔，傳慶在公台。"]'),
('18d7abf2-edf9-4875-936c-fdbfe7b877f0','送崔諭德致政東歸','權德輿','唐','唐诗','tang','','[]','天子坐法宮，詔書下江東。',144,'全唐诗/poet.tang.17000.json','["天子坐法宮，詔書下江東。", "懿此嘉遯士，蒲車赴丘中。", "褐衣入承明，朴略多古風。", "直道侍太子，昌言沃宸聰。", "嵓居四十年，心與鷗鳥同。", "一朝受恩澤，自說如池龍。", "乞骸歸故山，累疏明深衷。", "大君不奪志，命錫忽以崇。", "旭旦出國門，輕裝若秋蓬。", "家依白雲嶠，手植丹桂叢。", "竹齋引寒泉，霞月相玲瓏。", "曠然解赤綬，去逐冥冥鴻。"]'),
('b7ad52c3-6f5c-4eac-a557-bb93c8426a17','送三十叔赴任晉陵','權德輿','唐','唐诗','tang','','[]','春雲結暮陰，侍坐捧離襟。',48,'全唐诗/poet.tang.17000.json','["春雲結暮陰，侍坐捧離襟。", "黃綬輕裝去，青門芳草深。", "十年塵右職，三逕寄遐心。", "便道停橈處，應過舊竹林。"]'),
('3ddfa52e-06f0-42e6-bd3c-68ad1ee04ab1','送安南裴都護','權德輿','唐','唐诗','tang','','[]','忽佩交州印，初辭列宿文。',96,'全唐诗/poet.tang.17000.json','["忽佩交州印，初辭列宿文。", "莫言方任遠，且貴主憂分。", "迥轉朱鳶路，連飛翠羽羣。", "戈船航漲海，旌斾卷炎雲。", "絕徼褰帷識，名香夾轂焚。", "懷來通北戶，長養洽南薰。", "暫歎同心阻，行看異績聞。", "歸時無所欲，薏苡或煩君。"]'),
('47ac8d02-6a66-4a7c-bb5d-b2356026760c','送別沅汎','權德輿','唐','唐诗','tang','','[]','念爾強學殖，非貫早從師。',264,'全唐诗/poet.tang.17000.json','["念爾強學殖，非貫早從師。", "溫溫稟義方，慥慥習書詩。", "計偕來上國，宴喜方怡怡。", "經術既修明，藝文亦葳蕤。", "伊予諒無取，瑣質荷洪慈。", "偶來貳儀曹，量力何可支。", "廢業固相受，避嫌誠自私。", "徇吾刺促心，婉爾康莊姿。", "古人貴直道，內訟乖坦夷。", "用茲處大官，無乃玷清時。", "羸車出門去，悵望交涕洟。", "琢磨貴分陰，歲月若飆馳。", "千里起足下，豐年繫鎡䥓。", "苟令志氣堅，佇見纓珮隨。", "斑斕五綵服，前路春物熙。", "舊遊憶江南，環堵留蓬茨。", "湖水白於練，蓴羹細若絲。", "別來十三年，夢寐時見之。", "寵榮忽踰量，荏苒不自知。", "晨興愧華簪，止足爲靈龜。", "遐路各自愛，大來行可期。", "青冥在目前，努力調羽儀。"]'),
('d0a7f454-0d71-454d-a5ab-e6e03d6fa3e9','送張曹長工部大夫奉使西番','權德輿','唐','唐诗','tang','','[]','殊鄰覆露同，奉使小司空。',72,'全唐诗/poet.tang.17000.json','["殊鄰覆露同，奉使小司空。", "西候車徒出，南臺節印雄。", "弔祠將渥命，導驛暢皇風。", "故地山河在，新恩玉帛通。", "塞雲凝廢壘，關月照驚蓬。", "青史書歸日，翻輕五利功。"]'),
('33fff638-4537-45f4-a33c-8b3e1a48c57c','九華觀宴餞崔十七叔判官赴義武幕兼呈書記蕭校書','權德輿','唐','唐诗','tang','','[]','炎光三伏晝，洞府宜幽步。',72,'全唐诗/poet.tang.17000.json','["炎光三伏晝，洞府宜幽步。", "宿雨潤芝田，鮮風搖桂樹。", "陰陰臺殿敞，靡靡軒車駐。", "晚酌臨水清，晨裝出關路。", "偏榮本郡辟，倍感元臣遇。", "記室有門人，因君達書素。"]'),
('1841f94b-6ea4-4500-9299-2a6afef61afd','送文暢上人東遊','權德輿','唐','唐诗','tang','','[]','桑門許辯才，外學接宗雷。',48,'全唐诗/poet.tang.17000.json','["桑門許辯才，外學接宗雷。", "護法麻衣淨，翻經貝葉開。", "宗通知不染，妄想自堪哀。", "或結西方社，師遊早晚迴。"]'),
('41d9b21b-6f97-4be4-a475-d0cd6adb4430','送靈武范司空','權德輿','唐','唐诗','tang','','[]','上略在安邊，吳鉤結束鮮。',72,'全唐诗/poet.tang.17000.json','["上略在安邊，吳鉤結束鮮。", "三公臨右地，七萃擁中堅。", "舊壘銷烽火，新營辨井泉。", "伐謀師以律，賈勇士爭先。", "塞迥晴看月，沙平遠際天。", "榮薰知屈指，應在盛秋前。"]'),
('c0803728-7f49-4b98-a1a1-cd76d917e507','送商州杜中丞赴任','權德輿','唐','唐诗','tang','','[]','安康地里接商於，帝命專城總賦輿。',64,'全唐诗/poet.tang.17000.json','["安康地里接商於，帝命專城總賦輿。", "夕拜忽辭青瑣闥，晨裝獨捧紫泥書。", "深山古驛分騶騎，芳草閑雲逐隼旟。", "綺皓清風千古在，因君一爲謝巖居。"]'),
('21161999-bd74-4cd0-bada-b3a5ba42a112','送殷卿罷舉歸淮南舊居','權德輿','唐','唐诗','tang','','[]','計偕十上竟無成，忽憶嵓居便獨行。',64,'全唐诗/poet.tang.17000.json','["計偕十上竟無成，忽憶嵓居便獨行。", "志業嘗探絕編義，風塵虛作棄繻生。", "歲儲應歎山田薄，里社詩逢野醞清。", "惆悵中年羣從少，相看欲別倍關情。"]'),
('804478d7-16f1-4dc8-b539-77bf9249fe1c','送杜尹赴東都','權德輿','唐','唐诗','tang','','[]','商於留異績，河洛賀新遷。',72,'全唐诗/poet.tang.17000.json','["商於留異績，河洛賀新遷。", "朝選吾公守，時推杜尹賢。", "如綸披鳳詔，出匣淬龍泉。", "風雨交中土，簪裾敞別筵。", "清明人比玉，照灼府如蓮。", "佇報司州政，徵黃似頴川。"]'),
('325be953-64ad-4563-85bc-3d3814ab485d','送孔江州','權德輿','唐','唐诗','tang','','[]','九派尋陽郡，分明似畫圖。',48,'全唐诗/poet.tang.17000.json','["九派尋陽郡，分明似畫圖。", "秋光連瀑布，晴翠辨香鑪。", "才子厭蘭省，邦君榮竹符。", "江城多暇日，能寄八行無。"]'),
('49bf9535-2495-45a5-bb8b-3c7fdd482848','送渾鄧州','權德輿','唐','唐诗','tang','','[]','年少守南陽，新恩印綬光。',48,'全唐诗/poet.tang.17000.json','["年少守南陽，新恩印綬光。", "輕軒出繞霤，利刃發干將。", "風勁初下葉，雲寒方護霜。", "想君行縣處，露冕菊潭香。"]'),
('5254b1f3-d053-455b-a3c3-879225dc4f46','埇橋達奚四于十九陳大三侍御夜宴敘各賦二韻','權德輿','唐','唐诗','tang','','[]','滿樹鐵冠瓊樹枝，罇前燭下心相知。',32,'全唐诗/poet.tang.17000.json','["滿樹鐵冠瓊樹枝，罇前燭下心相知。", "明朝又與白雲遠，自古河梁多別離。"]'),
('41478cc9-de3f-496c-bea4-fed29865bba7','酬別蔡十二見贈','權德輿','唐','唐诗','tang','','[]','伊人茂天爵，恬澹臥郊園。',120,'全唐诗/poet.tang.17000.json','["伊人茂天爵，恬澹臥郊園。", "傲世方隱几，說經久顓門。", "浩歌曳柴車，詎羨丹轂尊。", "嚴霜被鶉衣，不知狐白溫。", "游心羲文際，愛我相討論。", "潢汙忽朝宗，傳騎令載奔。", "崢嶸歲陰晚，愀愴離念繁。", "別館絲桐清，寒郊煙雨昏。", "中飲見逸氣，縱談窮化元。", "佇見公車起，聖代待乞言。"]'),
('689cf3fa-0b49-4452-b010-64c3fc27a0df','揚州與丁山人別','權德輿','唐','唐诗','tang','','[]','將軍易道令威仙，華髮清談得此賢。',32,'全唐诗/poet.tang.17000.json','["將軍易道令威仙，華髮清談得此賢。", "惆悵今朝廣陵別，遼東後會復何年。"]'),
('0be38b1e-84f7-4373-8dec-62667469aa28','送台州崔錄事','權德輿','唐','唐诗','tang','','[]','不嫌臨海遠，微祿代躬耕。',48,'全唐诗/poet.tang.17000.json','["不嫌臨海遠，微祿代躬耕。", "古郡紀綱職，扁舟山水程。", "詩因琪樹麗，心與瀑泉清。", "盛府知音在，何時薦政成。"]'),
('d2320bc2-cbde-4793-9e55-a492e39588db','送信安劉少府','權德輿','唐','唐诗','tang','','[]','相看結離念，盡此林中淥。',72,'全唐诗/poet.tang.17000.json','["相看結離念，盡此林中淥。", "夷代輕遠遊，上才隨薄祿。", "參卿滯孫楚，隱市同梅福。", "吏散時泛弦，賓來閑覆局。", "襟情無俗慮，談笑成逸躅。", "此路足灘聲，羨君多水宿。"]'),
('5bc7d864-c25e-480b-992a-9db6daf514cb','送李城門罷官歸嵩陽','權德輿','唐','唐诗','tang','','[]','與君相識處，吏隱在牆東。',48,'全唐诗/poet.tang.17000.json','["與君相識處，吏隱在牆東。", "啓閉千門靜，逢迎兩掖通。", "罷官多暇日，肄業有儒風。", "歸去塵寰外，春山桂樹叢。"]'),
('5f573273-926f-4767-914e-19cbeb587983','送上虞丞','權德輿','唐','唐诗','tang','','[]','越郡佳山水，菁江接上虞。',48,'全唐诗/poet.tang.17000.json','["越郡佳山水，菁江接上虞。", "計程航一葦，試吏佐雙鳧。", "雲壑窺仙籍，風謠驗地圖。", "因尋黃絹字，爲我弔曹盱。"]'),
('92acc42a-a57d-46f8-bf91-2d832174622c','送盧評事婺州省覲','權德輿','唐','唐诗','tang','','[]','知向東陽去，晨裝見綵衣。',48,'全唐诗/poet.tang.17000.json','["知向東陽去，晨裝見綵衣。", "客愁青眼別，家喜玉人歸。", "漠漠水煙晚，蕭蕭楓葉飛。", "雙溪泊船處，候吏拜胡威。"]'),
('31e28206-5390-42db-9496-2f88975f5300','送崔端公郎君入京覲省','權德輿','唐','唐诗','tang','','[]','已見風姿美，仍聞藝業勤。',48,'全唐诗/poet.tang.17000.json','["已見風姿美，仍聞藝業勤。", "清秋上國路，白皙少年人。", "帶月輕帆疾，迎霜綵服新。", "過庭若有問，一爲說漳濱。"]'),
('65963428-2425-467a-9114-b7ca50744934','送張周二秀才謁宣州薛侍郎','權德輿','唐','唐诗','tang','','[]','儒衣兩少年，春棹轂溪船。',48,'全唐诗/poet.tang.17000.json','["儒衣兩少年，春棹轂溪船。", "湖月供詩興，嵐風費酒錢。", "上帆涵浦岸，欹枕傲晴天。", "不用愁羈旅，宣城太守賢。"]'),
('82be4e8f-42f6-4d54-a809-baa77b082b00','送張將軍歸東都舊業','權德輿','唐','唐诗','tang','','[]','功名不復求，舊業向東周。',48,'全唐诗/poet.tang.17000.json','["功名不復求，舊業向東周。", "白草辭邊騎，青門別故侯。", "摧殘寶劒折，羸病綠珠愁。", "日暮寒風起，猶疑大漠秋。"]'),
('527eebdf-fbba-45da-a5a6-8a27be40006b','送句容王少府簿領赴上都','權德輿','唐','唐诗','tang','','[]','上國路綿綿，行人候曉天。',48,'全唐诗/poet.tang.17000.json','["上國路綿綿，行人候曉天。", "離亭綠綺奏，鄉樹白雲連。", "江露濕征袂，山鶯宜泊船。", "春風若爲別，相顧起尊前。"]'),
('56164c0c-6a83-4c3b-8f92-4c26a6e8e34e','送從弟謁員外叔父迴歸義興','權德輿','唐','唐诗','tang','','[]','異鄉兄弟少，見爾自依然。',48,'全唐诗/poet.tang.17000.json','["異鄉兄弟少，見爾自依然。", "來酌林中酒，去耕湖上田。", "何朝逢暑雨，幾夜泊魚煙。", "餘力當勤學，成名貴少年。"]'),
('e2275360-22a1-4ea7-9983-b3dee2e80575','送梁道士謁壽州崔大夫','權德輿','唐','唐诗','tang','','[]','年少一仙官，清羸駕綵鸞。',48,'全唐诗/poet.tang.17000.json','["年少一仙官，清羸駕綵鸞。", "洞宮雲渺渺，花路水漫漫。", "歲計芝田熟，晨裝月帔寒。", "遙知小山桂，五馬待邀歡。"]'),
('43ad07cd-e6fe-4f1f-b218-ba3d9c876dc0','送鄭秀才貢舉','權德輿','唐','唐诗','tang','','[]','西笑意如何，知隨貢舉科。',48,'全唐诗/poet.tang.17000.json','["西笑意如何，知隨貢舉科。", "吟詩向月露，驅馬出煙蘿。", "晚色平蕪遠，秋聲候鴈多。", "自憐歸未得，相送一勞歌。"]'),
('89bc54f0-406d-4660-935f-e4c5cdf1f287','送謝孝廉移家越州','權德輿','唐','唐诗','tang','','[]','家承晉太傅，身慕魯諸生。',48,'全唐诗/poet.tang.17000.json','["家承晉太傅，身慕魯諸生。", "又見一帆去，共愁千里程。", "沙平古樹迥，潮滿曉江晴。", "從此幽深去，無妨隱姓名。"]'),
('72376846-a6c5-4811-b39b-59f64571d03a','送韓孝廉侍從赴舉','權德輿','唐','唐诗','tang','','[]','貢士去翩翩，如君最少年。',48,'全唐诗/poet.tang.17000.json','["貢士去翩翩，如君最少年。", "綵衣行不廢，儒服代相傳。", "曉月經淮路，繁陰過楚天。", "清談遇知己，應訪孝廉船。"]'),
('a01545fb-0ce3-4076-97cc-3c6552eeda38','送陸拾遺秖召赴行在','權德輿','唐','唐诗','tang','','[]','鵷鷺承新命，翻飛入漢庭。',48,'全唐诗/poet.tang.17000.json','["鵷鷺承新命，翻飛入漢庭。", "歌詩能合雅，獻納每論經。", "月曉蜀江迥，猿啼楚樹青。", "幸因焚草暇，書札訪沈冥。"]'),
('3c9be61b-8aa9-4d7e-89a5-b0528b4336d8','送暎師歸本寺','權德輿','唐','唐诗','tang','','[]','還歸柳市去，遠遠出人羣。',48,'全唐诗/poet.tang.17000.json','["還歸柳市去，遠遠出人羣。", "苔甃桐花落，山窗桂樹薰。", "引泉通絕澗，放鶴入孤雲。", "幸許宗雷到，清談不易聞。"]'),
('8aa3cc5f-da40-45be-b29c-37fb7f27ea9c','送宇文文府赴行在','權德輿','唐','唐诗','tang','','[]','送君當歲暮，斗酒破離顏。',48,'全唐诗/poet.tang.17000.json','["送君當歲暮，斗酒破離顏。", "車騎擁寒水，雪雲凝遠山。", "且安黃綬屈，莫羨白鷗閑。", "從此圖南路，青雲步武間。"]'),
('f12ba051-b790-42ea-9605-a0b0030e584f','送岳州溫錄事赴任','權德輿','唐','唐诗','tang','','[]','解巾州主簿，捧檄不辭遙。',48,'全唐诗/poet.tang.17000.json','["解巾州主簿，捧檄不辭遙。", "獨鶴九霄翼，寒松百尺條。", "晨裝沾雨雪，旅宿候風潮。", "爲政閑無事，清談肅郡僚。"]'),
('4d686b20-c52a-4db8-a034-95f116e7af66','送山人歸舊隱','權德輿','唐','唐诗','tang','','[]','工爲楚辭賦，更著魯衣冠。',48,'全唐诗/poet.tang.17000.json','["工爲楚辭賦，更著魯衣冠。", "歲儉山田薄，秋深晨服寒。", "武人榮燕頷，志士戀漁竿。", "會被公車薦，知君久晦難。"]'),
('92e2f6f4-592a-4aaf-921c-413b768480f2','惠上人房宴別','權德輿','唐','唐诗','tang','','["\u5e90\u5c71"]','方袍相引到龍華，支策開襟路不賒。',64,'全唐诗/poet.tang.17000.json','["方袍相引到龍華，支策開襟路不賒。", "法味已同香積會，禮容疑在少施家。", "逸民羽客期皆至，疎竹青苔景半斜。", "究竟相依何處好，匡山古社足煙霞。"]'),
('a1c8ad2f-17c8-457c-9f46-95c808e1963d','送裴秀才貢舉','權德輿','唐','唐诗','tang','','[]','儒衣風貌清，去抵漢公卿。',48,'全唐诗/poet.tang.17000.json','["儒衣風貌清，去抵漢公卿。", "賓貢年猶少，篇章藝已成。", "臨流惜暮景，話別起鄉情。", "離酌不辭醉，西江春草生。"]'),
('0f0c3b4b-c0bc-40b7-8623-ca251fe48152','送袁太祝衢婺巡覆','權德輿','唐','唐诗','tang','','[]','校緡稅畝不妨閑，清興自隨魚鳥間。',32,'全唐诗/poet.tang.17000.json','["校緡稅畝不妨閑，清興自隨魚鳥間。", "知君此去足佳句，路出桐溪千萬山。"]'),
('1e577367-dfb5-4a8f-be6f-18f9468a1bac','送湖南李侍御赴本使賦採菱亭詩','權德輿','唐','唐诗','tang','','[]','舊俗採菱處，津亭風景和。',48,'全唐诗/poet.tang.17000.json','["舊俗採菱處，津亭風景和。", "沅江收暮靄，楚女發清歌。", "曲岸縈湘葉，荒堦上白波。", "蘭橈向蓮府，一爲枉帆過。"]'),
('5882895b-e584-4587-ab29-30596ecb037c','送穆侍御歸東都','權德輿','唐','唐诗','tang','','[]','知君儒服貴，綵繡兩相輝。',48,'全唐诗/poet.tang.17000.json','["知君儒服貴，綵繡兩相輝。", "婉婉成名後，翩翩擁傳歸。", "江深煙嶼沒，山暗雨雲飛。", "共待酬恩罷，相將去息機。"]'),
('127da39a-a1d5-4abc-b32d-ef58ed80341c','送崔端公赴度支江陵院三韻','權德輿','唐','唐诗','tang','','[]','津亭風雪霽，斗酒留征棹。',36,'全唐诗/poet.tang.17000.json','["津亭風雪霽，斗酒留征棹。", "星傳指湘江，瑤琴多楚調。", "偏愁欲別處，黯黯頹陽照。"]'),
('1d354aed-ee73-4a15-a004-23cc713f4eae','送陸太祝赴湖南幕同用送字','權德輿','唐','唐诗','tang','','[]','不憚征路遙，定緣賓禮重。',36,'全唐诗/poet.tang.17000.json','["不憚征路遙，定緣賓禮重。", "新知折柳贈，舊侶乘籃送。", "此去佳句多，楓江接雲夢。"]'),
('06172f1f-1a0e-4f75-bff0-86682cbdd4df','送李處士歸弋陽山居','權德輿','唐','唐诗','tang','','[]','暫來城市意何如，却憶葛陽溪上居。',64,'全唐诗/poet.tang.17000.json','["暫來城市意何如，却憶葛陽溪上居。", "不憚薄田輸井稅，自將嘉句著州閭。", "波翻極浦檣竿出，霜落秋郊樹影疎。", "想到家山無俗侶，逢迎只是坐籃輿。"]'),
('ff8e181e-90d3-4ec9-8287-ac2d11d6a2d4','送清洨上人謁信州陸員外','權德輿','唐','唐诗','tang','','[]','暫辭長老去隨緣，候曉輕裝寄客船。',64,'全唐诗/poet.tang.17000.json','["暫辭長老去隨緣，候曉輕裝寄客船。", "佳句已齊康寶月，清談遠指謝臨川。", "灘經水瀨逢新雪，路過漁潭宿暝煙。", "暇日若隨千騎出，南巖只在郡樓前。"]'),
('586ce45c-fbf2-4618-a673-91d9cca086a8','送別同用闊字','權德輿','唐','唐诗','tang','','[]','耿耿離念繁，蕭蕭涼葉脫。',36,'全唐诗/poet.tang.17000.json','["耿耿離念繁，蕭蕭涼葉脫。", "緇塵素衣敝，風露秋江闊。", "想得讀書窗，巖花對巾褐。"]'),
('d8902cc4-de96-4f28-bce2-2fb64d29590f','送人使之江陵','權德輿','唐','唐诗','tang','','[]','嘉招不辭遠，捧檄利攸往。',72,'全唐诗/poet.tang.17000.json','["嘉招不辭遠，捧檄利攸往。", "行役念前程，讌游睽舊賞。", "征軺星乍動，江信潮應上。", "煙水飛一帆，霜雲搖五兩。", "紛紛別袂舉，切切離鴻響。", "後會杳何時，悠然勞夢想。"]'),
('c5f2bdd4-1ce0-4776-bc02-19c5728b04db','餘干贈別張二十二侍御','權德輿','唐','唐诗','tang','','[]','蕪城陌上春風別，干越亭邊歲暮逢。',32,'全唐诗/poet.tang.17000.json','["蕪城陌上春風別，干越亭邊歲暮逢。", "驅車又愴南北路，返照寒江千萬峯。"]'),
('f28f738e-b50f-4070-9ba3-72f6576d82e9','雜言賦得風送崔秀才歸白田限三五六七言','權德輿','唐','唐诗','tang','','[]','響深澗，思啼猨。',50,'全唐诗/poet.tang.17000.json','["響深澗，思啼猨。", "闇入蘋洲暖，輕隨柳陌暄。", "澹蕩乍飄雲影，芳菲徧滿花源。", "寂寞春江別君處，和煙帶雨送征軒。"]'),
('502830f1-5a57-4e49-a9f7-31e10d9f57b8','雜言同用離騷體送張評事襄陽覲省','權德輿','唐','唐诗','tang','','[]','黯離堂兮日晚，儼壺觴兮送遠。',75,'全唐诗/poet.tang.17000.json','["黯離堂兮日晚，儼壺觴兮送遠。", "遠水霽兮微明，杜蘅秀兮白芷生。", "波泫泫兮煙冪冪，凝暮色於空碧。", "紛離念兮隨君，泝九江兮經七澤。", "君之去兮不可留，五采裳兮木蘭舟。"]'),
('99261cc1-a8ea-4f79-b86b-fc06a851dec1','嶺上逢久別者又別','權德輿','唐','唐诗','tang','','["\u79bb\u522b"]','十年曾一別，征路此相逢。',24,'全唐诗/poet.tang.17000.json','["十年曾一別，征路此相逢。", "馬首向何處，夕陽千萬峯。"]'),
('104e9cfc-6a0e-4e07-a532-36d95074c0ea','贈別表兄韋卿','權德輿','唐','唐诗','tang','','[]','新讀兵書事護羌，腰間寶劒映金章。',32,'全唐诗/poet.tang.17000.json','["新讀兵書事護羌，腰間寶劒映金章。", "少年百戰應輕別，莫笑儒生淚數行。"]'),
('83083139-6851-444d-a675-c7f624f5fc83','古離別','權德輿','唐','唐诗','tang','','[]','人生天地間，瞥若六轡馳。',216,'全唐诗/poet.tang.17000.json','["人生天地間，瞥若六轡馳。", "夭壽既常數，奈何生別離。", "跡當中人域，正性日已衰。", "是非千萬境，杳靄情塵滋。", "出門事何常，暫別亦難期。", "冉冉歎流景，悠悠限山陂。", "盡此一夕歡，華罇會前墀。", "雞鳴東方曙，夙駕臨通逵。", "欲出強移步，欲留難致辭。", "兩情不得已，念此留何爲。", "天明去已遠，寂默居人歸。", "入門復上堂，怳怳生驚疑。", "經履同遊處，猶言常相隨。", "覽物或臨盤，翻怪來何遲。", "乃知前日歡，本爲今日悲。", "特此別後心，寧及未見時。", "則知交疎分，久久翻易持。", "報君未別後，別後當自知。"]'),
('de9b8f59-b45b-406b-a7bb-68b34b255146','早夏青龍寺致齋憑眺感物因書十四韻','權德輿','唐','唐诗','tang','','[]','曉出文昌宮，憩茲青蓮宇。',168,'全唐诗/poet.tang.17000.json','["曉出文昌宮，憩茲青蓮宇。", "潔齋奉明祀，憑覽傷夐古。", "秦爲三月火，漢乃一抔土。", "詐力自湮淪，霸儀終莽鹵。", "中南橫峻極，積翠洩雲雨。", "首夏諒清和，芳陰接場圃。", "仁祠閟嚴淨，稽首洗靈府。", "虛室僧正禪，危梁燕初乳。", "通莊走聲利，結駟乃旁午。", "觀化復何如，刳心信爲愈。", "盛時忽過量，弱質本無取。", "靜永環中樞，益愧腰下組。", "塵勞期抖擻，陟降聊俯僂。", "遺韻留壁間，淒然感東武。"]'),
('9d58e2a8-83cd-4a25-90f6-ea67ac260019','仲秋朝拜昭陵','權德輿','唐','唐诗','tang','','[]','清秋壽原上，詔拜承吉卜。',192,'全唐诗/poet.tang.17000.json','["清秋壽原上，詔拜承吉卜。", "嘗讀貞觀書，及茲幸齋沐。", "文皇昔潛耀，隋季自顛覆。", "撫運斯順人，救焚非逐鹿。", "神祇戴元聖，君父納大麓。", "良將授兵符，直臣調鼎餗。", "無疆傳慶祚，有截荷亭育。", "仙馭淩紫氛，神遊棄黃屋。", "方祗護山跡，先正陪巖腹。", "杳杳九嵕深，沈沈萬靈肅。", "鳥飛田已闢，龍去雲猶簇。", "金氣爽林巒，乾岡走崖谷。", "吾皇弘孝理，率士蒙景福。", "擁佑乃清夷，威靈諒回復。", "禮承三公重，心愧二卿祿。", "展敬何所伸，曾以斧山木。"]'),
('200b8b91-bd26-4196-a9ea-d9e9d183fae2','拜昭陵出城與張祕監閣老同里臨行別承在史館未歸尋辱清辭輒酬之','權德輿','唐','唐诗','tang','','[]','仲月當南呂，晨裝拜穀林。',48,'全唐诗/poet.tang.17000.json','["仲月當南呂，晨裝拜穀林。", "逢君在東觀，不得話離襟。", "策馬緣雲路，開緘扣玉音。", "還期纔浹日，里社酒同斟。"]'),
('c29bdc28-bccc-4f83-b399-2abfa812b62f','酬馮監拜昭陵迴途中遇雨見示','權德輿','唐','唐诗','tang','','[]','之子共乘軺，清秋拜上霄。',48,'全唐诗/poet.tang.17000.json','["之子共乘軺，清秋拜上霄。", "曙霞迎夙駕，零雨濕迴鑣。", "甘谷行初盡，軒臺去漸遙。", "望中猶可辨，耘鳥下山椒。"]'),
('fc13e5dc-14fa-4315-a91e-c5c222adbaf2','朔旦冬至攝職南郊因書即事','權德輿','唐','唐诗','tang','','[]','大明南至慶天正，朔旦圓丘樂六成。',64,'全唐诗/poet.tang.17000.json','["大明南至慶天正，朔旦圓丘樂六成。", "文軌盡同堯曆象，齋祠忝備漢公卿。", "星辰列位祥光滿，金石交音曉奏清。", "更有觀臺稱賀處，黃雲捧日瑞昇平。"]'),
('53650b3a-84b8-4569-8303-37c9462e69cf','奉和張監閣老過八陵院題贈杜卿崔員外','權德輿','唐','唐诗','tang','','[]','崇飾山園孝理深，萬方同感聖人心。',64,'全唐诗/poet.tang.17000.json','["崇飾山園孝理深，萬方同感聖人心。", "已聞東閣招從事，每向西垣奉德音。", "公府從容談婉婉，賓堦清切景沈沈。", "與君跬步如同舍，終日相期此盍簪。"]'),
('0b85a3ae-c81a-48d4-a416-094ac0eb2587','奉和鄭賓客相公攝官豐陵扈從之作','權德輿','唐','唐诗','tang','','[]','五輅導靈輼，千夫象繚垣。',120,'全唐诗/poet.tang.17000.json','["五輅導靈輼，千夫象繚垣。", "行宮移曉漏，綵杖下秋原。", "莫究希夷理，空懷渙汗恩。", "頤神方蹈道，傳聖乃尊尊。", "共祝如山壽，俄驚憑几言。", "遐荒七月會，肸蠁百靈奔。", "豹尾從風直，鸞旗映日翻。", "塗芻聯法從，營騎肅旌門。", "杳靄虞泉夕，淒清楚挽喧。", "不堪程盡處，嗚咽望文園。"]'),
('b1b03860-d390-481d-99fa-4c47f7f163ce','詹事府宿齋絕句','權德輿','唐','唐诗','tang','','[]','清齋四體泰，白晝一室空。',24,'全唐诗/poet.tang.17000.json','["清齋四體泰，白晝一室空。", "摧頹有古樹，騷屑多悲風。"]'),
('4cbfb138-5cc0-4b7b-9c63-25f7e1735aa6','和王祭酒太社宿齋不得赴李尚書宅會戲書見寄','權德輿','唐','唐诗','tang','','[]','元禮門前勞引望，句龍壇下阻歡娛。',32,'全唐诗/poet.tang.17000.json','["元禮門前勞引望，句龍壇下阻歡娛。", "此時對局空相憶，博進何人更樂輸。"]'),
('cc88d719-d465-406f-b010-e2d1af6c0017','酬裴端公八月十五日夜對月見懷','權德輿','唐','唐诗','tang','','[]','涼夜清秋半，空庭皓月圓。',48,'全唐诗/poet.tang.17000.json','["涼夜清秋半，空庭皓月圓。", "動搖隨積水，皎潔滿晴天。", "多病嘉期阻，深情麗曲傳。", "偏懷賞心處，同望庾樓前。"]'),
('e2604ccf-e0f3-4452-bba6-002ded367eda','奉和崔閣老清明日候許閣老交直之際辱裴閣老書招云與考功苗曹長先城南遊覽獨行口號因以簡贈','權德輿','唐','唐诗','tang','','[]','紫禁宿初迴，清明花亂開。',72,'全唐诗/poet.tang.17000.json','["紫禁宿初迴，清明花亂開。", "相招直城外，遠遠上春臺。", "諫曹將列宿，幾處期子玉。", "深竹與清泉，家家桃李鮮。", "折芳行載酒，勝賞隨君有。", "愁疾自無悰，臨風一搔首。"]'),
('5728439e-38dc-40cf-a534-875050a52e70','和張祕監閣老獻歲過蔣大拾遺因呈兩省諸公幷見示','權德輿','唐','唐诗','tang','','[]','二賢同載筆，久次入新年。',48,'全唐诗/poet.tang.17000.json','["二賢同載筆，久次入新年。", "焚草淹輕秩，藏書厭舊編。", "竹風晴翠動，松雪瑞光鮮。", "慶賜行春令，從茲佇九遷。"]'),
('cf52e310-9174-43aa-86cb-6d6f5351199b','酬崔舍人閣老冬至日宿直省中奉簡兩掖閣老幷見示','權德輿','唐','唐诗','tang','','[]','令節一陽新，西垣宿近臣。',96,'全唐诗/poet.tang.17000.json','["令節一陽新，西垣宿近臣。", "曉光連鳳沼，殘漏近雞人。", "白雪飛成曲，黃鐘律應均。", "層霄翔迅羽，廣陌駐歸輪。", "清切晨趨貴，恩華夜直頻。", "輟才時所重，分命秩皆真。", "左掖期連茹，南宮愧積薪。", "九年叨此地，迴首倍相親。"]'),
('ebcfc882-8d5d-4aaa-badf-0cad35bfb770','八月十五日夜瑤臺寺對月絕句','權德輿','唐','唐诗','tang','','["\u4e2d\u79cb\u8282", "\u6708\u4eae", "\u5bfa\u5e99"]','嬴女乘鸞已上天，仁祠空在鼎湖邊。',32,'全唐诗/poet.tang.17000.json','["嬴女乘鸞已上天，仁祠空在鼎湖邊。", "涼風遙夜清秋半，一望金波照粉田。"]'),
('295f895c-d021-4ad6-8ce6-1362de0b8662','夏至日作','權德輿','唐','唐诗','tang','','[]','璿樞無停連，四序相錯行。',24,'全唐诗/poet.tang.17000.json','["璿樞無停連，四序相錯行。", "寄言赫曦景，今日一陰生。"]'),
('6f3d25ae-b4cf-4439-a482-907730ef5592','二月二十七日社兼春分端居有懷簡所思者','權德輿','唐','唐诗','tang','','[]','清晝開簾坐，風光處處生。',48,'全唐诗/poet.tang.17000.json','["清晝開簾坐，風光處處生。", "看花詩思發，對酒客愁輕。", "社日雙飛燕，春分百囀鶯。", "所思終不見，還是一含情。"]'),
('0130dcaf-3f27-4a94-b78a-b8a1fe5c56b1','甲子歲元日呈鄭侍御明府','權德輿','唐','唐诗','tang','','[]','萬里煙塵合，秦吳遂渺然。',48,'全唐诗/poet.tang.17000.json','["萬里煙塵合，秦吳遂渺然。", "無人來上國，灑淚向新年。", "世故看風葉，生涯寄海田。", "屠蘇聊一醉，猶賴主人賢。"]'),
('6113d640-c2f5-4e11-aaae-0368e78f3fb6','七夕','權德輿','唐','唐诗','tang','','[]','佳期人不見，天上喜新秋。',48,'全唐诗/poet.tang.17000.json','["佳期人不見，天上喜新秋。", "玉珮霑新露，香車渡淺流。", "東西一水隔，迢遰兩年愁。", "別有穿針處，微明月暎樓。"]'),
('6e504c01-2618-4387-a624-8f536249bab3','嘉興九日寄丹陽親故','權德輿','唐','唐诗','tang','','[]','窮年路歧客，西望思茫茫。',72,'全唐诗/poet.tang.17000.json','["窮年路歧客，西望思茫茫。", "積水曾南渡，浮雲失舊鄉。", "海邊尋別墅，愁裏見重陽。", "草露荷衣冷，山風菊酒香。", "獨謠看墜葉，遠目徧秋光。", "更羨登攀處，煙花滿練塘。"]'),
('8aaa5bd6-160c-4719-bb82-a5c7b9c9d06d','九日北樓宴集','權德輿','唐','唐诗','tang','','[]','蕭颯秋聲樓上聞，霜風漠漠起陰雲。',64,'全唐诗/poet.tang.17000.json','["蕭颯秋聲樓上聞，霜風漠漠起陰雲。", "不見攜觴王太守，空思落帽孟參軍。", "風吟蟋蟀寒偏急，酒泛茱萸晚易醺。", "心憶舊山何日見，併將愁淚共紛紛。"]'),
('b7739ddd-9d7c-44c9-b8e0-c61cd4172bb0','奉陪李大夫九日龍沙宴會','權德輿','唐','唐诗','tang','','[]','龍沙重九會，千騎駐旌旗。',48,'全唐诗/poet.tang.17000.json','["龍沙重九會，千騎駐旌旗。", "水木秋光淨，絲桐雅奏遲。", "煙蕪斂暝色，霜菊發寒姿。", "今日從公醉，全勝落帽時。"]'),
('52993d71-7bc0-4371-a84f-f7bdd5546b93','臘日龍沙會絕句','權德輿','唐','唐诗','tang','','[]','簾外寒江千里色，林中罇酒七人期。',32,'全唐诗/poet.tang.17000.json','["簾外寒江千里色，林中罇酒七人期。", "寧知臘日龍沙會，却勝重陽落帽時。"]'),
('91892f0d-b686-4349-af07-d43c10a36ef0','嚴陵釣臺下作','權德輿','唐','唐诗','tang','','[]','絕頂聳蒼翠，清湍石磷磷。',168,'全唐诗/poet.tang.17000.json','["絕頂聳蒼翠，清湍石磷磷。", "先生晦其中，天子不得臣。", "心靈棲顥氣，纓冕猶緇塵。", "不樂禁中臥，却歸江上春。", "潛驅東漢風，日使薄者醇。", "焉用佐天子，特此報故人。", "人知大賢心，不獨私自身。", "弛張有深致，耕釣陶天真。", "奈何清風後，擾擾論屈伸。", "交情同市道，利欲相紛綸。", "我行訪遺臺，仰古懷逸民。", "矰繳鴻鵠遠，雪霜松桂新。", "江流去不窮，山色凌秋旻。", "人世自今古，清輝照無垠。"]'),
('df98256a-2092-412d-a6fe-8dff2dcef722','曉發武陽館即事書情','權德輿','唐','唐诗','tang','','[]','清晨策羸車，嘲唽聞村雞。',120,'全唐诗/poet.tang.17000.json','["清晨策羸車，嘲唽聞村雞。", "行將騎吏親，日與情愛暌。", "東風變林樾，南畝事耕犂。", "青菰冒白水，方塘接廣畦。", "雜英被長坂，野草蔓幽蹊。", "瀉鹵成沃壤，枯株發柔荑。", "芳樹鶯命雛，深林麏引麑。", "杳杳途未極，團團日已西。", "哲士務纓弁，鄙夫戀蓬藜。", "終當稅塵駕，盥濯依春溪。"]'),
('344f82e5-6f1c-4ea9-a4c2-49041091256e','豐城劒池驛感題','權德輿','唐','唐诗','tang','','[]','龍劒昔未發，泥沙相晦藏。',48,'全唐诗/poet.tang.17000.json','["龍劒昔未發，泥沙相晦藏。", "向非張茂先，孰辨斗牛光。", "神物不自達，聖賢亦彷徨。", "我行豐城野，慷慨心內傷。"]'),
('30d659f7-fa63-45e9-be47-70bb65c120ef','奉使宜春夜渡新淦江陸路至黃蘗館路上遇風雨作','權德輿','唐','唐诗','tang','','[]','草草理夜裝，涉江又登陸。',168,'全唐诗/poet.tang.17000.json','["草草理夜裝，涉江又登陸。", "望路殊未窮，指期今已促。", "傳呼戒徒御，振轡轉林麓。", "陰雲擁嵓端，霔雨當山腹。", "震雷如在耳，飛電來照目。", "獸跡不敢窺，馬蹄唯務速。", "虔心若齋禮，濡體如沐浴。", "萬竅相怒號，百泉暗奔瀑。", "危梁慮足跌，峻坂憂車覆。", "問我何以然，前日受微祿。", "轉知人代事，纓組乃徽束。", "向若家居時，安枕春夢熟。", "遵途稍已近，候吏來相續。", "曉霽心始安，林端見初旭。"]'),
('cd67fe2d-abeb-48a4-92c1-5bc77dc17189','細柳驛','權德輿','唐','唐诗','tang','','[]','細柳肅軍令，條侯信殊倫。',48,'全唐诗/poet.tang.17000.json','["細柳肅軍令，條侯信殊倫。", "棘門乃兒戲，從古多其人。", "神武今不殺，介夫如搢紳。", "息駕幸茲地，懷哉悚精神。"]'),
('2e8b850b-8e35-49b3-9a0b-32f667bb8b4e','渭水','權德輿','唐','唐诗','tang','','[]','呂叟年八十，皤然持釣鉤。',48,'全唐诗/poet.tang.17000.json','["呂叟年八十，皤然持釣鉤。", "意在靜天下，豈唯食營丘。", "師臣有家法，小白猶尊周。", "日暮駐征策，愛茲清渭流。"]'),
('4e03289f-39d2-4666-91dd-780bdf587f0e','宮人斜絕句','權德輿','唐','唐诗','tang','','[]','一路斜分古驛前，陰風切切晦秋煙。',32,'全唐诗/poet.tang.17000.json','["一路斜分古驛前，陰風切切晦秋煙。", "鉛華新舊共冥寞，日暮愁鴟飛野田。"]'),
('0aa2282d-fa50-4739-bf7c-39a7f7d63913','敷水驛','權德輿','唐','唐诗','tang','','[]','空見水名敷，秦樓昔事無。',24,'全唐诗/poet.tang.17000.json','["空見水名敷，秦樓昔事無。", "臨風駐征騎，聊復捋髭鬚。"]'),
('deedefac-7346-48f5-b1dc-e68a2af0761d','朝元閣','權德輿','唐','唐诗','tang','','[]','繚垣複道上層霄，十月離宮萬國朝。',32,'全唐诗/poet.tang.17000.json','["繚垣複道上層霄，十月離宮萬國朝。", "胡馬忽來清蹕去，空餘臺殿照山椒。"]'),
('e97b9412-50fd-4432-bc95-791ae1da5820','石甕寺','權德輿','唐','唐诗','tang','','[]','石甕靈泉勝寶井，汲人迴挂青絲綆。',32,'全唐诗/poet.tang.17000.json','["石甕靈泉勝寶井，汲人迴挂青絲綆。", "廚煙半逐白雲飛，當晝老僧來灌頂。"]'),
('d439c255-fa1a-4960-844c-72838a84ed30','盤豆驛','權德輿','唐','唐诗','tang','','[]','盤豆綠雲上古驛，望思臺下使人愁。',32,'全唐诗/poet.tang.17000.json','["盤豆綠雲上古驛，望思臺下使人愁。", "江充得計太子死，日暮戾園風雨秋。"]'),
('098811c4-25dc-4d8e-8ab4-fb74b78b5f95','晚渡揚子江却寄江南親故','權德輿','唐','唐诗','tang','','[]','返照滿寒流，輕舟任搖漾。',84,'全唐诗/poet.tang.17000.json','["返照滿寒流，輕舟任搖漾。", "支頤見千里，煙景非一狀。", "遠岫有無中，片帆風水上。", "天清去鳥滅，浦迥寒沙漲。", "樹晚疊秋嵐，江空翻宿浪。", "胸中千萬慮，對此一清曠。", "迴首碧雲深，佳人不可望。"]'),
('ad4e326d-2fca-4520-b3ee-8dc5f428c9c8','新安江路','權德輿','唐','唐诗','tang','','[]','深潭與淺灘，萬轉出新安。',48,'全唐诗/poet.tang.17000.json','["深潭與淺灘，萬轉出新安。", "人遠禽魚淨，山深水木寒。", "嘯起青蘋末，吟矚白雲端。", "即事遂幽賞，何心挂儒冠。"]'),
('3b60358a-fcbc-41fe-9751-de4fb2291d34','月夜江行','權德輿','唐','唐诗','tang','','["\u7f81\u65c5", "\u601d\u4e61"]','扣船不得寐，浩露清衣襟。',48,'全唐诗/poet.tang.17000.json','["扣船不得寐，浩露清衣襟。", "彌傷孤舟夜，遠結萬里心。", "幽興惜瑤草，素懷寄鳴琴。", "三奏月初上，寂寞寒江深。"]'),
('c47a66da-e4d1-4bfd-a8d9-38fdeda8404b','江城夜泊寄所思','權德輿','唐','唐诗','tang','','[]','客程殊未極，艤櫂泊迴塘。',48,'全唐诗/poet.tang.17000.json','["客程殊未極，艤櫂泊迴塘。", "水宿知寒早，愁眠覺夜長。", "遠鐘和暗杵，曙月照晴霜。", "此夕相思意，搖搖不暫忘。"]'),
('e40d3f8a-7e0c-47df-b0a4-f2e55fded03a','陪包諫議湖墅路中舉帆','權德輿','唐','唐诗','tang','','[]','蕭蕭涼雨歇，境物望中閑。',48,'全唐诗/poet.tang.17000.json','["蕭蕭涼雨歇，境物望中閑。", "風際片帆去，煙中獨鳥還。", "斷橋通遠浦，野墅接秋山。", "更喜陪清興，尊前一解顏。"]'),
('8b95f8dd-a40a-4000-b102-d4767cbe71e2','富陽陸路','權德輿','唐','唐诗','tang','','[]','又入亂峯去，遠程殊未歸。',48,'全唐诗/poet.tang.17000.json','["又入亂峯去，遠程殊未歸。", "煙蘿迷客路，山果落征衣。", "攲石臨清淺，晴雲出翠微。", "漁潭明夜泊，心憶謝玄暉。"]'),
('26969ecc-3f9f-454e-9cf2-7fbad838b0c3','曉','權德輿','唐','唐诗','tang','','[]','曉風搖五兩，殘月映石壁。',24,'全唐诗/poet.tang.17000.json','["曉風搖五兩，殘月映石壁。", "稍稍曙光開，片帆在空碧。"]'),
('de1523ff-1ef1-48ee-9e6c-af396bf69f51','晝','權德輿','唐','唐诗','tang','','[]','孤舟漾曖景，獨鶴下秋空。',24,'全唐诗/poet.tang.17000.json','["孤舟漾曖景，獨鶴下秋空。", "安流日正晝，淨綠天無風。"]'),
('09de69c4-5ad3-4c63-b968-41bb9dcd415a','晚','權德輿','唐','唐诗','tang','','[]','古樹夕陽盡，空江暮靄收。',24,'全唐诗/poet.tang.17000.json','["古樹夕陽盡，空江暮靄收。", "寂寞扣船坐，獨生千里愁。"]'),
('5b16bd2b-ca6b-4643-9c20-b49d5f6180c2','夜','權德輿','唐','唐诗','tang','','[]','猨聲到枕上，愁夢紛難理。',24,'全唐诗/poet.tang.17000.json','["猨聲到枕上，愁夢紛難理。", "寂寞深夜寒，青霜落秋水。"]'),
('6d4f7510-5622-46cc-a6ae-71e5d38a0e20','奉和韋諫議奉送水部家兄上後書情寄諸兄弟仍通簡南宮親舊幷呈兩省閣老院長','權德輿','唐','唐诗','tang','','[]','駟牡龍旂慶至今，一門儒服耀華簪。',64,'全唐诗/poet.tang.17000.json','["駟牡龍旂慶至今，一門儒服耀華簪。", "人望皆同照乘寶，家風不重滿籝金。", "護衣直夜南宮靜，焚草清時左掖深。", "何幸末班陪兩地，陽春欲和意難任。"]'),
('3dc26314-630f-409f-9e7f-47fd320e1fb5','奉和史館張閣老以許陳二閣長愛弟俱爲尚書郎伯仲同時列在南北省會於左掖因而有詠','權德輿','唐','唐诗','tang','','[]','伯仲盡時賢，平輿與潁川。',48,'全唐诗/poet.tang.17000.json','["伯仲盡時賢，平輿與潁川。", "桂枝嘗徧折，棣萼更相鮮。", "丹地晨趨並，黃扉夕拜聯。", "豈如分侍從，來就鳳池邊。"]'),
('e5459473-7394-4e72-a4f3-4658bdc60b0b','韋賓客宅與諸博士宴集','權德輿','唐','唐诗','tang','','[]','累抗乞身章，湛恩比上庠。',72,'全唐诗/poet.tang.17000.json','["累抗乞身章，湛恩比上庠。", "賓筵徴稷嗣，家法自扶陽。", "簪組歡言久，琴壺雅興長。", "陰嵐冒苔石，輕籟韻風篁。", "佩玉三朝貴，揮金百慮忘。", "因知臥商洛，豈勝白雲鄉。"]'),
('560d3dc3-a4fa-4861-97e0-c01523922830','酬張祕監閣老喜太常中書二閣老與德輿同日遷官相代之作','權德輿','唐','唐诗','tang','','[]','珠樹共飛棲，分封受紫泥。',48,'全唐诗/poet.tang.17000.json','["珠樹共飛棲，分封受紫泥。", "正名推五字，貴仕仰三珪。", "繼組心知忝，腰章事頗齊。", "蓬山有佳句，喜氣在新題。"]'),
('343a8541-204f-402b-a55c-5032db136f9e','國子柳博士兼領太常博士輒申賀贈','權德輿','唐','唐诗','tang','','[]','博士本秦官，求才帖職難。',48,'全唐诗/poet.tang.17000.json','["博士本秦官，求才帖職難。", "臨風曲臺淨，對月璧池寒。", "講學分陰重，齋祠曉漏殘。", "朝衣辨色處，雙綬更宜看。"]'),
('39ede6ef-735d-4513-8f5e-a183ba7c98eb','過隱者湖上所居','權德輿','唐','唐诗','tang','','[]','蝸舍映平湖，皤然一魯儒。',48,'全唐诗/poet.tang.17000.json','["蝸舍映平湖，皤然一魯儒。", "唯將酒作聖，不厭谷名愚。", "兵法窺黃石，天官辨白榆。", "行看軟輪起，未可號潛夫。"]'),
('6f4cf32e-a291-466a-b997-f8534086cf2e','從叔將軍宅薔薇花開太府韋卿有題壁長句因以和作','權德輿','唐','唐诗','tang','','[]','環列從容蹀躞歸，光風駘蕩發紅薇。',64,'全唐诗/poet.tang.17000.json','["環列從容蹀躞歸，光風駘蕩發紅薇。", "鶯藏密葉宜新霽，蝶遶低枝愛晚暉。", "豔色當軒迷舞袖，繁香滿逕拂朝衣。", "名卿洞壑仍相近，佳句新成和者稀。"]'),
('8369bcbb-f18f-45d5-a1dd-d028d3e6b034','奉和許閣老霽後慈恩寺杏園看花同用花字口號','權德輿','唐','唐诗','tang','','[]','杏林微雨霽，灼灼滿瑤華。',48,'全唐诗/poet.tang.17000.json','["杏林微雨霽，灼灼滿瑤華。", "左掖期先至，中園景未斜。", "含毫歌白雪，藉草醉流霞。", "獨限金閨籍，支頤啜茗花。"]'),
('f6de9d2c-fe81-46c4-84df-14dc5a5727ef','奉和陳閣老寒食初假當直從東省往集賢因過史館看木瓜花寄張蔣二閣老','權德輿','唐','唐诗','tang','','[]','晝漏沈沈倦瑣闈，西垣東觀閱芳菲。',32,'全唐诗/poet.tang.17000.json','["晝漏沈沈倦瑣闈，西垣東觀閱芳菲。", "繁花滿樹似留客，應爲主人休澣歸。"]'),
('f2601771-41b9-4b46-91b4-654495bc659a','晚秋陪崔閣老張祕監閣老苗考功同遊昊天觀時楊閣老新直未滿以詩見寄斐然酬和有愧蕪音','權德輿','唐','唐诗','tang','','[]','方駕遊何許，仙源去似歸。',96,'全唐诗/poet.tang.17000.json','["方駕遊何許，仙源去似歸。", "縈迴留勝賞，蕭灑出塵機。", "泛菊賢人至，燒丹姹女飛。", "步虛清曉籟，隱几吸晨暉。", "竹逕琅玕合，芝田沆瀣晞。", "銀鉤三洞字，瑤笥六銖衣。", "麗句翻紅藥，佳期限紫微。", "徒然一相望，郢曲和應稀。"]'),
('7f15d641-9baa-4f39-9cfd-9af29463f6ad','春日同諸公過兵部王尚書林園','權德輿','唐','唐诗','tang','','[]','休沐君相近，時容曳履過。',48,'全唐诗/poet.tang.17000.json','["休沐君相近，時容曳履過。", "花間留客久，臺上見春多。", "松色明金艾，鶯聲雜玉珂。", "更逢新酒熟，相與藉庭莎。"]'),
('2f71697f-c14d-4a82-a975-0d58dec06e44','與沈十九拾遺同遊棲霞寺上方於亮上人院會宿二首 一','權德輿','唐','唐诗','tang','','[]','攝山標勝絕，暇日諧想矚。',144,'全唐诗/poet.tang.17000.json','["攝山標勝絕，暇日諧想矚。", "縈紆松路深，繚繞雲巖曲。", "重樓迴樹杪，古像鑿山腹。", "人遠水木清，地深蘭桂馥。", "層臺聳金碧，絕頂摩淨綠。", "下界誠可悲，南朝紛在目。", "焚香入古殿，待月出深竹。", "稍覺天籟清，自傷人世促。", "宗雷此相遇，偃放從所欲。", "清論松枝低，閑吟茗花熟。", "一生如土梗，萬慮相桎梏。", "永願事潛師，窮年此棲宿。"]'),
('7dc6be34-ad42-47da-b5fa-4236c70c4404','與沈十九拾遺同遊棲霞寺上方於亮上人院會宿二首 二','權德輿','唐','唐诗','tang','','[]','偶來人境外，心賞幸隨君。',72,'全唐诗/poet.tang.17000.json','["偶來人境外，心賞幸隨君。", "古殿煙霞夕，深山松桂薰。", "巖花點寒溜，石磴掃春雲。", "清淨諸天近，喧塵下界分。", "名僧康寶月，上客沈休文。", "共宿東林夜，清猨徹曙聞。"]'),
('b5a7df0b-5fb2-45cb-b1e0-460d80716804','題崔山人草堂','權德輿','唐','唐诗','tang','','[]','竹徑茆堂接洞天，閑時麈尾漱春泉。',32,'全唐诗/poet.tang.17000.json','["竹徑茆堂接洞天，閑時麈尾漱春泉。", "世人車馬不知處，時有歸雲到枕邊。"]'),
('3069ccd3-bb21-453b-8a1b-a5fbb40b724b','徐孺亭馬上口號','權德輿','唐','唐诗','tang','','[]','湖上荒亭臨水開，龜文篆字積莓苔。',32,'全唐诗/poet.tang.17000.json','["湖上荒亭臨水開，龜文篆字積莓苔。", "曲江北海今何處，盡逐東流去不迴。"]'),
('49e36210-6a80-4c85-bd9c-395a526fdd25','哭劉四尚書','權德輿','唐','唐诗','tang','','[]','士友惜賢人，天朝喪守臣。',144,'全唐诗/poet.tang.17000.json','["士友惜賢人，天朝喪守臣。", "才華推獨步，聲氣幸相親。", "理析寰中妙，儒爲席上珍。", "笑言成月旦，風韻挹天真。", "丹地膺推擇，青油寄撫循。", "豈言朝象魏，翻是臥漳濱。", "命賜龍泉重，追榮密印陳。", "撤弦驚物故，庀具見家貧。", "牢落風悲笛，汍瀾涕泣巾。", "只嗟蒿里月，非復柳營春。", "黃絹碑文在，青松隧路新。", "音容無處所，歸作北邙塵。"]'),
('dcb815fe-d0e0-4ac0-a417-10704e338caf','張工部至薄寒山下有書無由馳報輤車之至倍切悲懷','權德輿','唐','唐诗','tang','','[]','書來遠自薄寒山，繚繞洮河出古關。',32,'全唐诗/poet.tang.17000.json','["書來遠自薄寒山，繚繞洮河出古關。", "今日難裁秣陵報，薤歌寥落柳車邊。"]'),
('1bb6d6ff-585e-4b86-9dc0-7404bd80557d','工部發引日屬傷足臥疾不遂執紼','權德輿','唐','唐诗','tang','','[]','子春傷足日，況有寢門哀。',48,'全唐诗/poet.tang.17000.json','["子春傷足日，況有寢門哀。", "元伯歸全去，無由白馬來。", "笳簫里巷咽，龜筮墓田開。", "片石潺湲淚，含悲敘史才。"]'),
('e1e289be-bef9-4b6b-b271-0ed1c6f1bc54','從事淮南府過亡友楊校書舊廳感念愀然','權德輿','唐','唐诗','tang','','[]','故人隨化往，倏忽今六霜。',120,'全唐诗/poet.tang.17000.json','["故人隨化往，倏忽今六霜。", "及我就拘限，清風留此堂。", "松竹逾映蔚，芝蘭自銷亡。", "絕弦罷流水，聞笛同山陽。", "熲如冰玉姿，粲若鸞鳳章。", "欲翥摧勁翮，先秋落貞芳。", "正平賦鸚鵡，文考頌靈光。", "二子古不弔，夫君今何傷。", "黃墟既杳杳，玄化亦茫茫。", "豈必限宿草，含悽灑衣裳。"]'),
('f7cd0592-1ca7-4c00-a207-098ece1df847','哭李晦羣崔季文二處士','權德輿','唐','唐诗','tang','','[]','華封西祝堯，貴壽多男子。',48,'全唐诗/poet.tang.17000.json','["華封西祝堯，貴壽多男子。", "二賢無主後，貧賤大壯齒。", "未成鴻鵠姿，遽頓驊騮趾。", "子淵將叔度，自古不得已。"]'),
('54942d0c-7474-4a82-bf00-8480f20a9c40','觀葬者','權德輿','唐','唐诗','tang','','[]','塗芻隨晝哭，數里至松門。',48,'全唐诗/poet.tang.17000.json','["塗芻隨晝哭，數里至松門。", "貴盡人間禮，寧知逝者魂。", "笳簫出古陌，煙雨閉寒原。", "萬古皆如此，傷心反不言。"]'),
('bdeae999-8685-469e-a286-1438e4e1e6f9','成南陽墓','權德輿','唐','唐诗','tang','','[]','枯荄沒古基，駮蘚蔽豐碑。',24,'全唐诗/poet.tang.17000.json','["枯荄沒古基，駮蘚蔽豐碑。", "向晚微風起，如聞坐嘯時。"]'),
('ccf1691d-8325-4d04-9eda-9d8608216ba7','周平西墓','權德輿','唐','唐诗','tang','','[]','英威今寂寞，陳跡對崇丘。',48,'全唐诗/poet.tang.17000.json','["英威今寂寞，陳跡對崇丘。", "壯志清風在，荒墳白日愁。", "窮泉那復曉，喬木不知秋。", "歲歲寒塘側，無人水自流。"]'),
('bd13f463-27b3-4cfd-9d2b-f38d52f0a760','蘇小小墓','權德輿','唐','唐诗','tang','','[]','萬古荒墳在，悠然我獨尋。',48,'全唐诗/poet.tang.17000.json','["萬古荒墳在，悠然我獨尋。", "寂寥紅粉盡，冥寞黃泉深。", "蔓草映寒水，空郊曖夕陰。", "風流有佳句，吟眺一傷心。"]'),
('567cb697-b314-4363-b4d8-7980cd57c9af','題柳郎中茅山故居','權德輿','唐','唐诗','tang','','[]','下馬荒堦日欲曛，潺潺石溜靜中聞。',32,'全唐诗/poet.tang.17000.json','["下馬荒堦日欲曛，潺潺石溜靜中聞。", "鳥啼花落人聲絕，寂寞山窗掩白雲。"]'),
('6487761a-51bf-4362-9513-52c1f6c495bb','哭張十八校書','權德輿','唐','唐诗','tang','','[]','芸閣爲郎一命初，桐州寄傲十年餘。',64,'全唐诗/poet.tang.17000.json','["芸閣爲郎一命初，桐州寄傲十年餘。", "魂隨逝水歸何處，名在新詩衆不如。", "蹉跎江浦生華髮，牢落寒原會素車。", "更憶八行前日到，含悽爲報秣陵書。"]'),
('1c41fe3c-494c-4a0c-879e-b17e141c2fa7','題亡友江畔舊居','權德輿','唐','唐诗','tang','','[]','寥落留三徑，柴扉對楚江。',48,'全唐诗/poet.tang.17000.json','["寥落留三徑，柴扉對楚江。", "蠨蛸集暗壁，蜥蜴走寒窗。", "松蓋欹書幌，苔衣上酒缸。", "平生斷金契，到此淚成雙。"]'),
('2368579c-8961-482d-9699-269921d44381','德宗神武孝文皇帝挽歌詞三首 一','權德舆','唐','唐诗','tang','','[]','覆露雍熙運，澄清敎化源。',48,'全唐诗/poet.tang.17000.json','["覆露雍熙運，澄清敎化源。", "賡歌凝庶績，羽舞被深恩。", "纂業光文祖，貽謀屬孝孫。", "恭聞留末命，猶是愛元元。"]'),
('fa79bc15-0456-4883-a42f-157d4931bbbd','德宗神武孝文皇帝挽歌詞三首 二','權德舆','唐','唐诗','tang','','[]','梯航來萬國，玉帛慶三朝。',48,'全唐诗/poet.tang.17000.json','["梯航來萬國，玉帛慶三朝。", "湛露恩方浹，薰風曲正調。", "晏車悲鹵簿，廣樂遏簫韶。", "最愴號弓處，龍髯上紫霄。"]'),
('914828b6-14dd-4adb-b40f-78c40f049c87','德宗神武孝文皇帝挽歌詞三首 三','權德舆','唐','唐诗','tang','','[]','常時柏梁宴，今日穀林歸。',48,'全唐诗/poet.tang.17000.json','["常時柏梁宴，今日穀林歸。", "玉斝恩波徧，靈輼煙雨霏。", "喬山森羽騎，渭水擁旌旂。", "仙馭何由見，耘田鳥自飛。"]'),
('95fb739e-2585-46c3-8023-bc00b2c99165','順宗至德大安孝皇帝挽歌三首 一','權德舆','唐','唐诗','tang','','[]','十葉開昌運，三辰麗德音。',48,'全唐诗/poet.tang.17000.json','["十葉開昌運，三辰麗德音。", "薦功期瘞玉，昭儉每捐金。", "解澤皇風徧，虞泉白日沈。", "仍聞起居注，焚奏感人心。"]'),
('56930e4b-289a-4014-a9aa-18080e622de8','順宗至德大安孝皇帝挽歌三首 二','權德舆','唐','唐诗','tang','','[]','孝理本憂勤，玄功在嗇神。',48,'全唐诗/poet.tang.17000.json','["孝理本憂勤，玄功在嗇神。", "睿圖傳上嗣，壽酒比家人。", "仙馭三清遠，行宮萬象新。", "小臣司吉從，還扈屬車塵。"]'),
('381d5e89-7ca5-410a-b3ea-7c601df4f563','順宗至德大安孝皇帝挽歌三首 三','權德舆','唐','唐诗','tang','','[]','候曉傳清蹕，迎風引綵旒。',48,'全唐诗/poet.tang.17000.json','["候曉傳清蹕，迎風引綵旒。", "共瞻宮輅出，遙想望陵愁。", "弓劒隨雲氣，衣冠奉月游。", "空餘駕龍處，搖落鼎湖秋。"]'),
('14eb3310-7dd1-4406-bc53-3f826d431843','昭德皇后挽歌詞','權德舆','唐','唐诗','tang','','[]','淮水源流遠，塗山禮命升。',48,'全唐诗/poet.tang.17000.json','["淮水源流遠，塗山禮命升。", "往年求故劒，今夕祔初陵。", "鸞鏡金波澀，翬衣玉彩凝。", "千年子孫慶，孝理在蒸蒸。"]'),
('6045bca2-8b33-4962-b50d-b6527e6ea24f','大行皇太后挽歌詞三首 一','權德舆','唐','唐诗','tang','','[]','筮水靈源濬，因山祔禮崇。',48,'全唐诗/poet.tang.17000.json','["筮水靈源濬，因山祔禮崇。", "從龍開隧路，合璧向方中。", "殿帳金根出，廞衣玉座空。", "唯餘文母化，陰德滿公宮。"]'),
('60b22d72-6e53-4812-99e7-cf7b8681c701','大行皇太后挽歌詞三首 二','權德舆','唐','唐诗','tang','','[]','配禮歸清廟，靈儀出直城。',48,'全唐诗/poet.tang.17000.json','["配禮歸清廟，靈儀出直城。", "九虞寧厚載，一惠易尊名。", "曉漏銅壺澀，秋風羽翣輕。", "容車攀望處，孺慕切皇情。"]'),
('19f5fb5a-7849-4a74-8e78-e7c511faf04a','大行皇太后挽歌詞三首 三','權德舆','唐','唐诗','tang','','[]','哀笳出長信，寶劒入延津。',48,'全唐诗/poet.tang.17000.json','["哀笳出長信，寶劒入延津。", "嗚咽宮車進，淒涼祠殿新。", "青烏靈兆久，白燕瑞書頻。", "從此山園夕，金波照玉塵。"]'),
('d9e01ea9-b222-43fb-a9e4-423a53eeb242','惠昭皇太子挽歌詞二首 一','權德舆','唐','唐诗','tang','','[]','前星落慶霄，薤露逐晨飆。',48,'全唐诗/poet.tang.17000.json','["前星落慶霄，薤露逐晨飆。", "宮仗黃麾出，仙遊紫府遙。", "空嗟鳳吹去，無復雞鳴朝。", "今夜西園月，重輪更寂寥。"]'),
('e351d228-3908-46e1-950d-5eb4de55f042','惠昭皇太子挽歌詞二首 二','權德舆','唐','唐诗','tang','','[]','東朝聞楚挽，羽翿依稀轉。',48,'全唐诗/poet.tang.17000.json','["東朝聞楚挽，羽翿依稀轉。", "天歸京兆新，日與長安遠。", "蘭芳落故殿，桂影銷空苑。", "騎吹咽不前，風悲九旗卷。"]'),
('d0393c9a-703b-4c85-9a10-aea7b9aaeb21','贈文敬太子挽歌詞二首 一','權德舆','唐','唐诗','tang','','[]','盤石公封重，瑤山贈禮尊。',48,'全唐诗/poet.tang.17000.json','["盤石公封重，瑤山贈禮尊。", "歸全榮備物，樂善積深恩。", "鴈沼寒波咽，鸞旌夕吹翻。", "唯餘西靡樹，千古霸陵原。"]'),
('2e391fb8-f3ae-46db-b83f-d00ddf5ea2a1','贈文敬太子挽歌詞二首 二','權德舆','唐','唐诗','tang','','[]','銅壺曉漏初，羽翣擁塗車。',48,'全唐诗/poet.tang.17000.json','["銅壺曉漏初，羽翣擁塗車。", "方外留鴻寶，人間得善書。", "清笳悲畫綬，朱邸散長裾。", "還似緱山駕，飄飄向碧虛。"]'),
('e2932509-d3fd-4cea-aecd-68822661f74c','贈鄭國莊穆公主挽歌二首 一','權德舆','唐','唐诗','tang','','[]','追飾崇湯沐，遺芳藹禁闈。',48,'全唐诗/poet.tang.17000.json','["追飾崇湯沐，遺芳藹禁闈。", "秋原森羽衛，夜壑掩容輝。", "睿藻悲難盡，公宮望不歸。", "笳簫向煙霧，疑是綵鸞飛。"]'),
('d16672f0-646c-4ab1-95d6-4ae1e46fdf4f','贈鄭國莊穆公主挽歌二首 二','權德舆','唐','唐诗','tang','','[]','舊館閉平陽，容車啓壽堂。',48,'全唐诗/poet.tang.17000.json','["舊館閉平陽，容車啓壽堂。", "霜凝蕣英落，風度薤歌長。", "淑德圖書在，皇慈禮命彰。", "淒涼霸川曲，壟樹已成行。"]'),
('23daec9c-1d95-4365-86c9-95f4cad539d8','贈魏國憲穆公主挽歌詞二首 一','權德舆','唐','唐诗','tang','','[]','漢制榮車服，周詩美肅雍。',48,'全唐诗/poet.tang.17000.json','["漢制榮車服，周詩美肅雍。", "禮尊同姓主，恩錫大名封。", "外館留圖史，陰堂閉德容。", "睿詞悲薤露，千古仰芳蹤。"]'),
('3e68d3e1-3f45-411f-89dd-699d7d6e717c','贈魏國憲穆公主挽歌詞二首 二','權德舆','唐','唐诗','tang','','[]','秦樓曉月殘，鹵簿列材官。',48,'全唐诗/poet.tang.17000.json','["秦樓曉月殘，鹵簿列材官。", "紅綬蘭桂歇，粉田風露寒。", "凝笳悲駟馬，清鏡掩孤鸞。", "愍冊徽音在，都人雪涕看。"]'),
('e92e574c-8f1d-4b8b-9fb8-689c3be89ee1','贈梁國惠康公主挽歌詞二首 一','權德舆','唐','唐诗','tang','','[]','外館嬪儀貴，中參睿渥深。',48,'全唐诗/poet.tang.17000.json','["外館嬪儀貴，中參睿渥深。", "初笄橫白玉，盛服鏤黃金。", "風度簫聲遠，河低婺彩沈。", "夜臺留冊諡，悽愴即徽音。"]'),
('d0ffaa5d-7c3b-4cae-a04a-3c218eb5e990','贈梁國惠康公主挽歌詞二首 二','權德舆','唐','唐诗','tang','','[]','杳靄異湘川，飄颻駕紫煙。',48,'全唐诗/poet.tang.17000.json','["杳靄異湘川，飄颻駕紫煙。", "鳳樓人已去，鸞鏡月空懸。", "霧濕湯沐地，霜凝脂粉田。", "音容無處所，應在玉皇前。"]'),
('11ae732b-6b28-4140-b7ab-d44d21b53561','故太尉兼中書令贈太師西平王挽詞','權德舆','唐','唐诗','tang','','[]','翊戴推元老，謀猷合大君。',48,'全唐诗/poet.tang.17000.json','["翊戴推元老，謀猷合大君。", "河山封故地，金石表新墳。", "劒履歸長夜，笳簫咽暮雲。", "還經誓師處，薤露不堪聞。"]'),
('3ed45e35-f04c-4ce2-838c-80fdc0e1f58e','故司徒兼侍中贈太傅北平王挽詞','權德舆','唐','唐诗','tang','','[]','授律勳庸盛，居中鼎鼐和。',48,'全唐诗/poet.tang.17000.json','["授律勳庸盛，居中鼎鼐和。", "佐時調四氣，盡力淨三河。", "忽訪天京兆，空傳漢伏波。", "今朝麟閣上，偏軫聖情多。"]'),
('9c2e9bc9-e7a3-459b-8c90-e3aefae8d962','奉和禮部尚書酬楊著作竹亭歌','權德舆','唐','唐诗','tang','','[]','直城朱戶相邐連，九逵丹轂聲闐闐。',220,'全唐诗/poet.tang.17000.json','["直城朱戶相邐連，九逵丹轂聲闐闐。", "春官自有花源賞，終日南山當目前。", "晨搖玉佩趨溫室，莫入竹溪疑洞天。", "煙銷雨過看不足，晴翠鮮飆逗深谷。", "獨謠一曲泛流霞，閑對千竿連淨綠。", "縈迴疏鑿隨勝地，石磴巖扉光景異。", "虛齋寂寂清籟唫，幽澗紛紛雜英墜。", "家承麟趾貴，劒有龍泉賜。", "上奉明時事無事，人間方外興偏多。", "能以簪纓狎薜蘿，常通內學青蓮偈。", "更奏新聲白雪歌，風入松，雲歸棟。", "鴻飛滅處猶目送，蝶舞閑時夢忽成。", "蘭臺有客敘交情，返照中林曳履聲。", "直爲君恩催造膝，東方辨色謁承明。"]'),
('0eabe0a2-cd14-4ced-97d2-bffd50579e26','奉和張僕射朝天行','權德舆','唐','唐诗','tang','','[]','元侯重寄貞師律，三郡四封今靜謐。',288,'全唐诗/poet.tang.17000.json','["元侯重寄貞師律，三郡四封今靜謐。", "丹轂常思闕下來，紫泥忽自天中出。", "軍裝喜氣倍趨程，千騎鳴珂入鳳城。", "周王致理稱申甫，今日賢臣見明主。", "拜恩稽首紛無已，凝旒前席皇情喜。", "逢時自是山出雲，獻可還同石投水。", "昔歲褒衣梁甫吟，當時已有致君心。", "專城一鼓妖氛靜，擁斾十年天澤深。", "日日披誠奉昌運，王人織路傳清問。", "仙醞嘗分玉斝濃，御閑更輟金羈駿。", "元正前殿朝君臣，一人負扆百福新。", "宮懸綵仗儼然合，瑞氣爐煙相與春。", "萬年枝上東風早，珮玉晨趨光景好。", "塗山已見首諸侯，麟閣終當畫元老。", "溫室沈沈漏刻移，退朝賓侶每相隨。", "雄詞樂職波濤闊，曠度交歡雲霧披。", "自古全才貴文武，懦夫只解冠章甫。", "見公抽匣百鍊光，試欲磨鉛諒無助。"]'),
('5f07c915-4af5-406f-b475-1b66ed3d8a7d','和李中丞慈恩寺清上人院牡丹花歌','權德舆','唐','唐诗','tang','','[]','澹蕩韶光三月中，牡丹偏自占春風。',128,'全唐诗/poet.tang.17000.json','["澹蕩韶光三月中，牡丹偏自占春風。", "時過寶地尋香徑，已見新花出故叢。", "曲水亭西杏園北，濃芳深院紅霞色。", "擢秀全勝珠樹林，結根幸在青蓮城。", "豔蘂鮮房次第開，含煙洗露照蒼苔。", "龐眉依杖禪僧起，輕翅縈枝舞蝶來。", "獨坐南臺時共美，閑行古剎情何已。", "花間一曲奏陽春，應爲芬芳比君子。"]'),
('1c167a59-3964-4e06-ae49-d65cd16365f5','錫杖歌送明楚上人歸佛川','權德舆','唐','唐诗','tang','','[]','上人遠自西天竺，頭陁行徧國朝寺。',112,'全唐诗/poet.tang.17000.json','["上人遠自西天竺，頭陁行徧國朝寺。", "口翻貝葉古字經，手持金策聲泠泠。", "護法護身唯振錫，石瀨雲溪深寂寂。", "乍來松徑風更寒，遙映霜天月成魄。", "後夜空山禪誦時，寥寥挂在枯樹枝。", "真法常傳心不住，東西南北隨緣路。", "佛川此去何時迴，應真莫便遊天台。"]'),
('1c32b8dc-af32-4775-b167-6bfaa08fd799','馬秀才草書歌','權德舆','唐','唐诗','tang','','[]','伯英草聖稱絕倫，後來學者無其人。',160,'全唐诗/poet.tang.17000.json','["伯英草聖稱絕倫，後來學者無其人。", "白眉年少未弱冠，落紙紛紛運纖腕。", "初聞之子十歲餘，當時時輩皆不如。", "猶輕昔日墨池學，未許前賢團扇書。", "豔彩芳姿相點綴，水映荷花風轉蕙。", "三春併向指下生，萬象爭分筆端勢。", "有時當暑如清秋，滿堂風雨寒颼颼。", "乍疑崩崖瀑水落，又見古木飢鼯愁。", "變化縱橫出新意，眼看一字千金貴。", "憶昔謝安問獻之，時人雖見那得知。"]'),
('50074313-0ec0-4b54-b73d-839bea9f1edd','離合詩贈張監閣老','權德舆','唐','唐诗','tang','','[]','黃葉從風散，暗嗟時節換。',72,'全唐诗/poet.tang.17000.json','["黃葉從風散，暗嗟時節換。", "忽見鬢邊霜，勿辭林下觴。", "躬行君子道，身負芳名早。", "帳殿漢官儀，巾車塞垣草。", "交情劇斷金，文律每招尋。", "始知蓬山下，如見古人心。"]'),
('ad3162f3-ffc3-48ff-9746-e4f19c0c1342','春日雪酬潘孟陽迴文','權德舆','唐','唐诗','tang','','[]','酒杯春醉好，飛雪晚庭閑。',24,'全唐诗/poet.tang.17000.json','["酒杯春醉好，飛雪晚庭閑。", "久憶同前賞，中林對遠山。"]'),
('387c52cf-4fa1-47ac-87a2-4fe2fc025e86','五雜組','權德舆','唐','唐诗','tang','','[]','五雜組，旗亭客。',24,'全唐诗/poet.tang.17000.json','["五雜組，旗亭客。", "往復還，城南陌。", "不得已，天涯謫。"]'),
('57788483-fa7b-4908-8315-878211693545','數名詩','權德舆','唐','唐诗','tang','','[]','一區楊雄宅，恬然無所欲。',120,'全唐诗/poet.tang.17000.json','["一區楊雄宅，恬然無所欲。", "二頃季子田，歲晏常自足。", "三端固爲累，事物反徽束。", "四體苟不動，安得豐菽粟。", "五侯誠暐曄，榮甚或爲辱。", "六翮未鶱翔，虞羅乃相觸。", "七人稱作者，杳杳有遐躅。", "八桂挺奇姿，森森照初旭。", "九歌傷澤畔，怨思徒刺促。", "十翼有格言，幽貞謝浮俗。"]'),
('5c81fa14-3388-49bf-af9d-f425ec3b522d','星名詩','權德舆','唐','唐诗','tang','','[]','虛懷何所欲，歲晏聊懶逸。',72,'全唐诗/poet.tang.17000.json','["虛懷何所欲，歲晏聊懶逸。", "雲翼謝翩翻，松心保貞實。", "風秋景氣爽，葉落井逕出。", "陶然美酒酣，所謂幽人吉。", "自當輕尺璧，豈復埽一室。", "安用簪進賢，少微斯可必。"]'),
('4d10dc89-51e6-415d-9389-cf5af5d71c73','卦名詩','權德舆','唐','唐诗','tang','','[]','節變忽驚春，臨風騁望頻。',72,'全唐诗/poet.tang.17000.json','["節變忽驚春，臨風騁望頻。", "支頤倦書幌，步履整山巾。", "時鳥漸成曲，雜芳隨意新。", "曙霞連觀闕，綺陌麗咸秦。", "天地今交泰，雲雷背遘屯。", "中孚諒可樂，書此示家人。"]'),
('8d3cc50a-68bc-482d-b911-171a8e667d1b','藥名詩','權德舆','唐','唐诗','tang','','[]','七澤蘭芳千里春，瀟湘花落石磷磷。',32,'全唐诗/poet.tang.17000.json','["七澤蘭芳千里春，瀟湘花落石磷磷。", "有時浪白微風起，坐釣藤陰不見人。"]'),
('45c3b8e3-0f3a-4f93-bc3e-6e6f9af38482','古人名詩','權德舆','唐','唐诗','tang','','[]','藩宣秉戎寄，衡石崇勢位。',120,'全唐诗/poet.tang.17000.json','["藩宣秉戎寄，衡石崇勢位。", "年紀信不留，弛張良自愧。", "樵蘇則爲愜，瓜李斯可畏。", "不顧榮官尊，每陳豐畝利。", "家林類巖巘，負郭躬斂積。", "忌滿寵生嫌，養蒙恬勝智。", "疎鐘皓月曉，晚景丹霞異。", "澗谷永不諼，山梁冀無累。", "頗符生肇學，得展禽尚志。", "從此直不疑，支離疎世事。"]'),
('62230011-0a84-4370-8651-879a5a6ad72c','州名詩寄道士','權德舆','唐','唐诗','tang','','[]','金蘭同道義，瓊簡復芝田。',48,'全唐诗/poet.tang.17000.json','["金蘭同道義，瓊簡復芝田。", "平楚白雲合，幽崖丹桂連。", "松峯明愛景，石竇納新泉。", "冀永南山壽，歡隨萬福延。"]'),
('cb9df600-b1c0-447e-ae8d-c6ac86e0d21e','八音詩','權德舆','唐','唐诗','tang','','[]','金谷盛繁華，涼臺列簪組。',96,'全唐诗/poet.tang.17000.json','["金谷盛繁華，涼臺列簪組。", "石崇留客醉，綠珠當座舞。", "絲淚可銷骨，冶容竟何補。", "竹林諒賢人，滿酌無所苦。", "匏居容宴豆，儒室貴環堵。", "土鼓與污尊，頤神則爲愈。", "革道當在早，謙光斯可取。", "木鴈才不才，吾知養生主。"]'),
('bb6982c8-4d92-4a8d-8b0c-dbe7b324219c','建除詩','權德舆','唐','唐诗','tang','','[]','建節出王都，雄雄大丈夫。',144,'全唐诗/poet.tang.17000.json','["建節出王都，雄雄大丈夫。", "除書加右職，騎吏擁前驅。", "滿月張繁弱，含霜耀鹿盧。", "平明躍騕褭，清夜擊珊瑚。", "定遠功那比，平津策乃迂。", "執心思報國，效節在忘軀。", "破膽銷丹浦，顰蛾舞綠珠。", "危冠徒自愛，長轂事應殊。", "成績封千室，疇勞使五符。", "收功輕驃衛，致埋邁黃虞。", "開濟今如此，英威古不侔。", "閉關草玄者，無乃誤爲儒。"]'),
('2818da83-b661-4ff4-83a1-838a53154938','六府詩','權德舆','唐','唐诗','tang','','[]','金罍暎玉俎，賓友紛宴喜。',72,'全唐诗/poet.tang.17000.json','["金罍暎玉俎，賓友紛宴喜。", "木蘭泛方塘，桂酒啓皓齒。", "水榭臨空迥，酣歌當座起。", "火雲散奇峯，瑤瑟韻清徴。", "土梗乃虛論，康莊有逸軌。", "穀成一編書，談笑佐天子。"]'),
('4a1b83a6-a6fc-48bc-9dca-c1d62cf3fe5b','三婦詩','權德舆','唐','唐诗','tang','','[]','大婦刺繡文，中婦縫羅裙。',36,'全唐诗/poet.tang.17000.json','["大婦刺繡文，中婦縫羅裙。", "小婦無所作，嬌歌遏行雲。", "丈人且安坐，金爐香正薰。"]'),
('6492dd68-3e5a-4e0a-9d92-b2af592a5614','安語','權德舆','唐','唐诗','tang','','[]','巖巖五岳鎮方輿，八極廓清氛祲除。',32,'全唐诗/poet.tang.17000.json','["巖巖五岳鎮方輿，八極廓清氛祲除。", "揮金得謝歸里閭，象牀角枕支體舒。"]'),
('a6ac9590-2389-49a5-ace9-5c9e1adc6e6b','危語','權德舆','唐','唐诗','tang','','[]','被病獨行逢乳虎，狂風駭浪失櫂櫓。',32,'全唐诗/poet.tang.17000.json','["被病獨行逢乳虎，狂風駭浪失櫂櫓。", "舉人看牓聞曉鼓，孱夫孽子遇妬母。"]'),
('049fb798-fe8b-44c2-aebd-075a3ee695b9','大言','權德舆','唐','唐诗','tang','','[]','華嵩爲佩河爲帶，南交北朔跬步內。',32,'全唐诗/poet.tang.17000.json','["華嵩爲佩河爲帶，南交北朔跬步內。", "搏鵬作臘巨鼇鱠，伸舒軼出元氣外。"]'),
('397d50fd-79fc-4c11-94fb-237bceee7c30','小言','權德舆','唐','唐诗','tang','','[]','醯雞伺晨駕蚊翼，毫端棘刺分畛域。',32,'全唐诗/poet.tang.17000.json','["醯雞伺晨駕蚊翼，毫端棘刺分畛域。", "蛛絲結搆聊蔭息，蟻垤崔嵬不可陟。"]'),
('8a451d5f-2d94-4fd7-92d1-335c153312bb','雜詩五首 一','權德輿','唐','唐诗','tang','','[]','婉彼嬴氏女。',48,'全唐诗/poet.tang.17000.json','["婉彼嬴氏女。", "吹簫偶蕭史，綵鸞駕非煙。", "綽約兩僊子，神期諒交感。", "相顧乃如此，豈比成都人，琴心中夜起。"]'),
('353993d4-5c9a-422c-a899-dc92bbf6ee6e','雜詩五首 二','權德輿','唐','唐诗','tang','','[]','陽臺巫山上，風雨忽清曠。',48,'全唐诗/poet.tang.17000.json','["陽臺巫山上，風雨忽清曠。", "朝雲與遊龍，變化千萬狀。", "魂交復目斷，縹緲難比況。", "蘭澤不可親，凝清坐惆悵。"]'),
('b431ecf5-b7de-4aed-83d4-d9d58e1c8a77','雜詩五首 三','權德輿','唐','唐诗','tang','','[]','淇水春正綠，上宮蘭葉齊。',48,'全唐诗/poet.tang.17000.json','["淇水春正綠，上宮蘭葉齊。", "光風兩搖蕩，鳴珮出中閨。", "一顧授橫波，千金呈瓠犀。", "徒然路傍子，怳怳復悽悽。"]'),
('7725dcec-cef1-4c84-95e7-57b2feaf2a19','雜詩五首 四','權德輿','唐','唐诗','tang','','[]','碧樹泛鮮飆，玉琴含妙曲。',48,'全唐诗/poet.tang.17000.json','["碧樹泛鮮飆，玉琴含妙曲。", "佳人掩鸞鏡，婉婉凝相矚。", "文袿映束素，香黛宜𥊑綠。", "寂寞遠懷春，何時來比目。"]'),
('39b28df8-a088-4c04-b5e6-d294e399a9bf','雜詩五首 五','權德輿','唐','唐诗','tang','','[]','含顰倚瑤瑟，丹慊結繁慮。',48,'全唐诗/poet.tang.17000.json','["含顰倚瑤瑟，丹慊結繁慮。", "失身不自還，萬恨隨玉筯。", "蘼蕪山下路，團扇秋風去。", "君看心斷時，猶在目成處。"]'),
('e3646f9c-437b-466f-ad4f-4d7782f7b1aa','廣陵詩','權德輿','唐','唐诗','tang','','[]','廣陵實佳麗，隋季此爲京。',168,'全唐诗/poet.tang.17000.json','["廣陵實佳麗，隋季此爲京。", "八方稱輻湊，五達如砥平。", "大斾映空色，笳簫發連營。", "層臺出重霄，金碧摩顥清。", "交馳流水轂，迥接浮雲甍。", "青樓旭日映，綠野春風晴。", "噴玉光照地，顰蛾價傾城。", "燈前互巧笑，陌上相逢迎。", "飄飄翠羽薄，掩映紅襦明。", "蘭麝遠不散，管弦閑自清。", "曲士守文墨，達人隨性情。", "茫茫竟同盡，冉冉將何營。", "且申今日歡，莫務身後名。", "肯學諸儒輩，書窗誤一生。"]'),
('07ff181a-394f-41cf-9c16-f5e1489cd158','古意','權德輿','唐','唐诗','tang','','[]','家人強進酒，酒後能忘情。',120,'全唐诗/poet.tang.17000.json','["家人強進酒，酒後能忘情。", "持杯未飲時，衆感紛已盈。", "明月照我房，庭柯振秋聲。", "空庭白露下，枕席涼風生。", "所思萬里餘，水闊山縱橫。", "佳期憑夢想，未曉愁雞鳴。", "願將一心人，當年歡樂平。", "長筵暎玉俎，素手彈秦箏。", "𥊑睇呈巧笑，惠音激淒清。", "此願良未果，永懷空如酲。"]'),
('d38dd760-d139-43dc-b33d-7b6c60aeebbc','雜言和常州李員外副使春日戲題十首 一','權德輿','唐','唐诗','tang','','[]','隨風柳絮輕，暎日杏花明。',24,'全唐诗/poet.tang.17000.json','["隨風柳絮輕，暎日杏花明。", "無奈花深處，流鶯三數聲。"]'),
('84b01de8-94d9-4bee-be0d-f7f39422efdf','雜言和常州李員外副使春日戲題十首 二','權德輿','唐','唐诗','tang','','[]','蘭橈畫舸轉花塘，水映風搖路漸香。',32,'全唐诗/poet.tang.17000.json','["蘭橈畫舸轉花塘，水映風搖路漸香。", "任興不知行近遠，更憐微月照鳴榔。"]'),
('759d69ef-add4-44fe-8c76-181ddaddab8e','雜言和常州李員外副使春日戲題十首 三','權德輿','唐','唐诗','tang','','[]','簷前曉色驚雙燕，戶外春風舞百花。',32,'全唐诗/poet.tang.17000.json','["簷前曉色驚雙燕，戶外春風舞百花。", "粉署可憐閑對此，唯令碧玉泛流霞。"]'),
('d5694049-628d-4422-a210-e2e5fdb30944','雜言和常州李員外副使春日戲題十首 四','權德輿','唐','唐诗','tang','','[]','枕上覺，窗外曉。',48,'全唐诗/poet.tang.17000.json','["枕上覺，窗外曉。", "怯朝光，驚曙鳥。", "花墜露，滿芳沼。", "柳如絲，風褭褭。", "佳期遠，相見少。", "試一望，魂杳渺。"]'),
('cb21da51-d0c5-450f-89d4-af3956031dd9','雜言和常州李員外副使春日戲題十首 五','權德輿','唐','唐诗','tang','','[]','閑庭無事，獨步春輝。',60,'全唐诗/poet.tang.17000.json','["閑庭無事，獨步春輝。", "韶光滿目，落蘂盈衣。", "芳樹交柯，文禽並飛。", "婉彼君子，悵然有違。", "對酒不飲，橫琴不揮。", "不揮者何，知音誠稀。"]'),
('9a54b93e-97b3-4808-ad84-348971be16a4','雜言和常州李員外副使春日戲題十首 六','權德輿','唐','唐诗','tang','','[]','江春好游衍，處處芳菲積。',48,'全唐诗/poet.tang.17000.json','["江春好游衍，處處芳菲積。", "綵舫入花津，香車依柳陌。", "綠楊煙褭褭，紅蘂鶯寂寂。", "如何愁思人，獨與風光隔。"]'),
('c0f4b3ef-8353-40a7-a27c-37d03e0379ff','雜言和常州李員外副使春日戲題十首 七','權德輿','唐','唐诗','tang','','[]','曙月漸到窗前，移尊更就芳筵。',56,'全唐诗/poet.tang.17000.json','["曙月漸到窗前，移尊更就芳筵。", "輕吹乍搖蘭燭，春光暗入花鈿。", "絲竹偏宜靜夜，綺羅共占韶年。", "不遣通宵盡醉，定知辜負風煙。"]'),
('b8e885f3-6c75-49cd-b044-7e07b376e2ae','雜言和常州李員外副使春日戲題十首 八','權德輿','唐','唐诗','tang','','[]','露洗百花新，簾開月照人。',48,'全唐诗/poet.tang.17000.json','["露洗百花新，簾開月照人。", "綠窗銷暗燭，蘭逕埽清塵。", "雙燕頻驚夢，三桃競報春。", "相思寂不語，珠淚灑紅巾。"]'),
('df746464-ff76-4402-a4b6-04bd238b3f1b','雜言和常州李員外副使春日戲題十首 九','權德輿','唐','唐诗','tang','','[]','雨歇風輕一院香，紅芳綠草接東牆。',32,'全唐诗/poet.tang.17000.json','["雨歇風輕一院香，紅芳綠草接東牆。", "春衣試出當軒立，定被鄰家暗斷腸。"]'),
('8b393d92-dcd6-4f32-9aba-f472e8f39493','雜言和常州李員外副使春日戲題十首 十','權德輿','唐','唐诗','tang','','[]','春風半，春光徧。',44,'全唐诗/poet.tang.17000.json','["春風半，春光徧。", "柳如絲，花似霰。", "歸心勞夢寐，遠目傷遊眄。", "可惜長安無限春，年年空向江南見。"]'),
('e0d628c7-f61a-41e7-8829-ce5c064aef8f','相思曲','權德輿','唐','唐诗','tang','','[]','少小別潘郎，嬌羞倚畫堂。',48,'全唐诗/poet.tang.17000.json','["少小別潘郎，嬌羞倚畫堂。", "有時裁尺素，無事約殘黃。", "鵲語臨妝鏡，花飛落繡牀。", "相思不解說，明月照空房。"]'),
('bc6626ba-c184-43f2-93ea-6f8bdc82a4de','古樂府','權德輿','唐','唐诗','tang','','[]','風光澹蕩百花吐，樓上朝朝學歌舞。',64,'全唐诗/poet.tang.17000.json','["風光澹蕩百花吐，樓上朝朝學歌舞。", "身年二八壻侍中，幼妹承恩兄尚主。", "綠窗珠箔繡鴛鴦，侍婢先焚百和香。", "鶯啼日出不知曙，寂寂羅幃春夢長。"]'),
('97ec1e0e-4be0-4a22-94ac-763f30dce680','渡江秋怨二首 一','權德輿','唐','唐诗','tang','','[]','秋江平，秋月明，孤舟獨夜萬里情。',32,'全唐诗/poet.tang.17000.json','["秋江平，秋月明，孤舟獨夜萬里情。", "萬里情，相思遠，人不見兮淚滿眼。"]'),
('40a92675-3a77-4ce1-9242-17eb287a246a','渡江秋怨二首 二','權德輿','唐','唐诗','tang','','[]','渡秋江兮渺然，望秋月兮嬋娟。',47,'全唐诗/poet.tang.17000.json','["渡秋江兮渺然，望秋月兮嬋娟。", "色如練，萬里徧，我有所思兮不得見。", "不得見兮露寒水深，耿遙夜兮傷心。"]'),
('929b6afa-418f-416d-921e-bae39cc99039','秋閨月','權德輿','唐','唐诗','tang','','[]','三五二八月如練，海上天涯應共見。',144,'全唐诗/poet.tang.17000.json','["三五二八月如練，海上天涯應共見。", "不知何處玉樓前，乍入深閨玳瑁筵。", "露濃香逕和愁坐，風動羅幃照獨眠。", "初卷珠簾看不足，斜抱箜篌未成曲。", "稍映妝臺臨綺窗，遙知不語淚雙雙。", "此時愁望知何極，萬里秋天同一色。", "靄靄遙分陌上光，迢迢對此閨中憶。", "早晚歸來歡讌同，可憐歌吹月明中。", "此夜不堪腸斷絕，願隨流影到遼東。"]'),
('c92216ac-114d-4bda-9c55-89688840f5b0','薄命篇','權德輿','唐','唐诗','tang','','[]','昔住邯鄲年尚少，只是嬌羞弄花鳥。',258,'全唐诗/poet.tang.17000.json','["昔住邯鄲年尚少，只是嬌羞弄花鳥。", "青樓碧紗大道邊，綠楊日暮風褭褭。", "嬋娟玉貌二八餘，自憐顏色花不如。", "麗質全勝秦氏女，藁砧寧用專城居。", "歲去年來年漸長，青春紅粉全堪賞。", "玉樓珠箔但閑居，南陌東城詎來往。", "韶光日日看漸遲，[摽]梅既落行有時。", "寧知燕趙娉婷子，翻嫁幽幷游俠兒。", "年年結束青絲騎，出門一去何時至。", "秋月空懸翡翠簾，春幃嬾臥鴛鴦被。", "沙塞經時不寄書，深閨愁獨意何如。", "花前拭淚情無限，月下調琴恨有餘。", "離別苦多相見少，洞房愁夢何由曉。", "閑看雙燕淚霏霏，靜對空牀魂悄悄。", "鏡裏紅顏不自禁，陌頭香騎動春心。", "爲問佳期早晚是，人人總解有黃金。"]'),
('96df801d-b5cf-4652-a219-aecf5ecda465','放歌行','權德輿','唐','唐诗','tang','','[]','夕陽不駐東流急，榮名貴在當年立。',304,'全唐诗/poet.tang.17000.json','["夕陽不駐東流急，榮名貴在當年立。", "青春虛度無所成，白首銜悲亦何及。", "拂衣西笑出東山，君臣道合俄頃間。", "一言一笑玉墀上，變化生涯如等閑。", "朱門杳杳列華戟，座中皆是王侯客。", "鳴環動珮暗珊珊，駿馬花驄白玉鞍。", "十千斗酒不知貴，半醉留賓邀盡歡。", "銀燭煌煌夜將久，侍婢金罍瀉春酒。", "春酒盛來琥珀光，暗聞蘭麝幾般香。", "乍看皓腕暎羅袖，微聽清歌發杏梁。", "雙鬟美人君不見，一一皆勝趙飛燕。", "迎杯乍舉石榴裙，勻粉時交合歡扇。", "未央鐘漏醉中聞，聯騎朝天曙色分。", "雙闕煙雲遙靄靄，五衢車馬亂紛紛。", "罷朝鳴珮驟歸鞍，今日還同昨日歡。", "歲歲年年恣遊讌，出門滿路光輝徧。", "一身自樂何足言，九族爲榮真可羨。", "男兒稱意須及時，閉門下帷人不知。", "年光看逐轉蓬盡，徒詠東山招隱詩。"]'),
('1318e5a7-c894-4bb0-a1aa-f5760e0b7f63','旅館雪晴又覩新月衆興所感因成雜言','權德輿','唐','唐诗','tang','','[]','寥寥深夜雪初晴，樓上雲開月漸明。',224,'全唐诗/poet.tang.17000.json','["寥寥深夜雪初晴，樓上雲開月漸明。", "池中片影依稀見，簾外清光遠近生。", "皎皎晴空疑破鏡，廣庭積素偏相映。", "珠簾卷却光更深，玉指持來色逾淨。", "夢覺青樓最可憐，嬋娟素魄滿寒天。", "天地寥寥同一色，秦淮楚江無限極。", "歸鴻斷猨何處聲，深閨旅館遙相憶。", "長安五侯華閣開，嘉賓列坐傾金罍。", "賞明月，翫流雪，纖手蛾眉座中設。", "清歌一聲無斷絕，夜已央，樂未闌。", "狐裘獸炭不知寒，珠環翠珮聲珊珊。", "履舃紛紜桂袖攢，朱顏倚醉盡君歡。", "人生少年全不久，相看且勸杯中酒。", "丈夫富貴自有期，映雪讀書徒白首。"]'),
('a2a9c971-c055-47e8-94ba-ab163742f747','玉臺體十二首 一','權德輿','唐','唐诗','tang','','[]','鶯啼蘭已紅，見出鳳城東。',36,'全唐诗/poet.tang.17000.json','["鶯啼蘭已紅，見出鳳城東。", "粉汗宜斜日，衣香逐上風。", "情來不自覺，暗駐五花驄。"]'),
('421ac769-e695-4a94-be7a-d49497838f29','玉臺體十二首 二','權德輿','唐','唐诗','tang','','[]','嬋娟二八正嬌羞，日暮相逢南陌頭。',32,'全唐诗/poet.tang.17000.json','["嬋娟二八正嬌羞，日暮相逢南陌頭。", "試問佳期不肯道，落花深處指青樓。"]'),
('b011a41b-ac9c-4452-b2a1-95c3adffa701','玉臺體十二首 三','權德輿','唐','唐诗','tang','','[]','隱映羅衫薄，輕盈玉腕圓。',24,'全唐诗/poet.tang.17000.json','["隱映羅衫薄，輕盈玉腕圓。", "相逢不肯語，微笑畫屏前。"]'),
('152d1b43-181b-4e0d-b726-ed75fb11a25e','玉臺體十二首 四','權德輿','唐','唐诗','tang','','[]','知向遼東去，由來幾許愁。',24,'全唐诗/poet.tang.17000.json','["知向遼東去，由來幾許愁。", "破顏君莫怪，嬌小不禁羞。"]'),
('db250770-5759-41e1-9058-45e4fbad7074','玉臺體十二首 五','權德輿','唐','唐诗','tang','','[]','樓上吹簫罷，閨中刺繡闌。',24,'全唐诗/poet.tang.17000.json','["樓上吹簫罷，閨中刺繡闌。", "佳期不可見，盡日淚潺潺。"]'),
('e0e11d93-4d60-46f0-ab86-1b2ca8e35f9a','玉臺體十二首 六','權德輿','唐','唐诗','tang','','[]','淚盡珊瑚枕，魂銷玳瑁牀。',24,'全唐诗/poet.tang.17000.json','["淚盡珊瑚枕，魂銷玳瑁牀。", "羅衣不忍著，羞見繡鴛鴦。"]'),
('14653c00-b703-4beb-8d90-acfce2cd7c0c','玉臺體十二首 七','權德輿','唐','唐诗','tang','','[]','君去期花時，花時君不至。',24,'全唐诗/poet.tang.17000.json','["君去期花時，花時君不至。", "簷前雙燕飛，落妾相思淚。"]'),
('c63932c0-3d5f-4037-96db-428334fd5aa4','玉臺體十二首 八','權德輿','唐','唐诗','tang','','[]','空閨滅燭後，羅幌獨眠時。',24,'全唐诗/poet.tang.17000.json','["空閨滅燭後，羅幌獨眠時。", "淚盡腸欲斷，心知人不知。"]'),
('8858d3ff-7e41-486a-a236-3c419457ccd1','玉臺體十二首 九','權德輿','唐','唐诗','tang','','[]','秋風一夜至，吹盡後庭花。',24,'全唐诗/poet.tang.17000.json','["秋風一夜至，吹盡後庭花。", "莫作經時別，西鄰是宋家。"]'),
('8b35c026-dbc7-4363-8301-5646e8d02adb','玉臺體十二首 十','權德輿','唐','唐诗','tang','','[]','獨自披衣坐，更深月露寒。',24,'全唐诗/poet.tang.17000.json','["獨自披衣坐，更深月露寒。", "隔簾腸欲斷，爭敢下堦看。"]'),
('9a5070c8-8b6a-46d3-a976-ce942baf42e7','玉臺體十二首 十一','權德輿','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u601d\u5ff5", "\u4e94\u8a00\u7edd\u53e5", "\u5973\u5b50"]','昨夜裙帶解，今朝蟢子飛。',24,'全唐诗/poet.tang.17000.json','["昨夜裙帶解，今朝蟢子飛。", "鉛華不可棄，莫是藁砧歸。"]'),
('46209cfd-b11b-49df-9623-856528a36167','玉臺體十二首 十二','權德輿','唐','唐诗','tang','','[]','萬里行人至，深閨夜未眠。',24,'全唐诗/poet.tang.17000.json','["萬里行人至，深閨夜未眠。", "雙眉燈下埽，不待鏡臺前。"]'),
('c8832732-e7a8-4813-becc-9832af2db960','贈友人','權德輿','唐','唐诗','tang','','[]','知向巫山逢日暮，輕袿玉佩暫淹留。',32,'全唐诗/poet.tang.17000.json','["知向巫山逢日暮，輕袿玉佩暫淹留。", "曉隨雲雨歸何處，還是襄王夢覺愁。"]'),
('2f49465c-1669-4b74-bb9b-f3afa519f9d7','舟行見月','權德輿','唐','唐诗','tang','','[]','月入孤舟夜半晴，寥寥霜鴈兩三聲。',32,'全唐诗/poet.tang.17000.json','["月入孤舟夜半晴，寥寥霜鴈兩三聲。", "洞房燭影在何處，欲寄相思夢不成。"]'),
('a74e140c-b177-40df-94df-601bfc2d3fcf','雜興五首 一','權德輿','唐','唐诗','tang','','[]','叢鬢愁眉時勢新，初笄絕代北方人。',32,'全唐诗/poet.tang.17000.json','["叢鬢愁眉時勢新，初笄絕代北方人。", "一顰一笑千金重，肯似成都夜失身。"]'),
('9979b18b-741e-456b-9da8-cf7397cb9df3','雜興五首 二','權德輿','唐','唐诗','tang','','[]','乍聽絲聲似竹聲，又疑丹穴九雛驚。',32,'全唐诗/poet.tang.17000.json','["乍聽絲聲似竹聲，又疑丹穴九雛驚。", "金波露洗淨於晝，寂寞不堪深夜情。"]'),
('758a74cd-9966-4572-8fb3-6ed51823893c','雜興五首 三','權德輿','唐','唐诗','tang','','[]','琥珀尊開月暎簾，調弦理曲指纖纖。',32,'全唐诗/poet.tang.17000.json','["琥珀尊開月暎簾，調弦理曲指纖纖。", "含羞斂態勸君住，更奏新聲刮骨鹽。"]'),
('bd802c06-6d8f-4322-800b-0001fa2b8266','雜興五首 四','權德輿','唐','唐诗','tang','','[]','乳燕雙飛鶯亂啼，百花如繡照深閨。',32,'全唐诗/poet.tang.17000.json','["乳燕雙飛鶯亂啼，百花如繡照深閨。", "新妝對鏡知無比，微笑時時出瓠犀。"]'),
('61ba3837-99d5-42c5-88de-3840dbba8e40','雜興五首 五','權德輿','唐','唐诗','tang','','[]','巫山雲雨洛川神，珠襻香腰穩稱身。',32,'全唐诗/poet.tang.17000.json','["巫山雲雨洛川神，珠襻香腰穩稱身。", "惆悵妝成君不見，含情起立問傍人。"]'),
('65930a39-b7b6-4708-9f8a-8cdc22f59f86','秖役江西路上以詩代書寄內','權德輿','唐','唐诗','tang','','[]','辛苦事行役，風波倦晨暮。',288,'全唐诗/poet.tang.17000.json','["辛苦事行役，風波倦晨暮。", "搖搖結遐心，靡靡即長路。", "別來如昨日，每見缺蟾兔。", "潮信催客帆，春光變江樹。", "宦遊豈云愜，歸夢無復數。", "愧非超曠姿，循此跼促步。", "笑言思暇日，規勸多遠度。", "鶉服我久安，荆釵君所慕。", "伊予多昧理，初不涉世務。", "適因擁腫材，成此懶慢趣。", "一身常抱病，不復理章句。", "胸中無町畦，與物且多忤。", "既非大川檝，則守南山霧。", "胡爲出處間，徒使名利污。", "羈孤望予祿，孩穉待我餔。", "未能即忘懷，恨恨以此故。", "終當稅鞿鞅，豈待畢婚娶。", "如何久人寰，俛仰學舉措。", "衡茅去迢遰，水陸兩馳騖。", "晰晰窺曉星，塗塗踐朝露。", "靜聞田鶴起，遠見沙𩾨聚。", "怪石不易躋，急湍那可泝。", "漁商聞遠岸，煙火明古渡。", "下碇夜已深，上碕波不駐。"]'),
('aa241c43-0b5c-4f97-a416-7c2536ee0484','夜泊有懷','權德輿','唐','唐诗','tang','','[]','棲鳥向前林，暝色生寒蕪。',72,'全唐诗/poet.tang.17000.json','["棲鳥向前林，暝色生寒蕪。", "孤舟去不息，衆感非一途。", "川程方浩淼，離思方鬱紆。", "轉枕眼未熟，擁衾淚已濡。", "窘然風水上，寢食疲朝晡。", "心想洞房夜，知君還向隅。"]'),
('8e4a66fe-fc87-4169-885f-7f68c69995a2','自桐廬如蘭溪有寄','權德輿','唐','唐诗','tang','','[]','東南江路舊知名，惆悵春深又獨行。',64,'全唐诗/poet.tang.17000.json','["東南江路舊知名，惆悵春深又獨行。", "新婦山頭雲半斂，女兒灘上月初明。", "風前蕩颺雙飛蝶，花裏間關百囀鶯。", "滿目歸心何處說，欹眠搔首不勝情。"]'),
('c0a7081a-75d2-4f2f-b7d3-d648bc546eed','相思樹','權德輿','唐','唐诗','tang','','[]','家寄江東遠，身對江西春。',24,'全唐诗/poet.tang.17000.json','["家寄江東遠，身對江西春。", "空見相思樹，不見相思人。"]'),
('e12a0e13-71b5-419e-bf17-2af3e1e306f2','石楠樹','權德輿','唐','唐诗','tang','','[]','石楠紅葉透簾春，憶得妝成下錦茵。',32,'全唐诗/poet.tang.17000.json','["石楠紅葉透簾春，憶得妝成下錦茵。", "試折一枝含萬恨，分明說向夢中人。"]'),
('fd5d1e99-7301-464e-a788-8e09419e449a','斗子灘','權德輿','唐','唐诗','tang','','[]','斗子灘頭夜已深，月華偏照此時心。',32,'全唐诗/poet.tang.17000.json','["斗子灘頭夜已深，月華偏照此時心。", "春江風水連天闊，歸夢悠揚何處尋。"]'),
('017c7ff5-d04b-4340-98c9-3ba532bd1913','黃蘗館','權德輿','唐','唐诗','tang','','[]','驅車振楫越山川，候曉通宵冒煙雨。',32,'全唐诗/poet.tang.17000.json','["驅車振楫越山川，候曉通宵冒煙雨。", "青楓浦上魂已銷，黃蘗館前心自苦。"]'),
('8a935cce-b030-4527-a3cc-d6cf9899924a','清明日次弋陽','權德輿','唐','唐诗','tang','','[]','自歎清明在遠鄉，桐花覆水葛溪長。',32,'全唐诗/poet.tang.17000.json','["自歎清明在遠鄉，桐花覆水葛溪長。", "家人定是持新火，點作孤燈照洞房。"]'),
('ae06c8aa-677c-41ba-b360-ed8a1f19b2cd','中書夜直寄贈','權德輿','唐','唐诗','tang','','[]','通籍在金閨，懷君百慮迷。',48,'全唐诗/poet.tang.17000.json','["通籍在金閨，懷君百慮迷。", "迢迢五夜永，脈脈兩心齊。", "步履疲青瑣，開緘倦紫泥。", "不堪風雨夜，轉枕憶鴻妻。"]'),
('acd61a32-e143-43da-b1d9-61cec3178c73','病中寓直代書題寄','權德輿','唐','唐诗','tang','','[]','愚夫何所任，多病感君深。',48,'全唐诗/poet.tang.17000.json','["愚夫何所任，多病感君深。", "自謂青春壯，寧知白髮侵。", "寢興勞善祝，疎懶愧良箴。", "寂寞聞宮漏，那堪直夜心。"]'),
('830c5d4c-c70e-4b88-837a-f25efc71be2b','端午日禮部宿齋有衣服綵結之貺以詩還荅','權德輿','唐','唐诗','tang','','["\u7aef\u5348\u8282"]','良辰當五日，偕老祝千年。',48,'全唐诗/poet.tang.17000.json','["良辰當五日，偕老祝千年。", "綵縷同心麗，輕裾暎體鮮。", "寂寥齋畫省，欵曲擘香牋。", "更想傳觴處，孫孩徧目前。"]'),
('c2612953-e483-4f76-9872-00a4270ce131','酬九日','權德輿','唐','唐诗','tang','','[]','重九共遊娛，秋光景氣殊。',24,'全唐诗/poet.tang.17000.json','["重九共遊娛，秋光景氣殊。", "他時頭似雪，還對插茱萸。"]'),
('d1b25f99-305c-4c53-b02e-d1644c528e0f','和九日從楊氏姊遊','權德輿','唐','唐诗','tang','','[]','秋光風露天，令節慶初筵。',48,'全唐诗/poet.tang.17000.json','["秋光風露天，令節慶初筵。", "易象家人吉，閨門女士賢。", "招邀菊酒會，屬和柳花篇。", "今日同心賞，全勝落帽年。"]'),
('169239cc-46c5-4ed6-a8c2-26f270402f61','上巳日貢院考雜文不遂赴九華觀祓禊之會以二絕句申贈 一','權德輿','唐','唐诗','tang','','[]','三日韶光處處新，九華仙洞七香輪。',32,'全唐诗/poet.tang.17000.json','["三日韶光處處新，九華仙洞七香輪。", "老夫留滯何由徃，珉玉相和正遶身。"]'),
('0cf4ae95-1ee9-4dfb-932a-500501e17f6e','上巳日貢院考雜文不遂赴九華觀祓禊之會以二絕句申贈 二','權德輿','唐','唐诗','tang','','[]','禊飲尋春興有餘，深情婉婉見雙魚。',32,'全唐诗/poet.tang.17000.json','["禊飲尋春興有餘，深情婉婉見雙魚。", "同心齊體如身到，臨水煩君便祓除。"]'),
('2aecdb8e-46cf-4941-a538-f5b3ed327989','和九華觀見懷貢院八韻','權德輿','唐','唐诗','tang','','[]','上巳好風景，仙家足芳菲。',96,'全唐诗/poet.tang.17000.json','["上巳好風景，仙家足芳菲。", "地殊蘭亭會，人似山陰歸。", "丹竈綴珠掩，白雲巖逕微。", "真宮集女士，虛室涵春輝。", "拘限心杳杳，歡言望依依。", "滯茲文墨職，坐與琴觴違。", "麗曲滌煩虛，幽緘發清機。", "支頤一吟想，恨不雙翻飛。"]'),
('f19c7864-67cf-4485-9b9d-a02c505ec4c7','桃源篇','權德輿','唐','唐诗','tang','','[]','小年嘗讀桃源記，忽覩良工施繪事。',160,'全唐诗/poet.tang.17000.json','["小年嘗讀桃源記，忽覩良工施繪事。", "巖逕初欣繚繞通，溪風轉覺芬芳異。", "一路鮮雲雜彩霞，漁舟遠遠逐桃花。", "漸入空濛迷島道，寧知掩映有人家。", "龐眉秀骨爭迎客，鑿井耕田人世隔。", "不知漢代有衣冠，猶說秦家變阡陌。", "石髓雲英甘且香，仙翁留飯出青囊。", "相逢自是松喬侶，良會應殊劉阮郎。", "內子閑吟倚瑤瑟，翫此沈沈銷永日。", "忽聞麗曲金玉聲，便使老夫思閣筆。"]'),
('e81f582d-b7b9-4812-817a-515e5a7cdedb','新月與兒女夜坐聽琴舉酒','權德輿','唐','唐诗','tang','','[]','泥泥露凝葉，騷騷風入林。',96,'全唐诗/poet.tang.17000.json','["泥泥露凝葉，騷騷風入林。", "以茲皓月圓，不厭良夜深。", "列坐屏輕箑，放懷弦素琴。", "兒女各冠笄，孫孩遶衣襟。", "乃知大隱趣，宛若滄洲心。", "方結偕老期，豈憚華髮侵。", "笑語向蘭室，風流傳玉音。", "愧君袖中字，價重雙南金。"]'),
('32f69392-6fb2-499a-9e8b-55081b5d48e3','七夕','權德輿','唐','唐诗','tang','','[]','今日雲軿渡鵲橋，應非脈脈與迢迢。',32,'全唐诗/poet.tang.17000.json','["今日雲軿渡鵲橋，應非脈脈與迢迢。", "家人競喜開妝鏡，月下穿針拜九霄。"]'),
('2c180065-37ac-4063-8945-1672263179d5','縣君赴興慶宮朝賀載之奉行冊禮因書即事','權德輿','唐','唐诗','tang','','[]','合巹交歡二十年，今朝比翼共朝天。',64,'全唐诗/poet.tang.17000.json','["合巹交歡二十年，今朝比翼共朝天。", "風傳漏刻香車度，日照旌旗綵仗鮮。", "顧我華簪鳴玉珮，看君盛服耀金鈿。", "相期偕老宜家處，鶴髮魚軒更可憐。"]'),
('557bcd4c-243a-44dd-adf1-cba7aa89a122','元和元年蒙恩封成紀縣伯時室中封安喜縣君感慶兼懷聊申賀贈','權德輿','唐','唐诗','tang','','[]','啓土封成紀，宜家縣安喜。',48,'全唐诗/poet.tang.17000.json','["啓土封成紀，宜家縣安喜。", "同欣井賦開，共受閨門祉。", "珩璜聯采組，琴瑟諧宮徴。", "更待懸車時，與君歡暮齒。"]'),
('d599371d-553d-409b-a105-4295f7726408','河南崔尹即安喜從兄宜于室家四十餘歲一昨寓書病傳永寫告身既枉善祝因成絕句','權德輿','唐','唐诗','tang','','[]','五色金光鸞鳳飛，三川墨妙巧相輝。',32,'全唐诗/poet.tang.17000.json','["五色金光鸞鳳飛，三川墨妙巧相輝。", "尊崇善祝今如此，共待曾玄捧翟衣。"]'),
('b78941df-0bf5-4961-b770-ed0dbf6466ca','奉使豐陵職司鹵簿通宵涉路因寄內','權德輿','唐','唐诗','tang','','[]','綵仗列森森，行宮夜漏深。',48,'全唐诗/poet.tang.17000.json','["綵仗列森森，行宮夜漏深。", "殳鋋方啓路，鉦鼓正交音。", "曙月思蘭室，前山辨穀林。", "家人念行役，應見此時心。"]'),
('2a5f6ded-1405-4526-8854-ad5a293b49b8','酬南園新亭宴會璩新第慰慶之作時任賓客','權德輿','唐','唐诗','tang','','[]','南宮煙景濃，平視中南峯。',168,'全唐诗/poet.tang.17000.json','["南宮煙景濃，平視中南峯。", "官閑似休沐，盡室來相從。", "日抱漢陰甕，或成蝴蝶夢。", "樹老欲連雲，竹深疑入洞。", "歡言交羽觴，列坐儼成行。", "歌吟不能去，待此明月光。", "好逑蘊明識，內顧多慙色。", "不厭梁鴻貧，常譏伯宗直。", "予壻信時英，諫垣金玉聲。", "男兒纔弱冠，射策幸成名。", "偃放斯自足，翛然去營欲。", "散木固無堪，虛舟常任觸。", "大隱本吾心，喜君流好音。", "相期懸車歲，此地即中林。"]'),
('939d5ee1-0a6a-4a4d-abc8-1566418ae232','七夕見與諸孫題乞巧文','權德輿','唐','唐诗','tang','','[]','外孫爭乞巧，內子共題文。',48,'全唐诗/poet.tang.17000.json','["外孫爭乞巧，內子共題文。", "隱暎花匳對，參差綺席分。", "鵲橋臨片月，河鼓掩輕雲。", "羨此嬰兒輩，歡呼徹曙聞。"]'),
('b996fb6a-c0b5-445f-8657-3599a929ab56','太常寺宿齋有寄','權德輿','唐','唐诗','tang','','[]','轉枕挑燈候曉雞，相君應歎太常妻。',32,'全唐诗/poet.tang.17000.json','["轉枕挑燈候曉雞，相君應歎太常妻。", "長年多病偏相憶，不遣歸時醉似泥。"]'),
('c98b9892-c6ab-46af-91f2-340e5659034e','朝迴閱樂寄絕句','權德輿','唐','唐诗','tang','','[]','子城風煖百花初，樓上龜茲引導車。',32,'全唐诗/poet.tang.17000.json','["子城風煖百花初，樓上龜茲引導車。", "曲罷卿卿理騶馭，細君相望意何如。"]'),
('4c6ee1a3-3f3a-4d2f-801c-af195d259c38','中書宿齋有寄','權德輿','唐','唐诗','tang','','[]','銅壺漏滴斗闌干，泛灩金波照露盤。',32,'全唐诗/poet.tang.17000.json','["銅壺漏滴斗闌干，泛灩金波照露盤。", "遙想洞房眠正熟，不堪深夜鳳池寒。"]'),
('a1b28069-1f1e-44f6-b655-8c6d19edc5b1','中書送勅賜齋饌戲酬','權德輿','唐','唐诗','tang','','[]','常日每齊眉，今朝共解頤。',24,'全唐诗/poet.tang.17000.json','["常日每齊眉，今朝共解頤。", "遙知大官膳，應與衆雛嬉。"]'),
('97215c41-72ff-4c04-b690-f6586c324f3d','勅賜長壽酒因口號以贈','權德輿','唐','唐诗','tang','','[]','恩霑長壽酒，歸遺同心人。',24,'全唐诗/poet.tang.17000.json','["恩霑長壽酒，歸遺同心人。", "滿酌共君醉，一杯千萬春。"]'),
('52fe3ab8-8248-46d2-99c7-102d601c4b12','湖南觀察使故相國袁公挽歌二首 一','權德輿','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','五驅龍虎節，一入鳳皇池。',48,'全唐诗/poet.tang.17000.json','["五驅龍虎節，一入鳳皇池。", "令尹自無喜，羊公人不疑。", "天歸京兆日，葉下洞庭時。", "湘水秋風至，淒涼吹素旗。"]'),
('3b4a1b7f-9c59-43ef-abe2-93047d6b6a0f','湖南觀察使故相國袁公挽歌二首 二','權德輿','唐','唐诗','tang','','[]','丹旐發江臯，人悲鴈亦號。',48,'全唐诗/poet.tang.17000.json','["丹旐發江臯，人悲鴈亦號。", "湘南罷亥市，漢上改詞曹。", "表墓雙碑立，尊名一字襃。", "常聞平楚獄，爲報里門高。"]'),
('6d8508dc-2a87-446b-8b86-610535a406a6','玉山嶺上作','權德輿','唐','唐诗','tang','','[]','悠悠驅匹馬，征路上連岡。',48,'全唐诗/poet.tang.17000.json','["悠悠驅匹馬，征路上連岡。", "晚翠深雲竇，寒苔淨石梁。", "荻花偏似雪，楓葉不禁霜。", "愁見前程遠，空郊下夕陽。"]'),
('06682a26-33db-4a60-877d-53f68f6de57f','題邵端公林亭','權德輿','唐','唐诗','tang','','[]','春光何處好，柱史有林塘。',48,'全唐诗/poet.tang.17000.json','["春光何處好，柱史有林塘。", "鶯囀風初暖，花開日欲長。", "鑿池通野水，掃徑閱新芳。", "更置盈尊酒，時時醉楚狂。"]'),
('f7c5a05e-436c-4fd9-b093-3886e90cd529','酬裴傑秀才新櫻桃','權德輿','唐','唐诗','tang','','[]','新果真瓊液，來應宴紫蘭。',72,'全唐诗/poet.tang.17000.json','["新果真瓊液，來應宴紫蘭。", "圓疑竊龍頷，色已奪雞冠。", "遠火微微辨，殘星隱隱看。", "茂先知味易，曼倩恨偷難。", "忍用烹騂駱，從將翫玉盤。", "流年如可駐，何必九華丹。"]'),
('0f01c56b-709e-4bfb-b1ff-1d4b9c366802','次滕老莊','權德輿','唐','唐诗','tang','','[]','征途無旅館，當晝喜逢君。',24,'全唐诗/poet.tang.17000.json','["征途無旅館，當晝喜逢君。", "羸病仍留客，朝朝掃白雲。"]'),
('17c8d328-f828-4069-b3a0-6ac70497f3b6','宿嚴陵','權德輿','唐','唐诗','tang','','[]','身羈從事驅征傳，江入新安泛暮濤。',32,'全唐诗/poet.tang.17000.json','["身羈從事驅征傳，江入新安泛暮濤。", "今夜子陵灘下泊，自慙相去九牛毛。"]'),
('24699abe-2779-4f87-ac05-50f72f052c77','題雲師山房','權德輿','唐','唐诗','tang','','[]','雲公蘭若深山裏，月明松殿微風起。',32,'全唐诗/poet.tang.17000.json','["雲公蘭若深山裏，月明松殿微風起。", "試問空門清淨心，蓮花不著秋潭水。"]'),
('50adab66-404f-48e4-bcab-f6c11d56846d','棲霞寺雲居室','權德輿','唐','唐诗','tang','','[]','一徑縈紆至此窮，山僧盥漱白雲中。',32,'全唐诗/poet.tang.17000.json','["一徑縈紆至此窮，山僧盥漱白雲中。", "閑吟定後更何事，石上松枝常有風。"]'),
('f9388acc-9645-4056-9950-00d258ebcda6','舟行夜泊','權德輿','唐','唐诗','tang','','[]','蕭蕭落葉送殘秋，寂寞寒波急暝流。',32,'全唐诗/poet.tang.17000.json','["蕭蕭落葉送殘秋，寂寞寒波急暝流。", "今夜不知何處泊，斷猨晴月引孤舟。"]'),
('43f374a9-522c-4e88-92ce-426d01946d7c','發硤石路上却寄內','權德輿','唐','唐诗','tang','','[]','莎柵東行五谷深，千峯萬壑雨沈沈。',32,'全唐诗/poet.tang.17000.json','["莎柵東行五谷深，千峯萬壑雨沈沈。", "細君幾日路經此，應見悲翁相望心。"]'),
('0b984031-a4e2-4e84-a151-d88548c46042','冬至宿齋時郡君南內朝謁因寄','權德輿','唐','唐诗','tang','','[]','清齋獨向丘園拜，盛服想君興慶朝。',32,'全唐诗/poet.tang.17000.json','["清齋獨向丘園拜，盛服想君興慶朝。", "明日一陽生百福，不辭相望阻寒宵。"]'),
('28b340d8-51b9-4204-9299-435c52052a79','和河南羅主簿送校書兄歸江南','權德輿','唐','唐诗','tang','','[]','兄弟泣殊方，天涯指故鄉。',96,'全唐诗/poet.tang.17000.json','["兄弟泣殊方，天涯指故鄉。", "斷雲無定處，歸鴈不成行。", "草莽人煙少，風波水驛長。", "上虞親渤澥，東楚隔瀟湘。", "古戍陰傳火，寒蕪曉帶霜。", "海門潮灩灩，沙岸荻蒼蒼。", "京輦辭芸閣，衡方憶草堂。", "知君始寧隱，還緝舊荷裳。"]'),
('cc8f6efd-2404-4797-a014-894d28b8ac4b','與故人夜坐道舊','權德輿','唐','唐诗','tang','','[]','笑語歡今夕，煙霞愴昔遊。',48,'全唐诗/poet.tang.17000.json','["笑語歡今夕，煙霞愴昔遊。", "清羸還對月，遲暮更逢秋。", "勝理方自得，浮名不在求。", "終當製初服，相與臥林丘。"]'),
('4e6d9628-9907-4001-986c-5ffd78b68d05','句','權德輿','唐','唐诗','tang','','[]','耒水波紋細，湘江竹葉輕。',84,'全唐诗/poet.tang.17000.json','["耒水波紋細，湘江竹葉輕。", "古時樓上清明夜，月照樓前撩亂花。", "今日成陰復成子，可憐春盡未歸家。", "新婦磯頭雲半歛，女兒灘畔月初明。", "迴合千峰裏，晴光似畫圖。", "征車隨反照，候吏暎白雲。"]'),
('35bc218a-0814-4ae9-bb01-1c33852426d2','奉酬禮部閣老轉韻離合見贈','張薦','唐','唐诗','tang','','[]','移居既同里，多幸陪君子。',72,'全唐诗/poet.tang.17000.json','["移居既同里，多幸陪君子。", "弘雅重當朝，弓旌早見招。", "植根瓊林圃，直夜金閨步。", "勸深子玉銘，力競相如賦。", "間闊向春闈，日復想光儀。", "格言信難繼，木石強爲詞。"]'),
('8ffca718-321a-48fe-9c7a-d46d59d32934','和潘孟陽春日雪迴文絕句','張薦','唐','唐诗','tang','','[]','遲遲日氣暖，漫漫雪天春。',24,'全唐诗/poet.tang.17000.json','["遲遲日氣暖，漫漫雪天春。", "知君欲醉飲，思見此交親。"]'),
('829fdca5-f440-4cb0-9f7c-edea5d7b6739','享文恭太子廟樂章','張薦','唐','唐诗','tang','','[]','三獻具舉，九旗將旋。',40,'全唐诗/poet.tang.17000.json','["三獻具舉，九旗將旋。", "追勞表德，罷享賓天。", "風引仙管，堂虛畫筵。", "芳馨常在，瞻望悠然。"]'),
('959bb5a4-0311-4226-a86f-d057032e62d7','禮部權侍郎閣老史館張秘監閣老有離合酬贈之什宿直吟翫聊繼此章','崔邠','唐','唐诗','tang','','[]','脉脉羨佳期，月夜吟麗詞。',72,'全唐诗/poet.tang.17000.json','["脉脉羨佳期，月夜吟麗詞。", "諫垣則隨步，東觀方承顧。", "林雪消豔陽，簡冊漏華光。", "坐更芝蘭室，千載各芬芳。", "節苦文俱盛，即時人竝命。", "翩翻紫霄中，羽翮相輝映。"]'),
('69c51939-a750-47b5-950e-b70fdb31472f','享文恭太子廟樂章','崔邠','唐','唐诗','tang','','[]','醴齊泛罇彝，軒縣動干戚。',48,'全唐诗/poet.tang.17000.json','["醴齊泛罇彝，軒縣動干戚。", "入室僾如在，升階虔所歷。", "舊疾合威容，定利舒皦澤。", "方崇廟貌禮，永被君恩錫。"]'),
('13219d7a-60e9-4869-9de5-aca4d970f369','和權載之離合詩','楊於陵','唐','唐诗','tang','','[]','校德盡珪璋，才臣時所揚。',72,'全唐诗/poet.tang.17000.json','["校德盡珪璋，才臣時所揚。", "放情寄文律，方茂經邦術。", "王猷符發揮，十載契心期。", "晝遊有嘉話，書法無隱辭。", "信茲酧和美，言與芝蘭比。", "昨來恣吟繹，日覺祛蒙鄙。"]'),
('1b706f51-babf-4b3b-bab4-371f66ad586b','郡齋有紫薇雙本自朱明接于徂暑其花芳馥數旬猶茂庭宇之內逈無其倫予嘉其美而能久因詩紀述','楊於陵','唐','唐诗','tang','','[]','晏朝受明命，繼夏走天衢。',168,'全唐诗/poet.tang.17000.json','["晏朝受明命，繼夏走天衢。", "逮茲三伏候，息駕萬里途。", "省躬既跼蹐，結思多煩紆。", "簿領幸無事，宴休誰與娛。", "內齋有嘉樹，雙植分庭隅。", "綠葉下成幄，紫花紛若鋪。", "摛霞晚舒豔，凝露朝垂珠。", "炎沴晝方鑠，幽姿閑且都。", "夭桃固難匹，芍藥寧爲徒。", "懿此時節久，詎同光景驅。", "陶甄試一致，品彙乃散殊。", "濯質非受彩，無心那奪朱。", "粤予負羈縶，留賞益踟躕。", "通夕靡云倦，西南山月孤。"]'),
('0bcb1efa-2174-4d1d-9549-4112d208b8fd','贈毛仙翁','楊於陵','唐','唐诗','tang','','[]','先生赤松侶，混俗遊人間。',48,'全唐诗/poet.tang.17000.json','["先生赤松侶，混俗遊人間。", "崑閬無窮路，何時下故山。", "千年猶孺質，秘術救塵寰。", "莫便沖天去，雲雷不可攀。"]'),
('6445e06e-5ec4-4a46-8b1d-83b492a0fec5','荅權載之離合詩','許孟容','唐','唐诗','tang','','[]','史才司秘府，文哲今超古。',72,'全唐诗/poet.tang.17000.json','["史才司秘府，文哲今超古。", "亦有擅風騷，六聯文墨曹。", "聖賢三代意，工藝千金字。", "化識從臣謠，人推仙閣吏。", "如登崑閬時，口誦靈真詞。", "孫簡下威鳳，系霜瓊玉枝。"]'),
('54f7ec2d-da01-4743-86fa-c6c7a5fb3925','奉和武相公春曉聞鶯','許孟容','唐','唐诗','tang','','[]','碧樹當窗啼曉鶯，間關入夢聽難成。',32,'全唐诗/poet.tang.17000.json','["碧樹當窗啼曉鶯，間關入夢聽難成。", "千回萬囀盡愁思，疑是血魂哀困聲。"]'),
('c9a529af-e423-4fa0-958e-71b6758e84fe','享文恭太子廟樂章','許孟容','唐','唐诗','tang','','[]','觴牢具品，管弦有節。',40,'全唐诗/poet.tang.17000.json','["觴牢具品，管弦有節。", "祝道寅恭，神儀昭晰。", "桐珪早貴，象輅追設。", "罄達樂成，降歆豐潔。"]'),
('954c6e24-7265-46f5-8331-dfe1d59af786','和權載之離合詩','馮伉','唐','唐诗','tang','','[]','車馬退朝後，聿懷在文友。',72,'全唐诗/poet.tang.17000.json','["車馬退朝後，聿懷在文友。", "動詞宗伯雄，重美良史功。", "亦曾吟鮑謝，二妙尤增價。", "雨霜鴻唳天，匝樹鳥鳴夜。", "覃思各縱橫，早擅希代名。", "息心欲焚硯，自靦陪羣英。"]'),
('37800dd9-895c-4fcc-8bb6-3ce8f3437c21','享文恭太子廟樂章二首 一','馮伉','唐','唐诗','tang','','[]','撰日瞻景，誠陳樂張。',40,'全唐诗/poet.tang.17000.json','["撰日瞻景，誠陳樂張。", "禮容秩秩，羽舞煌煌。", "肅將滌濯，祗薦芬芳。", "永錫繁祉，思深享嘗。"]'),
('6f50a741-7508-4119-b111-861b797c94c6','享文恭太子廟樂章二首 二','馮伉','唐','唐诗','tang','','[]','干旄羽籥相虧蔽，一進一退殊行綴。',32,'全唐诗/poet.tang.17000.json','["干旄羽籥相虧蔽，一進一退殊行綴。", "昔獻三雍盛禮容，今陳六佾崇儀制。"]'),
('b81a6d29-b9c1-43e4-905f-fe719bfb1d5b','和權載之離合詩','潘孟陽','唐','唐诗','tang','','[]','詠歌有離合，永夜觀酬荅。',72,'全唐诗/poet.tang.17000.json','["詠歌有離合，永夜觀酬荅。", "笥中操綵牋，竹簡何足編。", "意深俱妙絕，心契交情結。", "計彼官接聯，言初竝清切。", "翔集本相隨，羽儀良在斯。", "煙雲競文藻，因喜翫新詩。"]'),
('e2db887c-ebca-4b41-b9d4-d1d47dc960c7','春日雪以迴文絕句呈張薦權德輿','潘孟陽','唐','唐诗','tang','','[]','春梅雜落雪，發樹幾花開。',24,'全唐诗/poet.tang.17000.json','["春梅雜落雪，發樹幾花開。", "真須盡興飲，仁里願同來。"]'),
('ab695a2b-71a4-4c5c-b68e-64a063896add','元日和布澤','潘孟陽','唐','唐诗','tang','','[]','至德生成泰，咸歡照育恩。',72,'全唐诗/poet.tang.17000.json','["至德生成泰，咸歡照育恩。", "流輝霑萬物，布澤在三元。", "北闋祥雲逈，東方嘉氣繁。", "青陽初應律，蒼玉正臨軒。", "恩洽因時令，風和比化原。", "自慙同草木，無以荅乾坤。"]'),
('ca50e3f2-e8eb-470f-8acc-5cf5ff6237ae','和權載之離合詩','武少儀','唐','唐诗','tang','','[]','少年慕時彥，小悟文多變。',72,'全唐诗/poet.tang.17000.json','["少年慕時彥，小悟文多變。", "木鐸比羣英，八方流德聲。", "雷陳美交契，雨雪音塵繼。", "恩顧各飛翔，因詩覩瑰麗。", "傅野絕遺賢，人希有盛遷。", "早欽風與雅，日詠贈酬篇。"]'),
('3941670d-5a40-4a09-86a1-d920dafae88a','諸葛丞相廟','武少儀','唐','唐诗','tang','','[]','執簡焚香入廟門，武侯神象儼如存。',64,'全唐诗/poet.tang.17000.json','["執簡焚香入廟門，武侯神象儼如存。", "因機定蜀延衰漢，以計連吳振弱孫。", "欲盡智能傾僭盜，善持忠節轉庸昏。", "宣王請戰貽巾幗，始見才吞亦氣吞。"]'),
('95a3b804-29fb-4f39-a970-ae9a24812c90','享太廟樂章','段文昌','唐','唐诗','tang','','[]','肅肅清廟，登顯至德。',40,'全唐诗/poet.tang.17000.json','["肅肅清廟，登顯至德。", "澤周八荒，兵定四極。", "生物咸遂，羣盜滅息。", "明聖欽承，子孫千億。"]'),
('53e8b730-e2b2-4d93-8d7b-0db81dd467b4','題武擔寺西臺','段文昌','唐','唐诗','tang','','[]','秋天如鏡空，樓閣盡玲瓏。',48,'全唐诗/poet.tang.17000.json','["秋天如鏡空，樓閣盡玲瓏。", "水暗餘霞外，山明落照中。", "鳥行看漸遠，松韻聽難窮。", "今日登臨意，多歡語笑同。"]'),
('5b016a84-fa7c-4d53-a3bd-766c3818c790','晚夏登張儀樓呈院中諸公','段文昌','唐','唐诗','tang','','[]','重樓窗戶開，四望斂煙埃。',48,'全唐诗/poet.tang.17000.json','["重樓窗戶開，四望斂煙埃。", "遠岫林端出，清波城下迴。", "乍疑蟬韻促，稍覺雪風來。", "併起鄉關思，銷憂在酒杯。"]'),
('a1d387c0-d2e3-4dd2-8f57-2c787fad16d4','還別業尋龍華山寺廣宣上人','段文昌','唐','唐诗','tang','','[]','十里惟聞松桂風，江山忽轉見龍宮。',32,'全唐诗/poet.tang.17000.json','["十里惟聞松桂風，江山忽轉見龍宮。", "正與休師方話舊，風煙幾度入樓中。"]'),
('ed70612b-03db-4550-a59b-75224f262aa9','奉陪段相公晚夏登張儀樓','姚向','唐','唐诗','tang','','[]','秦相架羣材，登臨契上台。',48,'全唐诗/poet.tang.17000.json','["秦相架羣材，登臨契上台。", "查從銀漢落，江自雪山來。", "儷曲親流火，凌風洽小杯。", "帝鄉如在目，欲下盡裴回。"]'),
('bd81aad1-7619-4289-af5c-7202b3f1be67','和段相公登武擔寺西臺','姚向','唐','唐诗','tang','','[]','開閣錦城中，餘閑訪梵宮。',48,'全唐诗/poet.tang.17000.json','["開閣錦城中，餘閑訪梵宮。", "九層連晝景，萬象寫秋空。", "天半將身到，江長與海通。", "提攜出塵土，曾是穆清風。"]'),
('2455734f-c366-49ee-825e-dc73809af5db','和段相公登武擔寺西臺','溫會','唐','唐诗','tang','','[]','桑臺煙樹中，臺榭造雲空。',48,'全唐诗/poet.tang.17000.json','["桑臺煙樹中，臺榭造雲空。", "眺聽逢秋興，篇辭變國風。", "坐愁高鳥起，笑指遠人同。", "始愧才情薄，躋攀繼韻窮。"]'),
('00b52b15-a2a8-4020-bd5f-660331c44495','奉陪段相公晚夏登張儀樓','溫會','唐','唐诗','tang','','[]','危軒重疊開，訪古上裴回。',48,'全唐诗/poet.tang.17000.json','["危軒重疊開，訪古上裴回。", "有舌嗟秦策，飛樑駕楚材。", "雲霄隨鳳到，物象爲詩來。", "欲和關山意，巴歌調更哀。"]'),
('71074f7d-5edb-497c-aaaf-5aa46085beb9','和段相公登武擔寺西臺','李敬伯','唐','唐诗','tang','','[]','臺上起涼風，乘閑覽歲功。',48,'全唐诗/poet.tang.17000.json','["臺上起涼風，乘閑覽歲功。", "自隨台席貴，盡許羽觴同。", "樓殿斜暉照，江山極望通。", "賦詩思共樂，俱得詠時豐。"]'),
('c5b561ac-2084-4f6a-a2f3-0d9d62f69868','奉陪段相公晚夏登張儀樓','李敬伯','唐','唐诗','tang','','[]','層屋架城隈，賓筵此日開。',48,'全唐诗/poet.tang.17000.json','["層屋架城隈，賓筵此日開。", "文鋒摧八陣，星分應三台。", "望雪煩襟釋，當歡遠思來。", "披雲霄漢近，蹔覺出塵埃。"]'),
('bc513435-4f3b-49ab-9bb4-f0c1caf09d1e','奉陪段相公晚夏登張儀樓','姚康','唐','唐诗','tang','','[]','登覽值晴開，詩從野思來。',48,'全唐诗/poet.tang.17000.json','["登覽值晴開，詩從野思來。", "蜀川新草木，秦日舊樓臺。", "池景搖中座，山光接上台。", "近秋宜晚景，極目斷浮埃。"]'),
('3eefcdb6-3fcc-436c-bbd4-3193129e2cb0','和段相公登武擔寺西臺','姚康','唐','唐诗','tang','','[]','松逕引清風，登臺古寺中。',48,'全唐诗/poet.tang.17000.json','["松逕引清風，登臺古寺中。", "江平沙岸白，日下錦川紅。", "疎樹山根淨，深雲鳥跡窮。", "自慚陪末席，便與九霄通。"]'),
('8c0b0847-6a32-4c71-a548-5bd2dcba6fe8','禮部試早春殘雪','姚康','唐','唐诗','tang','','[]','微暖春潛至，輕明雪尚殘。',72,'全唐诗/poet.tang.17000.json','["微暖春潛至，輕明雪尚殘。", "銀鋪光漸濕，珪破色仍寒。", "無柳花常在，非秋露正團。", "素光浮轉薄，皓質駐應難。", "幸得依陰處，偏宜帶月看。", "玉塵銷欲盡，窮巷起袁安。"]'),
('6a85c6fc-d870-494d-83c1-51ac3bd8878a','賦得巨魚縱大壑','姚康','唐','唐诗','tang','','[]','水府乘閑望，圓波息躍魚。',72,'全唐诗/poet.tang.17000.json','["水府乘閑望，圓波息躍魚。", "從來暴泥久，今日脫泉初。", "得志寧相忌，無心任宛如。", "龍門應可度，鮫室豈常居。", "掉尾方窮樂，遊鱗每自舒。", "乘流千里去，風力藉吹噓。"]'),
('40d58e5f-5373-4b3a-8cb2-28904853fd1d','早春對雨','羊士諤','唐','唐诗','tang','','[]','南館垂楊早，東風細雨頻。',48,'全唐诗/poet.tang.17000.json','["南館垂楊早，東風細雨頻。", "輕寒消玉斝，幽賞滯朱輪。", "千里巴江守，三年故國春。", "含情非遲客，懸榻但生塵。"]'),
('3b4a301e-b540-4d63-867a-31a144117f98','永寧小園即事','羊士諤','唐','唐诗','tang','','[]','蕭條梧竹下，秋物映園廬。',48,'全唐诗/poet.tang.17000.json','["蕭條梧竹下，秋物映園廬。", "宿雨方然桂，朝飢更摘蔬。", "陰苔生白石，時菊覆清渠。", "陳力當何事，忘言媿道書。"]'),
('07181959-ec40-4958-83d2-57f2c55d6233','臺中遇直晨覽蕭侍御壁畫山水','羊士諤','唐','唐诗','tang','','[]','蟲思庭莎白露天，微風吹竹曉淒然。',32,'全唐诗/poet.tang.17000.json','["蟲思庭莎白露天，微風吹竹曉淒然。", "今來始悟朝迴客，暗寫歸心向石泉。"]'),
('36c25663-9c88-4f7b-9411-1453dad7065c','過三鄉望女几山早歲有卜築之志','羊士諤','唐','唐诗','tang','','[]','女几山頭春雪消，路傍仙杏發柔條。',32,'全唐诗/poet.tang.17000.json','["女几山頭春雪消，路傍仙杏發柔條。", "心期欲去知何日，惆悵回車上野橋。"]'),
('5624eaa5-331a-418c-a0e1-5cf616e01e43','和李都官郎中經宮人斜','羊士諤','唐','唐诗','tang','','[]','翡翠無窮掩夜泉，猶疑一半作神仙。',32,'全唐诗/poet.tang.17000.json','["翡翠無窮掩夜泉，猶疑一半作神仙。", "秋來還照長門月，珠露寒花是野田。"]'),
('43e725a9-1f56-446c-af8e-61702ec6f27f','山閣聞笛','羊士諤','唐','唐诗','tang','','[]','臨風玉管吹參差，山塢春深日又遲。',32,'全唐诗/poet.tang.17000.json','["臨風玉管吹參差，山塢春深日又遲。", "李白桃紅滿城郭，馬融閑臥望京師。"]'),
('e8fd1a28-064e-44d5-837b-c22087500732','登樓','羊士諤','唐','唐诗','tang','','[]','槐柳蕭疎遶郡城，夜添山雨作江聲。',32,'全唐诗/poet.tang.17000.json','["槐柳蕭疎遶郡城，夜添山雨作江聲。", "秋風南陌無車馬，獨上高樓故國情。"]'),
('c026b4e0-d430-46a2-a03c-b0cd56ead963','憶江南舊遊二首 一','羊士諤','唐','唐诗','tang','','[]','山陰道上桂花初，王謝風流滿晉書。',32,'全唐诗/poet.tang.17000.json','["山陰道上桂花初，王謝風流滿晉書。", "曾作江南步從事，秋來還復憶鱸魚。"]'),
('c6f1a92e-34ce-4410-885f-8eb349ef9149','憶江南舊遊二首 二','羊士諤','唐','唐诗','tang','','[]','曲水三春弄綵毫，樟亭八月又觀濤。',32,'全唐诗/poet.tang.17000.json','["曲水三春弄綵毫，樟亭八月又觀濤。", "金罍幾醉烏程酒，鶴舫閑吟把蟹螯。"]'),
('cbf9ab89-3ae8-4dd5-83a5-49ffca306ed0','郡中即事三首 一','羊士諤','唐','唐诗','tang','','[]','曉風山郭雁飛初，霜拂回塘水榭虛。',64,'全唐诗/poet.tang.17000.json','["曉風山郭雁飛初，霜拂回塘水榭虛。", "鼓角清明如戰壘，梧桐搖落似貧居。", "青門遠憶中人產，白首閑看太史書。", "城下秋江寒見底，賓筵莫訝食無魚。"]'),
('051fd41c-24cf-4995-b76b-4055580aeff6','郡中即事三首 二','羊士諤','唐','唐诗','tang','','[]','紅衣落盡暗香殘，葉上秋光白露寒。',32,'全唐诗/poet.tang.17000.json','["紅衣落盡暗香殘，葉上秋光白露寒。", "越女含情已無限，莫敎長袖倚闌干。"]'),
('af8e1d25-fcfb-4d07-8536-ee00052216c1','郡中即事三首 三','羊士諤','唐','唐诗','tang','','[]','登臨何事見瓊枝，白露黃花自繞籬。',32,'全唐诗/poet.tang.17000.json','["登臨何事見瓊枝，白露黃花自繞籬。", "惟有樓中好山色，稻畦殘水入秋池。"]'),
('2d23990e-9d41-4356-9c86-92307223979d','野望二首 一','羊士諤','唐','唐诗','tang','','[]','萋萋麥隴杏花風，好是行春野望中。',32,'全唐诗/poet.tang.17000.json','["萋萋麥隴杏花風，好是行春野望中。", "日暮不辭停五馬，鴛鴦飛去綠江空。"]'),
('2d342c44-d5a6-4c0e-ae05-80d8776a7ecb','野望二首 二','羊士諤','唐','唐诗','tang','','[]','忘懷不使海鷗疑，水映桃花酒滿巵。',32,'全唐诗/poet.tang.17000.json','["忘懷不使海鷗疑，水映桃花酒滿巵。", "亭上一聲歌白苧，野人歸棹亦行遲。"]'),
('13ed7a6a-9980-450f-9140-97720a386182','遊西山蘭若','羊士諤','唐','唐诗','tang','','[]','路傍垂柳古今情，春草春泉咽又生。',32,'全唐诗/poet.tang.17000.json','["路傍垂柳古今情，春草春泉咽又生。", "借問山僧好風景，看花攜酒幾人行。"]'),
('baf40934-ac92-4c41-8c0c-8628442881fd','泛舟入後溪 一','羊士諤','唐','唐诗','tang','','[]','東風朝日破輕嵐，仙棹初移酒未酣。',32,'全唐诗/poet.tang.17000.json','["東風朝日破輕嵐，仙棹初移酒未酣。", "玉笛閑吹折楊柳，春風無事傍魚潭。"]'),
('3b6f27f0-86ee-49a8-86a6-8bd66a887c7b','泛舟入後溪 二','羊士諤','唐','唐诗','tang','','[]','雨餘芳草淨沙塵，水綠灘平一帶春。',32,'全唐诗/poet.tang.17000.json','["雨餘芳草淨沙塵，水綠灘平一帶春。", "唯有啼鵑似留客，桃花深處更無人。"]'),
('295ad12e-47aa-4d56-979e-0f68b80b730b','看花','羊士諤','唐','唐诗','tang','','[]','一到花間一忘歸，玉桮瑤瑟減光輝。',32,'全唐诗/poet.tang.17000.json','["一到花間一忘歸，玉桮瑤瑟減光輝。", "歌筵更覆青油幕，忽似朝雲瑞雪飛。"]'),
('6ab17fc2-5d2c-4cd6-b8a0-67d5885531d3','春望','羊士諤','唐','唐诗','tang','','[]','莫問華簪髮已斑，歸心滿目是青山。',32,'全唐诗/poet.tang.17000.json','["莫問華簪髮已斑，歸心滿目是青山。", "獨上層城倚危檻，柳營春盡馬嘶閑。"]'),
('84a76cfe-3f1d-4736-83fc-82f00b9ea903','寄江陵韓少尹','羊士諤','唐','唐诗','tang','','[]','別來玄鬢共成霜，雲起無心出帝鄉。',32,'全唐诗/poet.tang.17000.json','["別來玄鬢共成霜，雲起無心出帝鄉。", "蜀國魚箋數行字，憶君秋夢過南塘。"]'),
('72efa79b-8bc6-4695-8e15-e8935e3a7433','賀州宴行營回將','羊士諤','唐','唐诗','tang','','[]','九劒盈庭酒滿巵，戍人歸日及瓜時。',32,'全唐诗/poet.tang.17000.json','["九劒盈庭酒滿巵，戍人歸日及瓜時。", "元戎靜鎮無邊事，遣向營中偃畫旗。"]'),
('81976ec6-c164-4b0d-adfa-6e218f0a0e0c','遊郭駙馬大安山池','羊士諤','唐','唐诗','tang','','[]','馬嘶芳草自淹留，別館何人屬細侯。',64,'全唐诗/poet.tang.17000.json','["馬嘶芳草自淹留，別館何人屬細侯。", "仙杏破顏逢醉客，綵鴛飛去避行舟。", "洞簫日暖移賓榻，垂柳風多掩妓樓。", "坐閱清暉不知暮，煙橫北渚水悠悠。"]'),
('a83ef032-ad73-46e3-b3ae-64862963c810','故蕭尚書癭柏齋前玉蘂樹與王起居吏部孟員外同賞','羊士諤','唐','唐诗','tang','','[]','柏寢閉何時，瑤華自滿枝。',48,'全唐诗/poet.tang.17000.json','["柏寢閉何時，瑤華自滿枝。", "天清凝積素，風暖動芬絲。", "留步蒼苔暗，停觴白日遲。", "因吟茂陵草，幽賞待妍詞。"]'),
('fb571e62-a750-422c-a2e1-8dfa86c8d262','和武相早朝中書候傳點書懷奉呈','羊士諤','唐','唐诗','tang','','[]','殿省祕清曉，夔龍升紫微。',120,'全唐诗/poet.tang.17000.json','["殿省祕清曉，夔龍升紫微。", "星辰拱帝座，劒履翊天機。", "耿耿金波缺，沉沉玉漏稀。", "綵箋蹲鷙獸，畫扇列名翬。", "志業丹青重，恩華雨露霏。", "三台昭建極，一德慶垂衣。", "昌運瞻文敎，雄圖本武威。", "殊勳如帶遠，佳氣似煙非。", "抗節衷無隱，同心尚弼違。", "良哉致君日，維嶽有光輝。"]'),
('6c11807f-5410-4d90-868e-89702e1a7bec','和蕭侍御監祭白帝城西村寺齋沐覽鏡有懷吏部孟員外幷見贈','羊士諤','唐','唐诗','tang','','[]','晚沐金仙宇，迎秋白帝祠。',48,'全唐诗/poet.tang.17000.json','["晚沐金仙宇，迎秋白帝祠。", "軒裳煩吏職，風物動心期。", "清鏡開塵匣，華簪指髮絲。", "南宮有高步，歲晏豈磷緇。"]'),
('425e3fdc-9226-47ec-984f-ac82b8997a71','送張郎中副使自南省赴鳳翔府幕','羊士諤','唐','唐诗','tang','','[]','仙郎佐氏謀，廷議寵元侯。',48,'全唐诗/poet.tang.17000.json','["仙郎佐氏謀，廷議寵元侯。", "城郭須來貢，河隍亦順流。", "亞夫高壘靜，充國大田秋。", "當奮燕然筆，銘功向隴頭。"]'),
('9a3b75a9-ca36-4ebc-bc01-9e7c953216b4','和竇吏部雪中寓直','羊士諤','唐','唐诗','tang','','[]','瑞花飄朔雪，灝氣滿南宮。',48,'全唐诗/poet.tang.17000.json','["瑞花飄朔雪，灝氣滿南宮。", "迢遰層城掩，徘徊午夜中。", "金閨通籍恨，銀燭直廬空。", "誰問烏臺客，家山憶桂叢。"]'),
('c8d230ba-fe7e-4d4c-9718-12488ff27195','小園春至偶呈吏部竇郎中','羊士諤','唐','唐诗','tang','','[]','松篠雖苦節，冰霜慘其間。',96,'全唐诗/poet.tang.17000.json','["松篠雖苦節，冰霜慘其間。", "欣然發佳色，如喜東風還。", "幽抱想前躅，冥鴻度南山。", "春臺一以眺，達士亦解顏。", "偃息非老圃，沉吟閟玄關。", "馳暉忽復失，壯氣不得閑。", "君子當濟物，丹梯誰共攀。", "心期自有約，去掃蒼苔斑。"]'),
('ff8cb3dc-dcc5-4be8-8e15-1ee6d54de22d','酬吏部竇郎中直夜見寄','羊士諤','唐','唐诗','tang','','[]','解巾侍雲陛，三命早爲郎。',48,'全唐诗/poet.tang.17000.json','["解巾侍雲陛，三命早爲郎。", "復以雕龍彩，旋歸振鷺行。", "玉書期養素，金印已懷黃。", "茲夕南宮詠，遐情媿不忘。"]'),
('371ebf75-34dc-4c08-a2c4-27670c6cf19a','永寧里園亭休沐悵然成詠','羊士諤','唐','唐诗','tang','','[]','雲景含初夏，休歸曲陌深。',72,'全唐诗/poet.tang.17000.json','["雲景含初夏，休歸曲陌深。", "幽簾宜永日，珍樹始清陰。", "遲客唯長簟，忘言有匣琴。", "畫披靈物態，書見古人心。", "芳草多留步，鮮飆自滿襟。", "勞形非立事，瀟灑媿頭簪。"]'),
('4d20fa6c-fa53-4f69-abe6-b3201bf0361b','登樂遊原寄司封孟郎中盧補闕','羊士諤','唐','唐诗','tang','','[]','爽節時清眺，秋懷悵獨過。',48,'全唐诗/poet.tang.17000.json','["爽節時清眺，秋懷悵獨過。", "神臯值宿雨，曲水已增波。", "白鳥凌風迥，紅蕖濯露多。", "伊川有歸思，君子復如何。"]'),
('8bec6b9f-91c5-4883-ae6f-88d4389841b3','乾元初嚴黃門自京兆少尹貶牧巴郡以長才英氣固多暇日每遊郡之東山山側精舍有盤石細泉䟽爲浮桮之勝苔深樹老蒼然遺躅士諤謬因出守得繼茲賞乃賦詩十四韻刻於石壁','羊士諤','唐','唐诗','tang','','[]','石座雙峰古，雲泉九曲深。',167,'全唐诗/poet.tang.17000.json','["石座雙峰古，雲泉九曲深。", "寂寥疏鑿意，蕪沒歲時侵。", "繞席流還壅，浮杯咽復沉。", "追懷王謝侶，更似會稽岑誰謂天池翼，相期宅畔吟。", "光輝輕尺璧，然諾重黃金。", "幾醉東山妓，長懸北闕心。", "蕙蘭留雜佩，桃李想華簪。", "閉閣余何事，鳴騶亦屢尋。", "軒裳遵往轍，風景憩中林。", "橫吹多淒調，安歌送好音。", "初筵方側弁，故老忽沾襟。", "盛世當弘濟，平生諒所欽。", "無能愧陳力，惆悵拂瑤琴。"]'),
('672526d7-45d8-4e03-bcdf-6f0df7c9c3bf','閑齋示一二道者','羊士諤','唐','唐诗','tang','','[]','幽蘭誰復奏，閑匣以端憂。',48,'全唐诗/poet.tang.17000.json','["幽蘭誰復奏，閑匣以端憂。", "知止慙先覺，歸歟想故侯。", "山蟬鈴閣晚，江雨麥田秋。", "唯有空門學，相期老一丘。"]'),
('b320cb73-b204-4653-b12a-5480f3e0436d','南池荷花','羊士諤','唐','唐诗','tang','','[]','蟬噪城溝水，芙蓉忽已繁。',48,'全唐诗/poet.tang.17000.json','["蟬噪城溝水，芙蓉忽已繁。", "紅花迷越豔，芳意過湘沅。", "湛露宜清暑，披香正滿軒。", "朝朝秖自賞，穠李亦何言。"]'),
('c4db6efc-10b5-47cb-8081-e602281a1313','郡中翫月寄江南李少尹虞部孟員外三首 一','羊士諤','唐','唐诗','tang','','[]','月滿自高丘，江通無狹流。',48,'全唐诗/poet.tang.17000.json','["月滿自高丘，江通無狹流。", "軒窗開到曉，風物坐含秋。", "鵲警銀河斷，蛩悲翠幕幽。", "清光望不極，耿耿下西樓。"]');
